INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-little-fox', 'the-little-fox', 'The Little Fox', 'The Little Fox', 'A curious little fox sets off into the forest and discovers that being brave means asking for help too.', 'Seekor rubah kecil yang penasaran menjelajahi hutan dan belajar bahwa berani juga berarti berani meminta bantuan.', 'cat_adventure', 'aut_axto-creative-team', 'sunrise', '🦊', 3, 7, 0, 'published', 8, 3151, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_1', 'bok_the-little-fox', 1, 'fox-1', 'Once upon a time, in a beautiful forest, there lived a little fox. He was curious, brave, and loved adventures.', 'Pada suatu waktu, di sebuah hutan yang indah, hiduplah seekor rubah kecil. Ia penasaran, berani, dan suka berpetualang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_2', 'bok_the-little-fox', 2, 'fox-2', 'Every morning, the little fox woke up early to explore a new corner of the forest.', 'Setiap pagi, rubah kecil itu bangun lebih awal untuk menjelajahi sudut hutan yang baru.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_3', 'bok_the-little-fox', 3, 'fox-3', 'One day, he found a path he had never seen before. It wound deep into the tall, whispering trees.', 'Suatu hari, ia menemukan jalan setapak yang belum pernah dilihatnya. Jalan itu berkelok masuk ke rimbunnya pepohonan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_4', 'bok_the-little-fox', 4, 'fox-4', 'He walked and walked, until suddenly the path split into three directions. The little fox did not know which way to go.', 'Ia berjalan terus, sampai tiba-tiba jalan itu bercabang menjadi tiga arah. Rubah kecil tidak tahu harus memilih arah mana.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_5', 'bok_the-little-fox', 5, 'fox-5', 'A wise old owl saw him standing there. "Being brave doesn''t mean you have to know everything," she said. "It''s also brave to ask for help."', 'Seekor burung hantu tua yang bijak melihatnya berdiri kebingungan. "Berani bukan berarti harus tahu segalanya," katanya. "Meminta bantuan juga adalah keberanian."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_6', 'bok_the-little-fox', 6, 'fox-6', 'So the little fox asked the owl for directions. Together, they found the most beautiful meadow he had ever seen.', 'Maka rubah kecil pun bertanya arah kepada burung hantu. Bersama-sama, mereka menemukan padang rumput terindah yang pernah ia lihat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_7', 'bok_the-little-fox', 7, 'fox-7', 'From that day on, the little fox explored the forest with new friends by his side.', 'Sejak hari itu, rubah kecil menjelajahi hutan bersama teman-teman baru di sisinya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-fox_8', 'bok_the-little-fox', 8, 'fox-8', 'And he learned that the best adventures are the ones we share with others. The end.', 'Dan ia belajar bahwa petualangan terbaik adalah yang dibagikan bersama orang lain. Selesai.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-little-fox_1', 'bok_the-little-fox', 1, 'What did the little fox love to do?', 'Apa yang disukai rubah kecil?', '["Sleeping all day","Exploring the forest","Baking cookies","Swimming in the sea"]', '["Tidur seharian","Menjelajahi hutan","Membuat kue","Berenang di laut"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-little-fox_2', 'bok_the-little-fox', 2, 'Who helped the little fox when the path split into three?', 'Siapa yang membantu rubah kecil saat jalan bercabang tiga?', '["A rabbit","A wise old owl","A fisherman","His mother"]', '["Seekor kelinci","Burung hantu tua yang bijak","Seorang nelayan","Ibunya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-little-fox_3', 'bok_the-little-fox', 3, 'What is the lesson of the story?', 'Apa pelajaran dari cerita ini?', '["Never leave home","Asking for help is also brave","Foxes cannot get lost","Owls are scary"]', '["Jangan pernah keluar rumah","Meminta bantuan juga sebuah keberanian","Rubah tidak bisa tersesat","Burung hantu itu menakutkan"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-brave-lion', 'the-brave-lion', 'The Brave Lion', 'The Brave Lion', 'A young lion who is afraid of the dark discovers that even the bravest hearts can feel scared sometimes.', 'Seekor singa muda yang takut gelap belajar bahwa hati yang paling berani pun boleh merasa takut.', 'cat_fairy-tales', 'aut_axto-creative-team', 'candy', '🦁', 3, 7, 0, 'published', 7, 2542, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_1', 'bok_the-brave-lion', 1, 'lion-1', 'In the golden savanna lived a young lion named Rico, with the fluffiest mane in the whole pride.', 'Di padang savana keemasan hiduplah seekor singa muda bernama Rico, dengan surai paling lebat di seluruh kawanan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_2', 'bok_the-brave-lion', 2, 'lion-2', 'Everyone said lions were the bravest animals of all. But at night, Rico was afraid of the dark.', 'Semua orang berkata singa adalah hewan paling berani. Tapi di malam hari, Rico takut pada gelap.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_3', 'bok_the-brave-lion', 3, 'lion-3', 'He worried the other animals would laugh if they knew his secret, so he hid his fear every night.', 'Ia khawatir hewan lain akan menertawakannya jika tahu rahasianya, jadi ia menyembunyikan rasa takutnya setiap malam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_4', 'bok_the-brave-lion', 4, 'lion-4', 'One evening, his little sister Lulu saw him trembling by the rocks. "What is wrong, big brother?" she asked gently.', 'Suatu malam, adiknya, Lulu, melihatnya gemetar di dekat bebatuan. "Kenapa, Kak?" tanyanya lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_5', 'bok_the-brave-lion', 5, 'lion-5', 'Rico took a deep breath and told her the truth. Lulu smiled and said, "Even lions can be scared. That is okay."', 'Rico menarik napas dalam dan menceritakan yang sebenarnya. Lulu tersenyum, "Singa pun boleh takut. Itu tidak apa-apa."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_6', 'bok_the-brave-lion', 6, 'lion-6', 'From then on, Lulu stayed close to him at night, and together they watched the stars until Rico felt brave again.', 'Sejak itu, Lulu selalu menemaninya di malam hari, dan bersama-sama mereka memandangi bintang hingga Rico merasa berani lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-brave-lion_7', 'bok_the-brave-lion', 7, 'lion-7', 'Rico learned that real bravery is not about never being afraid — it is about sharing your feelings with someone who loves you.', 'Rico belajar bahwa keberanian sejati bukan berarti tidak pernah takut — melainkan berani berbagi perasaan dengan orang yang menyayangimu.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-brave-lion_1', 'bok_the-brave-lion', 1, 'What was Rico afraid of?', 'Apa yang ditakuti Rico?', '["Water","The dark","Loud noises","Other lions"]', '["Air","Gelap","Suara keras","Singa lain"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-brave-lion_2', 'bok_the-brave-lion', 2, 'Who helped Rico feel better?', 'Siapa yang membantu Rico merasa lebih baik?', '["His father","A zebra","His little sister Lulu","A hunter"]', '["Ayahnya","Seekor zebra","Adiknya, Lulu","Seorang pemburu"]', 2, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-brave-lion_3', 'bok_the-brave-lion', 3, 'What does the story teach about bravery?', 'Apa yang diajarkan cerita ini tentang keberanian?', '["Brave means never being scared","It is okay to share your fears with someone who loves you","Only lions can be brave","You should hide your feelings"]', '["Berani berarti tidak pernah takut","Boleh berbagi rasa takut dengan orang yang menyayangimu","Hanya singa yang bisa berani","Kamu harus menyembunyikan perasaanmu"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_under-the-sea', 'under-the-sea', 'Under the Sea', 'Under the Sea', 'A little clownfish explores the coral reef and learns why every creature in the ocean matters.', 'Seekor ikan badut kecil menjelajahi terumbu karang dan belajar mengapa setiap makhluk laut itu penting.', 'cat_animals', 'aut_emily-clark', 'ocean', '🐠', 3, 8, 0, 'published', 7, 4640, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_1', 'bok_under-the-sea', 1, 'sea-1', 'Deep in the turquoise sea, a little clownfish named Coral lived in a soft anemone home.', 'Jauh di laut biru toska, seekor ikan badut kecil bernama Coral tinggal di rumah anemon yang lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_2', 'bok_under-the-sea', 2, 'sea-2', 'Coral loved to swim around the reef, waving hello to crabs, starfish, and gentle sea turtles.', 'Coral suka berenang mengelilingi terumbu karang, menyapa kepiting, bintang laut, dan penyu laut yang ramah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_3', 'bok_under-the-sea', 3, 'sea-3', 'One day, Coral noticed the coral reef looked pale and tired. "Why do you look sad?" she asked.', 'Suatu hari, Coral melihat terumbu karang tampak pucat dan lesu. "Kenapa kau terlihat sedih?" tanyanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_4', 'bok_under-the-sea', 4, 'sea-4', 'A wise sea turtle explained, "The reef needs clean water and all of us working together to stay healthy."', '"Terumbu karang butuh air bersih dan kita semua yang saling menjaga agar tetap sehat," jelas penyu laut yang bijak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_5', 'bok_under-the-sea', 5, 'sea-5', 'So Coral gathered her friends — crabs, shrimp, and small fish — to help clean up plastic that had drifted in.', 'Maka Coral mengajak teman-temannya — kepiting, udang, dan ikan-ikan kecil — untuk membersihkan sampah plastik yang hanyut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_6', 'bok_under-the-sea', 6, 'sea-6', 'Slowly, the reef began to sparkle with color again, and all the sea creatures cheered together.', 'Perlahan, terumbu karang mulai bersinar penuh warna kembali, dan semua makhluk laut bersorak bersama.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_under-the-sea_7', 'bok_under-the-sea', 7, 'sea-7', 'Coral learned that even a small fish can help take care of a big, beautiful ocean.', 'Coral belajar bahwa ikan kecil pun bisa membantu menjaga lautan yang luas dan indah.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_under-the-sea_1', 'bok_under-the-sea', 1, 'What kind of fish is Coral?', 'Ikan jenis apakah Coral?', '["A shark","A clownfish","A jellyfish","A dolphin"]', '["Hiu","Ikan badut","Ubur-ubur","Lumba-lumba"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_under-the-sea_2', 'bok_under-the-sea', 2, 'What did the reef need to stay healthy?', 'Apa yang dibutuhkan terumbu karang agar tetap sehat?', '["More sand","Clean water and teamwork","Loud music","More plastic"]', '["Lebih banyak pasir","Air bersih dan kerja sama","Musik keras","Lebih banyak plastik"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_under-the-sea_3', 'bok_under-the-sea', 3, 'What is the moral of the story?', 'Apa pesan moral dari cerita ini?', '["Only big animals matter","Even small creatures can help protect the ocean","Fish should stay alone","Plastic is good for the sea"]', '["Hanya hewan besar yang penting","Makhluk kecil pun bisa membantu menjaga laut","Ikan sebaiknya sendirian","Plastik baik untuk laut"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_dinosaur-world', 'dinosaur-world', 'Dinosaur World', 'Dinosaur World', 'A gentle young dinosaur discovers that being different from the other dinosaurs is what makes him special.', 'Seekor dinosaurus muda yang lembut menyadari bahwa perbedaannya justru membuatnya istimewa.', 'cat_dinosaur', 'aut_axto-creative-team', 'forest', '🦕', 4, 9, 0, 'published', 7, 1050, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_1', 'bok_dinosaur-world', 1, 'dino-1', 'Long, long ago, in a valley full of ferns, a little long-necked dinosaur named Dot hatched from her egg.', 'Dahulu kali, di sebuah lembah penuh pakis, seekor dinosaurus leher panjang kecil bernama Dot menetas dari telurnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_2', 'bok_dinosaur-world', 2, 'dino-2', 'All the other dinosaurs in the valley were loud and fast. But Dot liked to move slowly and look at little things.', 'Semua dinosaurus lain di lembah itu berisik dan cepat. Tapi Dot suka bergerak pelan dan memperhatikan hal-hal kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_3', 'bok_dinosaur-world', 3, 'dino-3', 'She noticed tiny flowers between the rocks, and patterns in the clouds that no one else seemed to see.', 'Ia memperhatikan bunga-bunga kecil di antara bebatuan, dan bentuk-bentuk awan yang tak disadari yang lain.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_4', 'bok_dinosaur-world', 4, 'dino-4', 'One day, a big storm confused the herd — they could not find the safe cave they always used.', 'Suatu hari, badai besar membuat kawanan itu bingung — mereka tidak bisa menemukan gua aman yang biasa mereka pakai.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_5', 'bok_dinosaur-world', 5, 'dino-5', 'But Dot, who always noticed small details, remembered a hidden path marked by a patch of blue flowers.', 'Tapi Dot, yang selalu memperhatikan detail kecil, mengingat jalan tersembunyi yang ditandai bunga biru.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_6', 'bok_dinosaur-world', 6, 'dino-6', 'She led the whole herd safely to the cave. Everyone cheered for careful, curious little Dot!', 'Ia memimpin seluruh kawanan dengan selamat ke gua itu. Semua bersorak untuk Dot yang teliti dan penasaran!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_dinosaur-world_7', 'bok_dinosaur-world', 7, 'dino-7', 'From that day, Dot understood that being different was not a weakness — it was her very own kind of strength.', 'Sejak hari itu, Dot mengerti bahwa menjadi berbeda bukanlah kelemahan — itu adalah kekuatannya sendiri.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_dinosaur-world_1', 'bok_dinosaur-world', 1, 'What did Dot like to do differently from the other dinosaurs?', 'Apa yang Dot suka lakukan berbeda dari dinosaurus lain?', '["Run very fast","Move slowly and notice small things","Roar loudly","Sleep all day"]', '["Berlari sangat cepat","Bergerak pelan dan memperhatikan hal kecil","Meraung keras","Tidur seharian"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_dinosaur-world_2', 'bok_dinosaur-world', 2, 'How did Dot help the herd during the storm?', 'Bagaimana Dot membantu kawanan saat badai?', '["She hid alone","She remembered a hidden path with blue flowers","She called for help loudly","She ran away"]', '["Ia bersembunyi sendirian","Ia mengingat jalan tersembunyi dengan bunga biru","Ia berteriak minta tolong","Ia melarikan diri"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_dinosaur-world_3', 'bok_dinosaur-world', 3, 'What is the lesson of the story?', 'Apa pelajaran dari cerita ini?', '["Being different can be a strength","Everyone must be the same","Storms are not dangerous","Only fast dinosaurs are useful"]', '["Menjadi berbeda bisa menjadi kekuatan","Semua orang harus sama","Badai tidak berbahaya","Hanya dinosaurus cepat yang berguna"]', 0, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_a-journey-to-space', 'a-journey-to-space', 'A Journey to Space', 'A Journey to Space', 'A young astronaut travels past the moon and stars, discovering how small — and how connected — our world truly is.', 'Seorang astronaut cilik terbang melewati bulan dan bintang, dan menyadari betapa kecil serta saling terhubungnya dunia kita.', 'cat_space', 'aut_axto-creative-team', 'cosmic', '🚀', 5, 10, 0, 'published', 7, 351, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_1', 'bok_a-journey-to-space', 1, 'space-1', 'Maya always dreamed of the stars. One quiet night, a tiny silver rocket landed softly in her backyard.', 'Maya selalu memimpikan bintang-bintang. Suatu malam yang tenang, sebuah roket perak kecil mendarat lembut di halaman belakangnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_2', 'bok_a-journey-to-space', 2, 'space-2', 'A friendly robot named Orbit opened the hatch. "Would you like to see the universe?" it asked.', 'Sebuah robot ramah bernama Orbit membuka pintunya. "Mau melihat alam semesta?" tanyanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_3', 'bok_a-journey-to-space', 3, 'space-3', 'They zoomed past the Moon, where Maya bounced in the low gravity and giggled with delight.', 'Mereka melesat melewati Bulan, tempat Maya melompat-lompat dalam gravitasi rendah sambil tertawa senang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_4', 'bok_a-journey-to-space', 4, 'space-4', 'Next, they flew by Saturn, its icy rings sparkling like a giant necklace made of diamonds.', 'Selanjutnya, mereka terbang melewati Saturnus, cincin esnya berkilau seperti kalung raksasa dari berlian.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_5', 'bok_a-journey-to-space', 5, 'space-5', 'Looking back, Maya saw planet Earth — a tiny blue marble glowing gently in the dark.', 'Menoleh ke belakang, Maya melihat planet Bumi — kelereng biru kecil yang bersinar lembut di kegelapan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_6', 'bok_a-journey-to-space', 6, 'space-6', '"It looks so small," Maya whispered. "That is our whole home," said Orbit. "Everyone we love is right there."', '"Kecil sekali," bisik Maya. "Itulah rumah kita semua," kata Orbit. "Semua orang yang kita sayangi ada di sana."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-journey-to-space_7', 'bok_a-journey-to-space', 7, 'space-7', 'Maya returned home with a new feeling in her heart — Earth was small in the universe, but full of everything she loved.', 'Maya pulang dengan perasaan baru di hatinya — Bumi memang kecil di alam semesta, tapi penuh dengan segala yang ia cintai.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-journey-to-space_1', 'bok_a-journey-to-space', 1, 'Who was Maya''s robot friend?', 'Siapa nama robot teman Maya?', '["Orbit","Rocket","Star","Luna"]', '["Orbit","Rocket","Star","Luna"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-journey-to-space_2', 'bok_a-journey-to-space', 2, 'What did Maya see that looked like a necklace of diamonds?', 'Apa yang dilihat Maya yang tampak seperti kalung berlian?', '["The Moon''s dust","Saturn''s rings","The Sun","A comet"]', '["Debu Bulan","Cincin Saturnus","Matahari","Komet"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-journey-to-space_3', 'bok_a-journey-to-space', 3, 'What did Maya learn about Earth?', 'Apa yang dipelajari Maya tentang Bumi?', '["It is the biggest planet","It is small but full of everyone she loves","It has rings like Saturn","It is not important"]', '["Bumi adalah planet terbesar","Bumi kecil tapi penuh orang yang ia sayangi","Bumi memiliki cincin seperti Saturnus","Bumi tidak penting"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_robot-and-me', 'robot-and-me', 'Robot and Me', 'Robot and Me', 'A shy inventor builds a small robot friend and learns how curiosity and kindness go hand in hand.', 'Seorang anak pemalu membuat teman robot kecil dan belajar bahwa rasa ingin tahu dan kebaikan hati berjalan beriringan.', 'cat_science', 'aut_david-lee', 'meadow', '🤖', 5, 10, 0, 'published', 7, 2604, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_1', 'bok_robot-and-me', 1, 'robot-1', 'Ken loved building things out of old boxes, gears, and batteries in his garage workshop.', 'Ken suka membuat berbagai hal dari kardus bekas, roda gigi, dan baterai di bengkel garasinya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_2', 'bok_robot-and-me', 2, 'robot-2', 'One rainy afternoon, he finally finished his biggest project yet: a small robot he named Bolt.', 'Suatu sore yang hujan, ia akhirnya menyelesaikan proyek terbesarnya: robot kecil yang ia beri nama Bolt.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_3', 'bok_robot-and-me', 3, 'robot-3', 'Bolt could not talk, but it beeped happily and rolled after Ken wherever he went.', 'Bolt tidak bisa berbicara, tapi ia berbunyi "beep" gembira dan mengikuti Ken ke mana pun ia pergi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_4', 'bok_robot-and-me', 4, 'robot-4', 'At school, Ken was too shy to share his invention. He worried the other kids might laugh.', 'Di sekolah, Ken terlalu malu untuk menunjukkan ciptaannya. Ia khawatir teman-teman akan menertawakannya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_5', 'bok_robot-and-me', 5, 'robot-5', 'But Bolt rolled out of his backpack by accident — and beeped so cheerfully that the whole class laughed with joy, not mockery.', 'Namun Bolt tidak sengaja menggelinding keluar dari tasnya — dan berbunyi begitu ceria hingga seisi kelas tertawa senang, bukan mengejek.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_6', 'bok_robot-and-me', 6, 'robot-6', 'Soon, every classmate wanted to help Ken build more robot friends, using boxes and gears of their own.', 'Segera, semua teman sekelas ingin membantu Ken membuat lebih banyak teman robot, menggunakan kardus dan roda gigi mereka sendiri.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_robot-and-me_7', 'bok_robot-and-me', 7, 'robot-7', 'Ken learned that sharing what you love can turn a quiet idea into something everyone enjoys together.', 'Ken belajar bahwa berbagi apa yang kita sukai bisa mengubah ide yang sunyi menjadi sesuatu yang dinikmati bersama.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_robot-and-me_1', 'bok_robot-and-me', 1, 'What did Ken name his robot?', 'Siapa nama yang Ken berikan untuk robotnya?', '["Bolt","Spark","Gizmo","Circuit"]', '["Bolt","Spark","Gizmo","Circuit"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_robot-and-me_2', 'bok_robot-and-me', 2, 'Why was Ken afraid to share his invention at school?', 'Kenapa Ken takut menunjukkan ciptaannya di sekolah?', '["He forgot it at home","He worried classmates would laugh","It was broken","He did not like robots"]', '["Ia lupa membawanya","Ia khawatir teman-teman menertawakannya","Robotnya rusak","Ia tidak suka robot"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_robot-and-me_3', 'bok_robot-and-me', 3, 'What happened when the class saw Bolt?', 'Apa yang terjadi saat kelas melihat Bolt?', '["They ignored it","They laughed with joy and wanted to help build more","The teacher took it away","Everyone got scared"]', '["Mereka mengabaikannya","Mereka tertawa senang dan ingin membantu membuat lebih banyak","Guru mengambilnya","Semua orang ketakutan"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_goodnight-little-owl', 'goodnight-little-owl', 'Goodnight, Little Owl', 'Selamat Malam, Burung Hantu Kecil', 'A tiny owl who is afraid of the daylight learns that everyone has their own perfect time to shine.', 'Burung hantu kecil yang takut cahaya siang belajar bahwa setiap makhluk punya waktunya sendiri untuk bersinar.', 'cat_bedtime', 'aut_siti-aminah', 'night', '🦉', 2, 6, 0, 'published', 7, 3907, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_1', 'bok_goodnight-little-owl', 1, 'owl-1', 'High in an old oak tree lived a tiny owl named Pip, who loved the cool, quiet night.', 'Tinggi di pohon ek tua, hiduplah burung hantu kecil bernama Pip, yang menyukai malam yang sejuk dan tenang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_2', 'bok_goodnight-little-owl', 2, 'owl-2', 'While other animals slept, Pip opened her big round eyes and watched the moon rise softly.', 'Saat hewan lain tertidur, Pip membuka mata bulatnya yang besar dan menyaksikan bulan terbit perlahan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_3', 'bok_goodnight-little-owl', 3, 'owl-3', 'She gently glided from branch to branch, humming a soft tune only the stars could hear.', 'Ia terbang lembut dari dahan ke dahan, bersenandung pelan yang hanya bisa didengar oleh bintang-bintang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_4', 'bok_goodnight-little-owl', 4, 'owl-4', 'Down below, a little firefly blinked her light. "Aren''t you scared of the dark?" she asked.', 'Di bawah sana, seekor kunang-kunang kecil berkedip. "Kamu tidak takut gelap?" tanyanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_5', 'bok_goodnight-little-owl', 5, 'owl-5', '"The dark is my favorite blanket," said Pip with a smile. "It is soft, quiet, and full of stars."', '"Gelap adalah selimut favoritku," kata Pip sambil tersenyum. "Lembut, tenang, dan penuh bintang."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_6', 'bok_goodnight-little-owl', 6, 'owl-6', 'The firefly smiled back and lit up beside her, and together they made the night feel warm and cozy.', 'Kunang-kunang itu tersenyum balik dan bersinar di sampingnya, dan bersama-sama mereka membuat malam terasa hangat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_goodnight-little-owl_7', 'bok_goodnight-little-owl', 7, 'owl-7', 'As the forest grew sleepy and still, Pip whispered goodnight to the moon — and so do you. Sweet dreams.', 'Saat hutan mulai lelap dan tenang, Pip berbisik selamat malam pada bulan — begitu juga kamu. Mimpi indah.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_goodnight-little-owl_1', 'bok_goodnight-little-owl', 1, 'What is Pip''s name?', 'Siapa nama burung hantu kecil itu?', '["Pip","Hoot","Luna","Star"]', '["Pip","Hoot","Luna","Star"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_goodnight-little-owl_2', 'bok_goodnight-little-owl', 2, 'What did Pip call the dark?', 'Apa julukan Pip untuk kegelapan?', '["Her favorite blanket","Something scary","A monster","Cold and lonely"]', '["Selimut favoritnya","Sesuatu yang menakutkan","Monster","Dingin dan sepi"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_goodnight-little-owl_3', 'bok_goodnight-little-owl', 3, 'Who became friends with Pip?', 'Siapa yang berteman dengan Pip?', '["A firefly","A wolf","A cat","A bear"]', '["Kunang-kunang","Serigala","Kucing","Beruang"]', 0, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-letter-parade', 'the-letter-parade', 'The Letter Parade', 'Parade Huruf', 'The letters of the alphabet come to life for a parade, helping a little girl fall in love with reading.', 'Huruf-huruf abjad hidup dan berbaris dalam parade, membuat seorang gadis kecil jatuh cinta pada membaca.', 'cat_learning', 'aut_axto-creative-team', 'dusk', '🔤', 3, 6, 0, 'published', 6, 4256, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-letter-parade_1', 'bok_the-letter-parade', 1, 'letter-1', 'Every night before bed, little Nadia said, "I don''t like letters. They look like squiggly lines."', 'Setiap malam sebelum tidur, Nadia kecil berkata, "Aku tidak suka huruf. Bentuknya seperti garis-garis aneh."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-letter-parade_2', 'bok_the-letter-parade', 2, 'letter-2', 'One night, a shining letter A hopped off her book. "Would you like to meet my friends?" it asked cheerfully.', 'Suatu malam, huruf A yang berkilau melompat keluar dari bukunya. "Mau berkenalan dengan teman-temanku?" tanyanya riang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-letter-parade_3', 'bok_the-letter-parade', 3, 'letter-3', 'Suddenly, B bounced in like a ball, C curled up like a smiling moon, and D marched like a little drum.', 'Tiba-tiba, B memantul seperti bola, C melengkung seperti bulan yang tersenyum, dan D berbaris seperti drum kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-letter-parade_4', 'bok_the-letter-parade', 4, 'letter-4', 'The letters lined up into a parade, and when they marched together, they spelled Nadia''s name!', 'Huruf-huruf itu berbaris membentuk parade, dan ketika berjalan bersama, mereka mengeja nama Nadia!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-letter-parade_5', 'bok_the-letter-parade', 5, 'letter-5', '"Every letter is a puzzle piece," said A. "Put enough pieces together, and you can tell any story in the world."', '"Setiap huruf adalah kepingan puzzle," kata A. "Kumpulkan cukup banyak kepingan, dan kamu bisa menceritakan kisah apa pun di dunia."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-letter-parade_6', 'bok_the-letter-parade', 6, 'letter-6', 'From that night on, Nadia looked at every book with new excitement, ready to meet the letters inside.', 'Sejak malam itu, Nadia memandang setiap buku dengan semangat baru, siap bertemu huruf-huruf di dalamnya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-letter-parade_1', 'bok_the-letter-parade', 1, 'What did Nadia think of letters at first?', 'Apa pendapat Nadia tentang huruf pada awalnya?', '["She loved them","She thought they were squiggly lines","She thought they were tasty","She ignored them"]', '["Ia menyukainya","Ia pikir bentuknya aneh","Ia pikir rasanya enak","Ia mengabaikannya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-letter-parade_2', 'bok_the-letter-parade', 2, 'What did the letters spell when they marched together?', 'Apa yang dieja huruf-huruf saat berbaris bersama?', '["Nadia''s name","A number","A song","Nothing"]', '["Nama Nadia","Sebuah angka","Sebuah lagu","Tidak ada apa-apa"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-letter-parade_3', 'bok_the-letter-parade', 3, 'What did letter A compare letters to?', 'Huruf A membandingkan huruf dengan apa?', '["Puzzle pieces","Rocks","Clouds","Shoes"]', '["Kepingan puzzle","Batu","Awan","Sepatu"]', 0, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-honest-woodcutter', 'the-honest-woodcutter', 'The Honest Woodcutter', 'Tukang Kayu yang Jujur', 'A retelling of a timeless folk tale about a poor woodcutter whose honesty is rewarded beyond measure.', 'Kisah rakyat abadi tentang tukang kayu miskin yang kejujurannya diganjar dengan berlipat ganda.', 'cat_moral-stories', 'aut_axto-creative-team', 'meadow', '🪓', 4, 9, 0, 'published', 7, 1229, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_1', 'bok_the-honest-woodcutter', 1, 'wood-1', 'Near a quiet village lived a poor woodcutter named Tomo, who worked hard every single day to feed his family.', 'Dekat sebuah desa yang tenang, hiduplah tukang kayu miskin bernama Tomo, yang bekerja keras setiap hari demi keluarganya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_2', 'bok_the-honest-woodcutter', 2, 'wood-2', 'One afternoon, while cutting wood by the river, his old iron axe slipped from his hands and sank into the water.', 'Suatu siang, saat menebang kayu di tepi sungai, kapak besinya yang tua terlepas dari tangannya dan tenggelam ke dalam air.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_3', 'bok_the-honest-woodcutter', 3, 'wood-3', 'Tomo sat down and cried, for that old axe was his only tool to earn a living. Suddenly, the river sparkled with light.', 'Tomo duduk dan menangis, sebab kapak tua itu adalah satu-satunya alat untuk mencari nafkah. Tiba-tiba, sungai itu berkilau cahaya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_4', 'bok_the-honest-woodcutter', 4, 'wood-4', 'A kind spirit of the river rose up, holding a golden axe. "Is this your axe?" she asked gently.', 'Seorang roh sungai yang baik hati muncul, membawa kapak emas. "Apakah ini kapakmu?" tanyanya lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_5', 'bok_the-honest-woodcutter', 5, 'wood-5', '"No," said Tomo honestly, "mine was old and made of iron, not gold." The spirit smiled and dove again, returning with a silver axe — but Tomo said the same.', '"Bukan," jawab Tomo jujur, "milikku sudah tua dan terbuat dari besi, bukan emas." Roh itu tersenyum dan menyelam lagi, kembali membawa kapak perak — namun Tomo tetap berkata jujur bahwa itu bukan miliknya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_6', 'bok_the-honest-woodcutter', 6, 'wood-6', 'Finally, she returned his old iron axe. "Because you told the truth," she said, "please accept all three axes as a gift."', 'Akhirnya, ia mengembalikan kapak besi milik Tomo. "Karena kau berkata jujur," katanya, "terimalah ketiga kapak ini sebagai hadiah."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_7', 'bok_the-honest-woodcutter', 7, 'wood-7', 'Tomo thanked her with a full heart, and from that day, his honesty was known throughout the whole village.', 'Tomo berterima kasih dengan hati yang penuh, dan sejak hari itu, kejujurannya dikenal di seluruh desa.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-honest-woodcutter_1', 'bok_the-honest-woodcutter', 1, 'What happened to Tomo''s axe?', 'Apa yang terjadi pada kapak Tomo?', '["It broke","It fell into the river","It was stolen","It turned to gold"]', '["Patah","Jatuh ke sungai","Dicuri","Berubah jadi emas"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-honest-woodcutter_2', 'bok_the-honest-woodcutter', 2, 'What did Tomo say when shown the golden axe?', 'Apa jawaban Tomo saat ditunjukkan kapak emas?', '["\"Yes, that is mine!\"","\"No, mine was iron\"","He said nothing","He took it anyway"]', '["\"Ya, itu milikku!\"","\"Bukan, milikku dari besi\"","Ia diam saja","Ia tetap mengambilnya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-honest-woodcutter_3', 'bok_the-honest-woodcutter', 3, 'Why did the river spirit reward Tomo?', 'Mengapa roh sungai memberi hadiah kepada Tomo?', '["Because he was rich","Because he was honest","Because he was fast","Because he asked for gold"]', '["Karena ia kaya","Karena ia jujur","Karena ia cepat","Karena ia meminta emas"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-magic-forest', 'the-magic-forest', 'The Magic Forest', 'Hutan Ajaib', 'Two siblings discover a hidden forest where every tree grants a wish — as long as it is a kind one.', 'Dua bersaudara menemukan hutan tersembunyi tempat setiap pohon mengabulkan permintaan — asal permintaan itu baik.', 'cat_fairy-tales', 'aut_sarah-johnson', 'forest', '🌳', 3, 8, 0, 'published', 7, 1788, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_1', 'bok_the-magic-forest', 1, 'forest-1', 'Siblings Aya and Budi were chasing a butterfly when they stumbled into a part of the forest they had never seen.', 'Kakak beradik Aya dan Budi sedang mengejar kupu-kupu ketika tiba-tiba mereka tersesat ke bagian hutan yang belum pernah mereka lihat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_2', 'bok_the-magic-forest', 2, 'forest-2', 'The leaves shimmered like silver, and the air smelled like warm honey and rain.', 'Daun-daunnya berkilau seperti perak, dan udaranya beraroma madu hangat dan hujan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_3', 'bok_the-magic-forest', 3, 'forest-3', 'An old tree with kind, glowing eyes spoke softly: "This is the Wishing Forest. Every tree here can grant one kind wish."', 'Sebatang pohon tua bermata lembut dan bercahaya berkata pelan, "Ini Hutan Permintaan. Setiap pohon di sini bisa mengabulkan satu permintaan baik."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_4', 'bok_the-magic-forest', 4, 'forest-4', 'Budi wished for a mountain of candy, but the tree only rustled and stayed silent — that wish was not kind, only for himself.', 'Budi meminta gunung permen, tapi pohon itu hanya bergemerisik dan diam — permintaan itu tidak baik, hanya untuk dirinya sendiri.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_5', 'bok_the-magic-forest', 5, 'forest-5', 'Then Aya wished for the nearby stream to always have clean water for every animal in the forest.', 'Lalu Aya berharap agar sungai di dekat sana selalu memiliki air bersih untuk semua hewan di hutan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_6', 'bok_the-magic-forest', 6, 'forest-6', 'The tree glowed brightly, and the stream sparkled clean and clear. "A wish for others always grows the strongest," it said.', 'Pohon itu bersinar terang, dan sungai berkilau bersih dan jernih. "Permintaan untuk orang lain selalu tumbuh paling kuat," katanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-forest_7', 'bok_the-magic-forest', 7, 'forest-7', 'Budi learned from his sister, and the next year, he returned to wish for shelter for the forest''s smallest animals.', 'Budi belajar dari kakaknya, dan tahun berikutnya, ia kembali untuk berharap ada tempat berlindung bagi hewan-hewan terkecil di hutan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-forest_1', 'bok_the-magic-forest', 1, 'What did the trees in the Wishing Forest grant?', 'Apa yang dikabulkan pohon-pohon di Hutan Permintaan?', '["Any wish at all","Only kind wishes","Only wishes for candy","No wishes"]', '["Semua jenis permintaan","Hanya permintaan baik","Hanya permintaan permen","Tidak ada permintaan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-forest_2', 'bok_the-magic-forest', 2, 'Why didn''t Budi''s first wish come true?', 'Mengapa permintaan pertama Budi tidak dikabulkan?', '["It was too big","It was only for himself","The tree was asleep","He asked incorrectly"]', '["Terlalu besar","Hanya untuk dirinya sendiri","Pohonnya sedang tidur","Ia salah bertanya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-forest_3', 'bok_the-magic-forest', 3, 'What did Aya wish for?', 'Apa yang diminta Aya?', '["A mountain of candy","Clean water for the animals","A new toy","To go home"]', '["Gunung permen","Air bersih untuk hewan-hewan","Mainan baru","Pulang ke rumah"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_princess-aira-and-the-lost-kite', 'princess-aira-and-the-lost-kite', 'Princess Aira and the Lost Kite', 'Putri Aira dan Layang-Layang yang Hilang', 'A young princess sets aside her crown to chase her kite across the kingdom, making unlikely friends along the way.', 'Seorang putri kecil melepas mahkotanya untuk mengejar layang-layangnya, dan menemukan sahabat-sahabat baru yang tak terduga.', 'cat_fairy-tales', 'aut_siti-aminah', 'dusk', '👑', 4, 8, 0, 'published', 7, 3244, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_1', 'bok_princess-aira-and-the-lost-kite', 1, 'aira-1', 'In a kingdom by the hills, Princess Aira loved flying her red kite more than wearing her golden crown.', 'Di sebuah kerajaan di antara bukit-bukit, Putri Aira lebih suka menerbangkan layang-layang merahnya daripada memakai mahkota emas.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_2', 'bok_princess-aira-and-the-lost-kite', 2, 'aira-2', 'One windy afternoon, a strong gust snatched her kite away, carrying it over the castle walls.', 'Suatu sore yang berangin, hembusan kencang merenggut layang-layangnya, membawanya melewati tembok istana.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_3', 'bok_princess-aira-and-the-lost-kite', 3, 'aira-3', 'Without a second thought, Aira took off her crown, put on her walking boots, and ran after it.', 'Tanpa berpikir dua kali, Aira melepas mahkotanya, memakai sepatu botnya, dan berlari mengejarnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_4', 'bok_princess-aira-and-the-lost-kite', 4, 'aira-4', 'She met a baker boy who showed her a shortcut through the market, and a farmer girl who pointed toward the hills.', 'Ia bertemu seorang anak tukang roti yang menunjukkan jalan pintas melalui pasar, dan seorang anak petani yang menunjuk ke arah bukit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_5', 'bok_princess-aira-and-the-lost-kite', 5, 'aira-5', 'At last, she found her kite gently caught in a tall apple tree, with new friends cheering beside her.', 'Akhirnya, ia menemukan layang-layangnya tersangkut lembut di pohon apel yang tinggi, dengan teman-teman baru bersorak di sampingnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_6', 'bok_princess-aira-and-the-lost-kite', 6, 'aira-6', 'Together they climbed and freed the kite, laughing as it soared back into the golden evening sky.', 'Bersama-sama mereka memanjat dan melepaskan layang-layang itu, tertawa saat ia kembali terbang ke langit senja keemasan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-aira-and-the-lost-kite_7', 'bok_princess-aira-and-the-lost-kite', 7, 'aira-7', 'Aira returned to the castle without her crown, but with something far more precious — new friends from every corner of the kingdom.', 'Aira kembali ke istana tanpa mahkotanya, tetapi membawa sesuatu yang jauh lebih berharga — sahabat baru dari setiap penjuru kerajaan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_princess-aira-and-the-lost-kite_1', 'bok_princess-aira-and-the-lost-kite', 1, 'What did Princess Aira love more than her crown?', 'Apa yang lebih disukai Putri Aira daripada mahkotanya?', '["Flying her kite","Eating cake","Reading books","Playing music"]', '["Menerbangkan layang-layang","Makan kue","Membaca buku","Bermain musik"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_princess-aira-and-the-lost-kite_2', 'bok_princess-aira-and-the-lost-kite', 2, 'Who helped Aira find her way?', 'Siapa yang membantu Aira menemukan jalan?', '["A baker boy and a farmer girl","The king","A dragon","No one"]', '["Anak tukang roti dan anak petani","Sang raja","Seekor naga","Tidak ada yang membantu"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_princess-aira-and-the-lost-kite_3', 'bok_princess-aira-and-the-lost-kite', 3, 'What did Aira gain by the end of the story?', 'Apa yang didapat Aira di akhir cerita?', '["A new crown","New friends","A new kite","Gold coins"]', '["Mahkota baru","Sahabat baru","Layang-layang baru","Koin emas"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_counting-stars-with-mira', 'counting-stars-with-mira', 'Counting Stars with Mira', 'Menghitung Bintang Bersama Mira', 'Mira and her grandfather count stars one by one and discover that numbers can be magical.', 'Mira dan kakeknya menghitung bintang satu per satu dan menemukan bahwa angka bisa terasa ajaib.', 'cat_numbers', 'aut_axto-creative-team', 'cosmic', '⭐', 3, 6, 0, 'published', 6, 999, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_counting-stars-with-mira_1', 'bok_counting-stars-with-mira', 1, 'mira-1', 'Every clear night, Mira climbed onto the roof with Grandpa to look at the sky.', 'Setiap malam cerah, Mira naik ke atap bersama Kakek untuk memandangi langit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_counting-stars-with-mira_2', 'bok_counting-stars-with-mira', 2, 'mira-2', '"Let''s count the stars," said Grandpa. "One star, two stars, three stars!"', '"Ayo kita hitung bintangnya," kata Kakek. "Satu bintang, dua bintang, tiga bintang!"');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_counting-stars-with-mira_3', 'bok_counting-stars-with-mira', 3, 'mira-3', 'Mira giggled and pointed at four twinkling stars shaped like a kite, then five more near the moon.', 'Mira tertawa dan menunjuk empat bintang berkelip berbentuk layang-layang, lalu lima lagi dekat bulan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_counting-stars-with-mira_4', 'bok_counting-stars-with-mira', 4, 'mira-4', 'By the time they reached ten, Mira could count all on her own, without any help at all.', 'Saat mereka sampai hitungan sepuluh, Mira sudah bisa menghitung sendiri tanpa bantuan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_counting-stars-with-mira_5', 'bok_counting-stars-with-mira', 5, 'mira-5', '"Numbers help us see how big the world is," said Grandpa, "from one tiny star to a thousand."', '"Angka membantu kita melihat seberapa besar dunia ini," kata Kakek, "dari satu bintang kecil sampai seribu."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_counting-stars-with-mira_6', 'bok_counting-stars-with-mira', 6, 'mira-6', 'From that night on, Mira counted everything she loved — her toys, her books, and her stars.', 'Sejak malam itu, Mira menghitung semua yang ia sukai — mainannya, bukunya, dan bintang-bintangnya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_counting-stars-with-mira_1', 'bok_counting-stars-with-mira', 1, 'Who did Mira count stars with?', 'Bersama siapa Mira menghitung bintang?', '["Her teacher","Grandpa","Her dog","A neighbor"]', '["Gurunya","Kakek","Anjingnya","Tetangga"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_counting-stars-with-mira_2', 'bok_counting-stars-with-mira', 2, 'How many stars could Mira count by the end?', 'Sampai angka berapa Mira bisa menghitung di akhir cerita?', '["Five","Ten","Twenty","One hundred"]', '["Lima","Sepuluh","Dua puluh","Seratus"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_counting-stars-with-mira_3', 'bok_counting-stars-with-mira', 3, 'What did Mira start counting after that night?', 'Apa yang mulai dihitung Mira setelah malam itu?', '["Only stars","Everything she loved","Nothing","Only numbers on a clock"]', '["Hanya bintang","Semua yang ia sukai","Tidak ada","Hanya angka di jam"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_two-best-friends-and-one-umbrella', 'two-best-friends-and-one-umbrella', 'Two Best Friends and One Umbrella', 'Dua Sahabat dan Satu Payung', 'When sudden rain catches two friends with only one umbrella, they learn that sharing makes any storm smaller.', 'Saat hujan tiba-tiba turun dan hanya ada satu payung, dua sahabat belajar bahwa berbagi membuat badai apa pun terasa lebih kecil.', 'cat_friendship', 'aut_axto-creative-team', 'ocean', '☂️', 3, 7, 0, 'published', 6, 2275, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_two-best-friends-and-one-umbrella_1', 'bok_two-best-friends-and-one-umbrella', 1, 'friends-1', 'Dara and Beni walked home from school together every single day, rain or shine.', 'Dara dan Beni selalu berjalan pulang sekolah bersama setiap hari, hujan atau cerah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_two-best-friends-and-one-umbrella_2', 'bok_two-best-friends-and-one-umbrella', 2, 'friends-2', 'One afternoon, dark clouds rolled in fast, and only Dara remembered to bring an umbrella.', 'Suatu sore, awan gelap datang dengan cepat, dan hanya Dara yang ingat membawa payung.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_two-best-friends-and-one-umbrella_3', 'bok_two-best-friends-and-one-umbrella', 3, 'friends-3', '"You take it," said Dara. "No, you take it," said Beni. Neither wanted the other to get wet.', '"Kamu pakai saja," kata Dara. "Tidak, kamu saja," kata Beni. Tak ada yang mau temannya basah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_two-best-friends-and-one-umbrella_4', 'bok_two-best-friends-and-one-umbrella', 4, 'friends-4', 'Then Dara had an idea. "Let''s hold it together, in the middle, so we both stay dry!"', 'Lalu Dara punya ide. "Ayo kita pegang bersama, di tengah, supaya kita berdua tetap kering!"');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_two-best-friends-and-one-umbrella_5', 'bok_two-best-friends-and-one-umbrella', 5, 'friends-5', 'They laughed as they splashed through puddles, shoulder to shoulder under the small umbrella.', 'Mereka tertawa sambil menerjang genangan air, berdampingan di bawah payung kecil itu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_two-best-friends-and-one-umbrella_6', 'bok_two-best-friends-and-one-umbrella', 6, 'friends-6', 'They reached home a little damp at the edges, but happier than any dry walk alone.', 'Mereka sampai rumah dengan sedikit basah di ujung baju, tapi lebih bahagia daripada jalan sendirian dalam keadaan kering.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_two-best-friends-and-one-umbrella_1', 'bok_two-best-friends-and-one-umbrella', 1, 'Who remembered to bring an umbrella?', 'Siapa yang ingat membawa payung?', '["Beni","Dara","Their teacher","No one"]', '["Beni","Dara","Gurunya","Tidak ada"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_two-best-friends-and-one-umbrella_2', 'bok_two-best-friends-and-one-umbrella', 2, 'How did they solve the umbrella problem?', 'Bagaimana mereka menyelesaikan masalah payung itu?', '["They ran home separately","They held it together","They waited for the rain to stop","They called a taxi"]', '["Mereka lari pulang sendiri-sendiri","Mereka memegangnya bersama","Mereka menunggu hujan reda","Mereka memanggil taksi"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_two-best-friends-and-one-umbrella_3', 'bok_two-best-friends-and-one-umbrella', 3, 'What is the lesson of this story?', 'Apa pelajaran dari cerita ini?', '["Always walk home alone","Sharing makes hard moments easier together","Umbrellas are not useful","Rain should be avoided at all costs"]', '["Selalu jalan pulang sendirian","Berbagi membuat saat sulit terasa lebih ringan bersama","Payung tidak berguna","Hujan harus dihindari dengan segala cara"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_captain-kindness-saves-the-day', 'captain-kindness-saves-the-day', 'Captain Kindness Saves the Day', 'Captain Kindness Menyelamatkan Hari', 'A boy discovers that his cardboard cape and a kind heart make him a real kind of hero.', 'Seorang anak menyadari bahwa jubah kardusnya dan hati yang baik menjadikannya pahlawan sungguhan.', 'cat_superheroes', 'aut_axto-creative-team', 'dusk', '🦸', 4, 8, 0, 'published', 6, 1384, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-kindness-saves-the-day_1', 'bok_captain-kindness-saves-the-day', 1, 'hero-1', 'Eli wore a cardboard cape everywhere he went, pretending to be a mighty superhero.', 'Eli memakai jubah kardus ke mana pun ia pergi, berpura-pura menjadi pahlawan super yang hebat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-kindness-saves-the-day_2', 'bok_captain-kindness-saves-the-day', 2, 'hero-2', 'He practiced flying poses and superhero landings, but he had never actually saved anyone.', 'Ia berlatih pose terbang dan gaya mendarat pahlawan, tapi belum pernah benar-benar menolong siapa pun.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-kindness-saves-the-day_3', 'bok_captain-kindness-saves-the-day', 3, 'hero-3', 'At the park, he saw a little girl crying because her balloon had floated into a tall tree.', 'Di taman, ia melihat seorang gadis kecil menangis karena balonnya tersangkut di pohon tinggi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-kindness-saves-the-day_4', 'bok_captain-kindness-saves-the-day', 4, 'hero-4', '"Don''t worry! Captain Kindness is here!" Eli called out, and he found a long stick to help.', '"Jangan khawatir! Captain Kindness datang!" seru Eli, dan ia mencari tongkat panjang untuk membantu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-kindness-saves-the-day_5', 'bok_captain-kindness-saves-the-day', 5, 'hero-5', 'With a gentle poke, the balloon floated back down, and the little girl smiled brightly.', 'Dengan colekan lembut, balon itu melayang turun kembali, dan gadis kecil itu tersenyum cerah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-kindness-saves-the-day_6', 'bok_captain-kindness-saves-the-day', 6, 'hero-6', 'Eli realized his real superpower was not flying — it was noticing when someone needed help.', 'Eli menyadari kekuatan sejatinya bukanlah terbang — melainkan peka saat ada yang membutuhkan bantuan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_captain-kindness-saves-the-day_1', 'bok_captain-kindness-saves-the-day', 1, 'What did Eli wear as his superhero costume?', 'Apa yang dipakai Eli sebagai kostum pahlawannya?', '["A cardboard cape","A real cape","A crown","Wings"]', '["Jubah kardus","Jubah sungguhan","Mahkota","Sayap"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_captain-kindness-saves-the-day_2', 'bok_captain-kindness-saves-the-day', 2, 'How did Eli help the little girl?', 'Bagaimana Eli membantu gadis kecil itu?', '["He flew up to get the balloon","He used a long stick","He called her parents","He gave her a new balloon"]', '["Ia terbang mengambil balon","Ia menggunakan tongkat panjang","Ia memanggil orang tuanya","Ia memberi balon baru"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_captain-kindness-saves-the-day_3', 'bok_captain-kindness-saves-the-day', 3, 'What did Eli learn was his real superpower?', 'Apa yang Eli sadari sebagai kekuatan sejatinya?', '["Flying","Noticing when someone needs help","Being invisible","Super strength"]', '["Terbang","Peka saat ada yang butuh bantuan","Menghilang","Kekuatan super"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_trucky-the-brave-fire-truck', 'trucky-the-brave-fire-truck', 'Trucky the Brave Fire Truck', 'Trucky, Mobil Pemadam yang Berani', 'A young fire truck who feels too small learns that courage, not size, is what makes a rescue vehicle brave.', 'Sebuah mobil pemadam kebakaran kecil yang merasa terlalu mungil belajar bahwa keberanian, bukan ukuran, yang membuatnya hebat.', 'cat_vehicles', 'aut_axto-creative-team', 'candy', '🚒', 3, 7, 0, 'published', 6, 4933, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_trucky-the-brave-fire-truck_1', 'bok_trucky-the-brave-fire-truck', 1, 'truck-1', 'At Maple Street Fire Station, the newest fire truck was small and shiny red. His name was Trucky.', 'Di Stasiun Pemadam Jalan Maple, mobil pemadam terbaru berukuran kecil dan merah mengkilap. Namanya Trucky.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_trucky-the-brave-fire-truck_2', 'bok_trucky-the-brave-fire-truck', 2, 'truck-2', 'The big trucks could carry tall ladders and huge hoses. Trucky worried he was too small to help.', 'Truk-truk besar bisa membawa tangga tinggi dan selang raksasa. Trucky khawatir ia terlalu kecil untuk membantu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_trucky-the-brave-fire-truck_3', 'bok_trucky-the-brave-fire-truck', 3, 'truck-3', 'One day, an alarm rang for a kitten stuck in a narrow drainpipe that no big truck could reach.', 'Suatu hari, alarm berbunyi untuk seekor kucing kecil yang terjebak di pipa saluran sempit yang tak terjangkau truk besar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_trucky-the-brave-fire-truck_4', 'bok_trucky-the-brave-fire-truck', 4, 'truck-4', '"This is a job for someone small and brave," said the fire chief, looking right at Trucky.', '"Ini tugas untuk yang kecil dan berani," kata kepala pemadam, menatap langsung ke Trucky.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_trucky-the-brave-fire-truck_5', 'bok_trucky-the-brave-fire-truck', 5, 'truck-5', 'Trucky squeezed carefully through the narrow lane, and his crew gently rescued the frightened kitten.', 'Trucky menyelinap hati-hati melewati gang sempit, dan krunya menyelamatkan kucing ketakutan itu dengan lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_trucky-the-brave-fire-truck_6', 'bok_trucky-the-brave-fire-truck', 6, 'truck-6', 'That day, Trucky learned that every size has its own superpower — his was fitting where big trucks could not.', 'Hari itu, Trucky belajar bahwa setiap ukuran punya kekuatannya sendiri — miliknya adalah bisa masuk ke tempat yang tak terjangkau truk besar.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_trucky-the-brave-fire-truck_1', 'bok_trucky-the-brave-fire-truck', 1, 'What was Trucky worried about?', 'Apa yang dikhawatirkan Trucky?', '["Being too loud","Being too small to help","Being too fast","Being too red"]', '["Terlalu berisik","Terlalu kecil untuk membantu","Terlalu cepat","Terlalu merah"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_trucky-the-brave-fire-truck_2', 'bok_trucky-the-brave-fire-truck', 2, 'Who needed rescuing in the drainpipe?', 'Siapa yang perlu diselamatkan di pipa saluran?', '["A kitten","A puppy","A bird","A ball"]', '["Seekor kucing","Seekor anjing","Seekor burung","Sebuah bola"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_trucky-the-brave-fire-truck_3', 'bok_trucky-the-brave-fire-truck', 3, 'What did Trucky learn about his size?', 'Apa yang dipelajari Trucky tentang ukurannya?', '["Small size has its own superpower","He should become bigger","Size does not matter at all","Only big trucks can help"]', '["Ukuran kecil punya kekuatannya sendiri","Ia harus menjadi lebih besar","Ukuran sama sekali tidak penting","Hanya truk besar yang bisa membantu"]', 0, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-drum-that-traveled-the-world', 'the-drum-that-traveled-the-world', 'The Drum That Traveled the World', 'Gendang yang Berkeliling Dunia', 'A magical drum passes from child to child around the world, teaching that music speaks every language.', 'Sebuah gendang ajaib berpindah dari satu anak ke anak lain di seluruh dunia, mengajarkan bahwa musik bisa dimengerti semua orang.', 'cat_world-cultures', 'aut_siti-aminah', 'meadow', '🥁', 4, 9, 0, 'published', 6, 348, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-drum-that-traveled-the-world_1', 'bok_the-drum-that-traveled-the-world', 1, 'drum-1', 'In a village by the mountains, a boy named Bayu carved a small wooden drum from a fallen branch.', 'Di sebuah desa dekat pegunungan, seorang anak bernama Bayu mengukir gendang kecil dari kayu dahan yang jatuh.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-drum-that-traveled-the-world_2', 'bok_the-drum-that-traveled-the-world', 2, 'drum-2', 'He played a joyful beat, and the sound traveled on the wind, over oceans, to a girl in West Africa.', 'Ia memainkan irama gembira, dan suaranya terbawa angin, melintasi lautan, hingga ke seorang gadis di Afrika Barat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-drum-that-traveled-the-world_3', 'bok_the-drum-that-traveled-the-world', 3, 'drum-3', 'She answered with her own rhythm on a talking drum, and children in Brazil began to dance to it.', 'Ia membalas dengan iramanya sendiri di gendang berbicara, dan anak-anak di Brasil mulai menari mengikutinya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-drum-that-traveled-the-world_4', 'bok_the-drum-that-traveled-the-world', 4, 'drum-4', 'From Brazil, the beat reached Japan, where a boy added the tap of his taiko drum to the song.', 'Dari Brasil, irama itu sampai ke Jepang, tempat seorang anak menambahkan ketukan taiko-nya ke lagu tersebut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-drum-that-traveled-the-world_5', 'bok_the-drum-that-traveled-the-world', 5, 'drum-5', 'One by one, children from every corner of the world joined in, each adding their own special rhythm.', 'Satu per satu, anak-anak dari setiap penjuru dunia ikut bergabung, masing-masing menambahkan irama khas mereka.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-drum-that-traveled-the-world_6', 'bok_the-drum-that-traveled-the-world', 6, 'drum-6', 'Though none of them spoke the same words, together they made one beautiful song everyone understood.', 'Meski tak satu pun berbicara bahasa yang sama, bersama-sama mereka menciptakan satu lagu indah yang dimengerti semua orang.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-drum-that-traveled-the-world_1', 'bok_the-drum-that-traveled-the-world', 1, 'What did Bayu make the drum from?', 'Dari apa Bayu membuat gendangnya?', '["Metal","A fallen branch","Plastic","Stone"]', '["Logam","Dahan yang jatuh","Plastik","Batu"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-drum-that-traveled-the-world_2', 'bok_the-drum-that-traveled-the-world', 2, 'Which country did the rhythm travel to first?', 'Ke negara mana irama itu pertama kali sampai?', '["Japan","West Africa","Brazil","Indonesia"]', '["Jepang","Afrika Barat","Brasil","Indonesia"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-drum-that-traveled-the-world_3', 'bok_the-drum-that-traveled-the-world', 3, 'What is the message of the story?', 'Apa pesan dari cerita ini?', '["Only one country can make music","Music can be understood across every language","Drums are difficult to play","Children should not share instruments"]', '["Hanya satu negara yang bisa membuat musik","Musik bisa dimengerti melintasi semua bahasa","Gendang sulit dimainkan","Anak-anak tidak boleh berbagi alat musik"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-sneezing-elephant', 'the-sneezing-elephant', 'The Sneezing Elephant', 'Gajah yang Bersin', 'A silly, giant sneeze causes a chain of giggles across the savanna in this gentle story about laughing together.', 'Sebuah bersin raksasa yang konyol memicu deretan tawa di seluruh savana dalam cerita hangat tentang tertawa bersama.', 'cat_humor', 'aut_axto-creative-team', 'sunrise', '🐘', 2, 6, 0, 'published', 6, 3876, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-sneezing-elephant_1', 'bok_the-sneezing-elephant', 1, 'elephant-1', 'Ellie the elephant felt a tickle in her big trunk. "Ah... ah... AH-CHOO!"', 'Ellie si gajah merasa geli di belalainya yang besar. "Hah... hah... HATCHIII!"');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-sneezing-elephant_2', 'bok_the-sneezing-elephant', 2, 'elephant-2', 'The sneeze was SO big that it blew all the leaves off the nearest tree in one gust!', 'Bersinnya begitu besar sehingga menerbangkan semua daun dari pohon terdekat dalam sekali hembusan!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-sneezing-elephant_3', 'bok_the-sneezing-elephant', 3, 'elephant-3', 'A monkey fell off his branch laughing, which made a giraffe laugh so hard she got hiccups.', 'Seekor monyet jatuh dari dahannya karena tertawa, membuat seekor jerapah tertawa begitu keras sampai cegukan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-sneezing-elephant_4', 'bok_the-sneezing-elephant', 4, 'elephant-4', 'The giraffe''s "HIC! HIC!" made a family of zebras giggle so much they rolled in the dust.', '"HIK! HIK!" jerapah itu membuat sekeluarga zebra tertawa terpingkal-pingkal hingga berguling di tanah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-sneezing-elephant_5', 'bok_the-sneezing-elephant', 5, 'elephant-5', 'Soon the whole savanna was laughing together, though none of them quite remembered why anymore!', 'Tak lama, seluruh savana tertawa bersama, meski tak satu pun lagi ingat kenapa mereka mulai tertawa!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-sneezing-elephant_6', 'bok_the-sneezing-elephant', 6, 'elephant-6', '"Bless you, Ellie," they all said at last, still smiling. One little sneeze had made everyone''s day brighter.', '"Semoga sehat, Ellie," kata mereka semua akhirnya, masih tersenyum. Satu bersin kecil membuat hari semua orang lebih cerah.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-sneezing-elephant_1', 'bok_the-sneezing-elephant', 1, 'What happened when Ellie sneezed?', 'Apa yang terjadi saat Ellie bersin?', '["Nothing happened","It blew leaves off a tree","It started raining","All the animals ran away"]', '["Tidak ada yang terjadi","Menerbangkan daun dari pohon","Mulai hujan","Semua hewan lari"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-sneezing-elephant_2', 'bok_the-sneezing-elephant', 2, 'What happened to the giraffe?', 'Apa yang terjadi pada jerapah?', '["She got hiccups from laughing","She fell asleep","She sneezed too","She got scared"]', '["Ia cegukan karena tertawa","Ia tertidur","Ia juga bersin","Ia ketakutan"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-sneezing-elephant_3', 'bok_the-sneezing-elephant', 3, 'What is this story mainly about?', 'Cerita ini terutama tentang apa?', '["A scary storm","A funny chain reaction of laughter","A dangerous adventure","A sad goodbye"]', '["Badai yang menakutkan","Reaksi berantai tawa yang lucu","Petualangan berbahaya","Perpisahan yang sedih"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_ellies-alphabet-adventure', 'ellies-alphabet-adventure', 'Ellie''s Alphabet Adventure', 'Petualangan Abjad Ellie', 'Ellie meets a shy letter who is scared to appear in words, and helps it find its courage.', 'Ellie bertemu sebuah huruf pemalu yang takut muncul di dalam kata, dan membantunya menemukan keberanian.', 'cat_alphabet', 'aut_axto-creative-team', 'candy', '🔤', 2, 5, 0, 'published', 6, 5116, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_ellies-alphabet-adventure_1', 'bok_ellies-alphabet-adventure', 1, 'alphabet-1', 'Ellie loved singing the alphabet every morning. A, B, C, all the way to Z!', 'Ellie suka menyanyikan lagu abjad setiap pagi. A, B, C, sampai ke Z!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_ellies-alphabet-adventure_2', 'bok_ellies-alphabet-adventure', 2, 'alphabet-2', 'One day, she noticed the letter Q hiding behind a big book, looking very shy.', 'Suatu hari, ia melihat huruf Q bersembunyi di balik buku besar, terlihat sangat pemalu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_ellies-alphabet-adventure_3', 'bok_ellies-alphabet-adventure', 3, 'alphabet-3', '"Why are you hiding?" Ellie asked. Q whispered, "I don''t show up in as many words as the other letters."', '"Kenapa kamu sembunyi?" tanya Ellie. Q berbisik, "Aku tidak muncul di banyak kata seperti huruf lain."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_ellies-alphabet-adventure_4', 'bok_ellies-alphabet-adventure', 4, 'alphabet-4', 'Ellie smiled. "But you make wonderful words like queen, quiet, and quilt!" she said.', 'Ellie tersenyum. "Tapi kamu membuat kata-kata hebat seperti queen, quiet, dan quilt!" katanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_ellies-alphabet-adventure_5', 'bok_ellies-alphabet-adventure', 5, 'alphabet-5', 'Together they found five words that needed Q, and Q felt proud for the very first time.', 'Bersama-sama mereka menemukan lima kata yang butuh Q, dan Q merasa bangga untuk pertama kalinya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_ellies-alphabet-adventure_6', 'bok_ellies-alphabet-adventure', 6, 'alphabet-6', 'From that day, Q always stood tall in the alphabet parade, right between P and R.', 'Sejak hari itu, Q selalu berdiri tegak di barisan abjad, tepat di antara P dan R.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_ellies-alphabet-adventure_1', 'bok_ellies-alphabet-adventure', 1, 'Which letter was hiding?', 'Huruf apa yang bersembunyi?', '["A","Q","Z","M"]', '["A","Q","Z","M"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_ellies-alphabet-adventure_2', 'bok_ellies-alphabet-adventure', 2, 'Why was the letter shy?', 'Kenapa huruf itu pemalu?', '["It was too loud","It was in fewer words than others","It was upside down","It was too big"]', '["Terlalu keras","Muncul di lebih sedikit kata","Terbalik","Terlalu besar"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_ellies-alphabet-adventure_3', 'bok_ellies-alphabet-adventure', 3, 'How did Ellie help?', 'Bagaimana Ellie membantu?', '["She ignored it","She found words that use it","She erased it","She hid too"]', '["Mengabaikannya","Mencari kata yang memakainya","Menghapusnya","Ikut bersembunyi"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_a-day-with-grandma', 'a-day-with-grandma', 'A Day With Grandma', 'Sehari Bersama Nenek', 'A little girl spends a warm afternoon learning her grandmother''s favorite recipe and stories.', 'Seorang gadis kecil menghabiskan sore yang hangat belajar resep dan cerita favorit neneknya.', 'cat_family', 'aut_siti-aminah', 'sunrise', '👵', 3, 7, 0, 'published', 6, 2078, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-grandma_1', 'bok_a-day-with-grandma', 1, 'family-1', 'Every Sunday, Nadia visited her grandmother''s little house at the end of the street.', 'Setiap hari Minggu, Nadia mengunjungi rumah kecil neneknya di ujung jalan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-grandma_2', 'bok_a-day-with-grandma', 2, 'family-2', 'Grandma always smelled like cinnamon and warm bread. "Come help me cook," she said with a smile.', 'Nenek selalu berbau kayu manis dan roti hangat. "Ayo bantu Nenek memasak," katanya sambil tersenyum.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-grandma_3', 'bok_a-day-with-grandma', 3, 'family-3', 'They mixed flour, sugar, and a secret ingredient Grandma would only whisper: a pinch of love.', 'Mereka mengaduk tepung, gula, dan bahan rahasia yang hanya dibisikkan Nenek: sejumput cinta.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-grandma_4', 'bok_a-day-with-grandma', 4, 'family-4', 'While the cookies baked, Grandma told stories about when she was a little girl, just like Nadia.', 'Sambil kue dipanggang, Nenek bercerita tentang masa kecilnya, sama seperti Nadia sekarang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-grandma_5', 'bok_a-day-with-grandma', 5, 'family-5', 'When the cookies were ready, they shared them with the whole family at the dinner table.', 'Ketika kue matang, mereka membagikannya untuk seluruh keluarga di meja makan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-grandma_6', 'bok_a-day-with-grandma', 6, 'family-6', 'Nadia hugged Grandma tight. "Family is the warmest place in the world," she thought.', 'Nadia memeluk Nenek erat. "Keluarga adalah tempat paling hangat di dunia," pikirnya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-day-with-grandma_1', 'bok_a-day-with-grandma', 1, 'What day did Nadia visit Grandma?', 'Hari apa Nadia mengunjungi Nenek?', '["Monday","Sunday","Friday","Saturday"]', '["Senin","Minggu","Jumat","Sabtu"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-day-with-grandma_2', 'bok_a-day-with-grandma', 2, 'What was Grandma''s secret ingredient?', 'Apa bahan rahasia Nenek?', '["Salt","A pinch of love","Extra sugar","Chocolate"]', '["Garam","Sejumput cinta","Gula ekstra","Cokelat"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-day-with-grandma_3', 'bok_a-day-with-grandma', 3, 'What did they do while the cookies baked?', 'Apa yang mereka lakukan sambil kue dipanggang?', '["Watched TV","Told stories","Went shopping","Took a nap"]', '["Menonton TV","Bercerita","Berbelanja","Tidur siang"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_milos-big-feelings', 'milos-big-feelings', 'Milo and His Big Feelings', 'Milo dan Perasaan Besarnya', 'Milo learns that it''s okay to feel angry, sad, or scared, as long as he knows how to talk about it.', 'Milo belajar bahwa tidak apa-apa merasa marah, sedih, atau takut, selama ia tahu cara membicarakannya.', 'cat_emotions', 'aut_sarah-johnson', 'meadow', '😊', 3, 7, 0, 'published', 6, 4182, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_milos-big-feelings_1', 'bok_milos-big-feelings', 1, 'emotions-1', 'Milo''s tower of blocks fell down with a crash. His face turned red and hot.', 'Menara balok Milo runtuh dengan suara keras. Wajahnya memerah dan panas.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_milos-big-feelings_2', 'bok_milos-big-feelings', 2, 'emotions-2', '"I feel like yelling!" Milo said. His mom sat beside him. "That''s okay. That feeling is called anger."', '"Aku ingin berteriak!" kata Milo. Ibunya duduk di sampingnya. "Tidak apa-apa. Perasaan itu namanya marah."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_milos-big-feelings_3', 'bok_milos-big-feelings', 3, 'emotions-3', '"You can feel angry, but we don''t throw things. Let''s take a deep breath together," said Mom.', '"Kamu boleh merasa marah, tapi kita tidak melempar barang. Yuk tarik napas dalam-dalam bersama," kata Ibu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_milos-big-feelings_4', 'bok_milos-big-feelings', 4, 'emotions-4', 'Milo breathed in slowly, then out slowly. The hot feeling started to cool down.', 'Milo menarik napas perlahan, lalu menghembuskannya perlahan. Rasa panas itu mulai mereda.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_milos-big-feelings_5', 'bok_milos-big-feelings', 5, 'emotions-5', '"Now let''s build the tower again, together," Mom said. Milo smiled a little.', '"Sekarang ayo bangun menaranya lagi, bersama-sama," kata Ibu. Milo tersenyum sedikit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_milos-big-feelings_6', 'bok_milos-big-feelings', 6, 'emotions-6', 'Milo learned that every feeling has a name, and every feeling can be talked about.', 'Milo belajar bahwa setiap perasaan punya nama, dan setiap perasaan bisa dibicarakan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_milos-big-feelings_1', 'bok_milos-big-feelings', 1, 'Why did Milo feel upset?', 'Kenapa Milo merasa kesal?', '["He lost a toy","His tower fell down","He was hungry","He was tired"]', '["Kehilangan mainan","Menaranya runtuh","Lapar","Mengantuk"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_milos-big-feelings_2', 'bok_milos-big-feelings', 2, 'What helped Milo feel calmer?', 'Apa yang membuat Milo lebih tenang?', '["Throwing blocks","Taking deep breaths","Yelling louder","Running away"]', '["Melempar balok","Menarik napas dalam","Berteriak lebih keras","Lari"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_milos-big-feelings_3', 'bok_milos-big-feelings', 3, 'What is the name for the feeling Milo had?', 'Apa nama perasaan yang dirasakan Milo?', '["Happiness","Anger","Sleepiness","Hunger"]', '["Bahagia","Marah","Ngantuk","Lapar"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-whispering-wand', 'the-whispering-wand', 'The Whispering Wand', 'Tongkat yang Berbisik', 'A young girl finds a wand that only grants wishes that help others, teaching her real magic is kindness.', 'Seorang gadis kecil menemukan tongkat yang hanya mengabulkan permintaan untuk menolong orang lain.', 'cat_fantasy', 'aut_axto-creative-team', 'cosmic', '🪄', 5, 9, 0, 'published', 6, 2444, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-whispering-wand_1', 'bok_the-whispering-wand', 1, 'fantasy-1', 'Deep in the Whisper Woods, Lira found a wand glowing softly beneath a silver leaf.', 'Jauh di dalam Hutan Bisikan, Lira menemukan tongkat yang bersinar lembut di bawah daun perak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-whispering-wand_2', 'bok_the-whispering-wand', 2, 'fantasy-2', 'She waved it and wished for a mountain of candy — but nothing happened at all.', 'Ia mengayunkannya dan berharap gunung permen muncul — tapi tidak terjadi apa-apa.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-whispering-wand_3', 'bok_the-whispering-wand', 3, 'fantasy-3', 'A tiny voice giggled from the wand. "I only grant wishes that help someone else," it said.', 'Suara kecil terkekeh dari tongkat itu. "Aku hanya mengabulkan permintaan yang menolong orang lain," katanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-whispering-wand_4', 'bok_the-whispering-wand', 4, 'fantasy-4', 'Lira thought of her neighbor, old Mr. Yusuf, whose garden had wilted in the summer heat.', 'Lira teringat tetangganya, Pak Yusuf, yang kebunnya layu karena panas musim kemarau.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-whispering-wand_5', 'bok_the-whispering-wand', 5, 'fantasy-5', 'She wished for rain for his garden. The wand glowed bright, and soft rain fell that very night.', 'Ia berharap hujan turun untuk kebun itu. Tongkat itu bersinar terang, dan hujan lembut turun malam itu juga.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-whispering-wand_6', 'bok_the-whispering-wand', 6, 'fantasy-6', 'The next morning, Mr. Yusuf''s flowers bloomed again. Lira realized real magic was kindness.', 'Keesokan paginya, bunga-bunga Pak Yusuf mekar kembali. Lira sadar bahwa sihir sejati adalah kebaikan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-whispering-wand_1', 'bok_the-whispering-wand', 1, 'What kind of wish did the wand grant?', 'Permintaan seperti apa yang dikabulkan tongkat itu?', '["Wishes for candy","Wishes that help someone else","Wishes for toys","Any wish at all"]', '["Permen","Yang menolong orang lain","Mainan","Apa saja"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-whispering-wand_2', 'bok_the-whispering-wand', 2, 'Who did Lira help?', 'Siapa yang ditolong Lira?', '["Her teacher","Mr. Yusuf","Her sister","A stranger"]', '["Gurunya","Pak Yusuf","Adiknya","Orang asing"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-whispering-wand_3', 'bok_the-whispering-wand', 3, 'What did Lira learn in the end?', 'Apa yang dipelajari Lira pada akhirnya?', '["Wands are useless","Real magic is kindness","Candy is best","Rain is scary"]', '["Tongkat tidak berguna","Sihir sejati adalah kebaikan","Permen paling enak","Hujan menakutkan"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-case-of-the-missing-cookies', 'the-case-of-the-missing-cookies', 'The Case of the Missing Cookies', 'Kasus Kue Kering yang Hilang', 'Detective Nina uses clues, not accusations, to solve the mystery of the empty cookie jar.', 'Detektif Nina menggunakan petunjuk, bukan tuduhan, untuk memecahkan misteri toples kue yang kosong.', 'cat_mystery', 'aut_david-lee', 'dusk', '🔍', 5, 9, 0, 'published', 6, 234, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-case-of-the-missing-cookies_1', 'bok_the-case-of-the-missing-cookies', 1, 'mystery-1', 'The cookie jar was empty! Nina put on her detective hat and grabbed her magnifying glass.', 'Toples kue itu kosong! Nina memakai topi detektifnya dan mengambil kaca pembesar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-case-of-the-missing-cookies_2', 'bok_the-case-of-the-missing-cookies', 2, 'mystery-2', 'Clue one: crumbs led from the kitchen counter across the floor toward the living room.', 'Petunjuk pertama: remah-remah kue mengarah dari meja dapur ke ruang tamu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-case-of-the-missing-cookies_3', 'bok_the-case-of-the-missing-cookies', 3, 'mystery-3', 'Clue two: a small paw print was pressed into a smear of chocolate on the rug.', 'Petunjuk kedua: jejak kaki kecil tercetak di noda cokelat di atas karpet.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-case-of-the-missing-cookies_4', 'bok_the-case-of-the-missing-cookies', 4, 'mystery-4', 'Nina followed the trail behind the couch, where she found her dog Max fast asleep, crumbs on his nose.', 'Nina mengikuti jejak itu ke belakang sofa, dan menemukan anjingnya Max tertidur pulas, remah di hidungnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-case-of-the-missing-cookies_5', 'bok_the-case-of-the-missing-cookies', 5, 'mystery-5', '"Case closed!" Nina laughed. "Max, you''re a cookie thief, but I still love you."', '"Kasus selesai!" Nina tertawa. "Max, kamu pencuri kue, tapi aku tetap sayang kamu."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-case-of-the-missing-cookies_6', 'bok_the-case-of-the-missing-cookies', 6, 'mystery-6', 'From then on, Nina always kept the cookie jar somewhere Max''s nose couldn''t reach.', 'Sejak itu, Nina selalu menyimpan toples kue di tempat yang tidak terjangkau hidung Max.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-case-of-the-missing-cookies_1', 'bok_the-case-of-the-missing-cookies', 1, 'What tool did Nina use?', 'Alat apa yang digunakan Nina?', '["A telescope","A magnifying glass","A flashlight","A camera"]', '["Teropong","Kaca pembesar","Senter","Kamera"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-case-of-the-missing-cookies_2', 'bok_the-case-of-the-missing-cookies', 2, 'Who ate the cookies?', 'Siapa yang memakan kue itu?', '["Her brother","Her dog Max","A neighbor","Nobody"]', '["Kakaknya","Anjingnya Max","Tetangga","Tidak ada yang makan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-case-of-the-missing-cookies_3', 'bok_the-case-of-the-missing-cookies', 3, 'What clue was on the rug?', 'Petunjuk apa yang ada di karpet?', '["A footprint","A paw print in chocolate","A torn paper","A missing shoe"]', '["Jejak kaki manusia","Jejak kaki dengan cokelat","Kertas sobek","Sepatu hilang"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_captain-nanos-treasure-map', 'captain-nanos-treasure-map', 'Captain Nano''s Treasure Map', 'Peta Harta Karun Kapten Nano', 'A young pirate learns that the greatest treasure on the island is the friends who sailed with her.', 'Seorang bajak laut kecil belajar bahwa harta terbesar di pulau itu adalah teman-teman seperjalanannya.', 'cat_pirates', 'aut_axto-creative-team', 'ocean', '🏴‍☠️', 4, 8, 0, 'published', 6, 4545, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-nanos-treasure-map_1', 'bok_captain-nanos-treasure-map', 1, 'pirates-1', 'Captain Nano and her crew found an old map hidden inside a bottle on the beach.', 'Kapten Nano dan awaknya menemukan peta tua tersembunyi di dalam botol di pantai.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-nanos-treasure-map_2', 'bok_captain-nanos-treasure-map', 2, 'pirates-2', 'The map showed an X on Coconut Island, three days of sailing across the Blue Sea.', 'Peta itu menunjukkan tanda X di Pulau Kelapa, tiga hari berlayar melintasi Laut Biru.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-nanos-treasure-map_3', 'bok_captain-nanos-treasure-map', 3, 'pirates-3', 'Along the way, a storm rocked their little ship, but the crew worked together to steer it safely.', 'Di tengah jalan, badai mengguncang kapal kecil mereka, tapi awak kapal bekerja sama untuk mengemudikannya dengan selamat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-nanos-treasure-map_4', 'bok_captain-nanos-treasure-map', 4, 'pirates-4', 'When they finally dug at the X, they found only a small wooden box with an old note inside.', 'Ketika akhirnya mereka menggali di tanda X, mereka hanya menemukan kotak kayu kecil berisi catatan tua.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-nanos-treasure-map_5', 'bok_captain-nanos-treasure-map', 5, 'pirates-5', 'The note read: "The real treasure was the friends who sailed with you." Captain Nano smiled.', 'Catatan itu berbunyi: "Harta sesungguhnya adalah teman yang berlayar bersamamu." Kapten Nano tersenyum.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_captain-nanos-treasure-map_6', 'bok_captain-nanos-treasure-map', 6, 'pirates-6', 'They sailed home laughing, already planning their next adventure together.', 'Mereka berlayar pulang sambil tertawa, sudah merencanakan petualangan berikutnya bersama.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_captain-nanos-treasure-map_1', 'bok_captain-nanos-treasure-map', 1, 'Where did they find the map?', 'Di mana mereka menemukan peta itu?', '["In a bottle on the beach","In a cave","In a chest","In a book"]', '["Dalam botol di pantai","Dalam gua","Dalam peti","Dalam buku"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_captain-nanos-treasure-map_2', 'bok_captain-nanos-treasure-map', 2, 'What happened during the journey?', 'Apa yang terjadi selama perjalanan?', '["They got lost forever","A storm rocked their ship","They found gold early","Nothing happened"]', '["Tersesat selamanya","Badai mengguncang kapal","Menemukan emas lebih awal","Tidak terjadi apa-apa"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_captain-nanos-treasure-map_3', 'bok_captain-nanos-treasure-map', 3, 'What was the real treasure?', 'Apa harta yang sesungguhnya?', '["Gold coins","Friendship","A map","A ship"]', '["Koin emas","Persahabatan","Peta","Kapal"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_princess-rosa-and-the-kind-knight', 'princess-rosa-and-the-kind-knight', 'Princess Rosa and the Kind Knight', 'Putri Rosa dan Ksatria yang Baik Hati', 'Princess Rosa learns that true bravery is protecting others with kindness, not just a sword.', 'Putri Rosa belajar bahwa keberanian sejati adalah melindungi orang lain dengan kebaikan, bukan hanya pedang.', 'cat_princess-knights', 'aut_sarah-johnson', 'candy', '👑', 4, 8, 0, 'published', 6, 498, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-rosa-and-the-kind-knight_1', 'bok_princess-rosa-and-the-kind-knight', 1, 'princess-1', 'In the Kingdom of Meadowlight, Princess Rosa wanted to become a knight more than anything.', 'Di Kerajaan Meadowlight, Putri Rosa sangat ingin menjadi seorang ksatria.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-rosa-and-the-kind-knight_2', 'bok_princess-rosa-and-the-kind-knight', 2, 'princess-2', 'She trained every day with Sir Callum, the gentlest knight in the castle.', 'Ia berlatih setiap hari bersama Sir Callum, ksatria paling lembut di istana.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-rosa-and-the-kind-knight_3', 'bok_princess-rosa-and-the-kind-knight', 3, 'princess-3', 'One day, a baby dragon got stuck in the castle well, crying for help.', 'Suatu hari, seekor bayi naga terjebak di sumur istana, menangis meminta tolong.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-rosa-and-the-kind-knight_4', 'bok_princess-rosa-and-the-kind-knight', 4, 'princess-4', 'Other knights wanted to chase it away, but Rosa knelt down and spoke to it softly.', 'Ksatria lain ingin mengusirnya, tapi Rosa berlutut dan berbicara dengan lembut padanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-rosa-and-the-kind-knight_5', 'bok_princess-rosa-and-the-kind-knight', 5, 'princess-5', 'The dragon calmed down and let Rosa gently guide it out of the well with a rope of flowers.', 'Naga itu tenang dan membiarkan Rosa menuntunnya keluar dari sumur dengan tali bunga.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_princess-rosa-and-the-kind-knight_6', 'bok_princess-rosa-and-the-kind-knight', 6, 'princess-6', 'The whole kingdom cheered. Sir Callum said, "You are the bravest knight I know, Rosa."', 'Seluruh kerajaan bersorak. Sir Callum berkata, "Kamu ksatria paling berani yang kukenal, Rosa."');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_princess-rosa-and-the-kind-knight_1', 'bok_princess-rosa-and-the-kind-knight', 1, 'Who trained Princess Rosa?', 'Siapa yang melatih Putri Rosa?', '["The King","Sir Callum","The dragon","Her sister"]', '["Sang Raja","Sir Callum","Sang naga","Kakaknya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_princess-rosa-and-the-kind-knight_2', 'bok_princess-rosa-and-the-kind-knight', 2, 'What was stuck in the well?', 'Apa yang terjebak di sumur?', '["A cat","A baby dragon","A bucket","A ball"]', '["Kucing","Bayi naga","Ember","Bola"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_princess-rosa-and-the-kind-knight_3', 'bok_princess-rosa-and-the-kind-knight', 3, 'How did Rosa help the dragon?', 'Bagaimana Rosa menolong naga itu?', '["She scared it away","She spoke to it gently","She ignored it","She called guards to attack"]', '["Mengusirnya","Berbicara dengan lembut","Mengabaikannya","Memanggil penjaga untuk menyerang"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_bubbles-the-dolphins-new-friend', 'bubbles-the-dolphins-new-friend', 'Bubbles the Dolphin''s New Friend', 'Teman Baru Bubbles si Lumba-Lumba', 'A playful dolphin helps a lost baby turtle find its way back to its family in the reef.', 'Seekor lumba-lumba periang membantu bayi penyu yang tersesat kembali ke keluarganya di terumbu karang.', 'cat_ocean-life', 'aut_emily-clark', 'ocean', '🐬', 3, 7, 0, 'published', 6, 2365, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_bubbles-the-dolphins-new-friend_1', 'bok_bubbles-the-dolphins-new-friend', 1, 'ocean-1', 'Bubbles the dolphin loved doing flips near the coral reef every morning.', 'Bubbles si lumba-lumba suka melompat-lompat dekat terumbu karang setiap pagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_bubbles-the-dolphins-new-friend_2', 'bok_bubbles-the-dolphins-new-friend', 2, 'ocean-2', 'One day, she found a tiny turtle named Kiko, swimming alone and crying softly.', 'Suatu hari, ia menemukan penyu kecil bernama Kiko, berenang sendirian dan menangis pelan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_bubbles-the-dolphins-new-friend_3', 'bok_bubbles-the-dolphins-new-friend', 3, 'ocean-3', '"I got separated from my family during the current," Kiko said. Bubbles promised to help.', '"Aku terpisah dari keluargaku saat ada arus deras," kata Kiko. Bubbles berjanji akan membantu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_bubbles-the-dolphins-new-friend_4', 'bok_bubbles-the-dolphins-new-friend', 4, 'ocean-4', 'They swam past colorful fish and swaying seaweed, following the scent of Kiko''s home reef.', 'Mereka berenang melewati ikan-ikan warna-warni dan rumput laut yang bergoyang, mengikuti aroma terumbu rumah Kiko.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_bubbles-the-dolphins-new-friend_5', 'bok_bubbles-the-dolphins-new-friend', 5, 'ocean-5', 'At last, they spotted Kiko''s family waiting anxiously near a big sea sponge.', 'Akhirnya, mereka melihat keluarga Kiko menunggu cemas dekat spons laut besar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_bubbles-the-dolphins-new-friend_6', 'bok_bubbles-the-dolphins-new-friend', 6, 'ocean-6', 'Kiko''s family thanked Bubbles with a happy underwater dance, and Bubbles had a new best friend.', 'Keluarga Kiko berterima kasih pada Bubbles dengan tarian bahagia di bawah air, dan Bubbles punya sahabat baru.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_bubbles-the-dolphins-new-friend_1', 'bok_bubbles-the-dolphins-new-friend', 1, 'What is the turtle''s name?', 'Siapa nama penyu itu?', '["Kiko","Bubbles","Rex","Fin"]', '["Kiko","Bubbles","Rex","Fin"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_bubbles-the-dolphins-new-friend_2', 'bok_bubbles-the-dolphins-new-friend', 2, 'Why was Kiko alone?', 'Kenapa Kiko sendirian?', '["He was hiding","He got separated in the current","He ran away","He was sleeping"]', '["Bersembunyi","Terpisah karena arus","Kabur","Tidur"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_bubbles-the-dolphins-new-friend_3', 'bok_bubbles-the-dolphins-new-friend', 3, 'How did the story end?', 'Bagaimana akhir ceritanya?', '["Kiko stayed lost","Kiko found his family","Bubbles got lost too","They never met again"]', '["Kiko tetap tersesat","Kiko menemukan keluarganya","Bubbles juga tersesat","Mereka tidak pernah bertemu lagi"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_zuri-and-the-lost-cub', 'zuri-and-the-lost-cub', 'Zuri and the Lost Cub', 'Zuri dan Anak Singa yang Tersesat', 'A young elephant helps a lost lion cub find its pride, learning that kindness has no borders.', 'Seekor anak gajah membantu anak singa yang tersesat menemukan kelompoknya, belajar bahwa kebaikan tak mengenal batas.', 'cat_jungle-safari', 'aut_axto-creative-team', 'meadow', '🦁', 4, 8, 0, 'published', 6, 842, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_zuri-and-the-lost-cub_1', 'bok_zuri-and-the-lost-cub', 1, 'safari-1', 'Zuri the young elephant was drinking at the waterhole when she heard a tiny roar.', 'Zuri si anak gajah sedang minum di lubang air ketika ia mendengar auman kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_zuri-and-the-lost-cub_2', 'bok_zuri-and-the-lost-cub', 2, 'safari-2', 'A lion cub named Jabari was stuck between two rocks, too small to climb out alone.', 'Seekor anak singa bernama Jabari terjepit di antara dua batu, terlalu kecil untuk memanjat keluar sendiri.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_zuri-and-the-lost-cub_3', 'bok_zuri-and-the-lost-cub', 3, 'safari-3', 'Even though lions and elephants usually kept their distance, Zuri gently lifted Jabari with her trunk.', 'Meski singa dan gajah biasanya menjaga jarak, Zuri dengan lembut mengangkat Jabari dengan belalainya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_zuri-and-the-lost-cub_4', 'bok_zuri-and-the-lost-cub', 4, 'safari-4', '"Thank you," Jabari said, shaking with fear. "I can''t find my pride anywhere."', '"Terima kasih," kata Jabari, gemetar ketakutan. "Aku tidak bisa menemukan kelompokku."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_zuri-and-the-lost-cub_5', 'bok_zuri-and-the-lost-cub', 5, 'safari-5', 'Zuri used her long trunk to sniff the air and followed the scent all the way to the acacia trees.', 'Zuri menggunakan belalai panjangnya untuk mencium udara dan mengikuti aromanya sampai ke pohon akasia.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_zuri-and-the-lost-cub_6', 'bok_zuri-and-the-lost-cub', 6, 'safari-6', 'There, Jabari''s mother waited, relieved. From that day, elephants and lions in that savanna were the best of friends.', 'Di sana, ibu Jabari menunggu, lega. Sejak hari itu, gajah dan singa di sabana itu menjadi sahabat terbaik.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_zuri-and-the-lost-cub_1', 'bok_zuri-and-the-lost-cub', 1, 'Who got stuck between two rocks?', 'Siapa yang terjepit di antara dua batu?', '["Zuri","Jabari the lion cub","A zebra","A bird"]', '["Zuri","Jabari si anak singa","Zebra","Burung"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_zuri-and-the-lost-cub_2', 'bok_zuri-and-the-lost-cub', 2, 'How did Zuri find Jabari''s family?', 'Bagaimana Zuri menemukan keluarga Jabari?', '["She asked a bird","She followed the scent with her trunk","She guessed","She waited for them"]', '["Bertanya pada burung","Mengikuti aroma dengan belalainya","Menebak","Menunggu mereka"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_zuri-and-the-lost-cub_3', 'bok_zuri-and-the-lost-cub', 3, 'What lesson does the story teach?', 'Pelajaran apa yang diajarkan cerita ini?', '["Only help your own kind","Kindness has no borders","Stay away from strangers","Lions are scary"]', '["Hanya tolong sejenis","Kebaikan tak mengenal batas","Jauhi orang asing","Singa menakutkan"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_old-macfarms-missing-rooster', 'old-macfarms-missing-rooster', 'Old MacFarm and the Missing Rooster', 'Peternakan Tua dan Ayam Jantan yang Hilang', 'When the rooster who wakes the farm disappears, the animals must learn to work together.', 'Ketika ayam jantan yang membangunkan peternakan menghilang, para hewan harus belajar bekerja sama.', 'cat_farm', 'aut_siti-aminah', 'sunrise', '🐓', 3, 6, 0, 'published', 6, 3130, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_old-macfarms-missing-rooster_1', 'bok_old-macfarms-missing-rooster', 1, 'farm-1', 'Every morning, Rudi the rooster crowed "Cock-a-doodle-doo!" to wake up the whole farm.', 'Setiap pagi, Rudi si ayam jantan berkokok "Kukuruyuk!" untuk membangunkan seluruh peternakan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_old-macfarms-missing-rooster_2', 'bok_old-macfarms-missing-rooster', 2, 'farm-2', 'One morning, there was silence. No crowing at all. Rudi was nowhere to be found!', 'Suatu pagi, semua sunyi. Tidak ada kokokan sama sekali. Rudi tidak ditemukan di mana pun!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_old-macfarms-missing-rooster_3', 'bok_old-macfarms-missing-rooster', 3, 'farm-3', 'The cow, the sheep, and the pig searched everywhere, calling his name across the barn.', 'Sapi, domba, dan babi mencari ke mana-mana, memanggil namanya di seluruh kandang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_old-macfarms-missing-rooster_4', 'bok_old-macfarms-missing-rooster', 4, 'farm-4', 'The little duck found him stuck in the mud near the pond, his feathers all muddy.', 'Bebek kecil menemukannya terjebak di lumpur dekat kolam, bulunya penuh lumpur.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_old-macfarms-missing-rooster_5', 'bok_old-macfarms-missing-rooster', 5, 'farm-5', 'All the animals worked together, pulling gently, until Rudi popped free with a happy squelch.', 'Semua hewan bekerja sama, menarik dengan lembut, sampai Rudi terlepas dengan suara lucu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_old-macfarms-missing-rooster_6', 'bok_old-macfarms-missing-rooster', 6, 'farm-6', 'The next morning, Rudi crowed louder than ever, thankful for his wonderful farm friends.', 'Keesokan paginya, Rudi berkokok lebih keras dari biasanya, berterima kasih pada teman-teman peternakannya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_old-macfarms-missing-rooster_1', 'bok_old-macfarms-missing-rooster', 1, 'What does Rudi do every morning?', 'Apa yang dilakukan Rudi setiap pagi?', '["He sleeps in","He crows to wake everyone","He eats breakfast","He swims"]', '["Tidur lagi","Berkokok membangunkan semua","Sarapan","Berenang"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_old-macfarms-missing-rooster_2', 'bok_old-macfarms-missing-rooster', 2, 'Where was Rudi stuck?', 'Di mana Rudi terjebak?', '["In a tree","In the mud near the pond","In the barn","On the roof"]', '["Di pohon","Di lumpur dekat kolam","Di kandang","Di atap"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_old-macfarms-missing-rooster_3', 'bok_old-macfarms-missing-rooster', 3, 'How was Rudi rescued?', 'Bagaimana Rudi diselamatkan?', '["He escaped alone","All the animals worked together","The farmer used a machine","He was left there"]', '["Kabur sendiri","Semua hewan bekerja sama","Petani pakai mesin","Dibiarkan saja"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_buddys-first-day-home', 'buddys-first-day-home', 'Buddy the Puppy''s First Day Home', 'Hari Pertama Buddy si Anak Anjing di Rumah Baru', 'A nervous new puppy learns that his new family will love and take care of him always.', 'Seekor anak anjing yang gugup belajar bahwa keluarga barunya akan selalu mencintai dan merawatnya.', 'cat_pets', 'aut_sarah-johnson', 'sunrise', '🐶', 2, 6, 0, 'published', 6, 1639, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_buddys-first-day-home_1', 'bok_buddys-first-day-home', 1, 'pets-1', 'Buddy the puppy arrived at his new home in a little basket, feeling small and nervous.', 'Buddy si anak anjing tiba di rumah barunya dalam keranjang kecil, merasa kecil dan gugup.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_buddys-first-day-home_2', 'bok_buddys-first-day-home', 2, 'pets-2', 'A little boy named Dimas knelt down slowly and held out his hand. "Hi Buddy, I''m your friend now."', 'Seorang anak laki-laki bernama Dimas berlutut pelan dan mengulurkan tangannya. "Hai Buddy, aku temanmu sekarang."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_buddys-first-day-home_3', 'bok_buddys-first-day-home', 3, 'pets-3', 'Buddy sniffed his hand carefully, then wagged his tail just a little bit.', 'Buddy mengendus tangan itu hati-hati, lalu mengibaskan ekornya sedikit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_buddys-first-day-home_4', 'bok_buddys-first-day-home', 4, 'pets-4', 'Dimas showed him his cozy new bed, a bowl of fresh water, and a soft squeaky toy.', 'Dimas menunjukkan tempat tidur baru yang nyaman, mangkuk berisi air segar, dan mainan lembut yang berbunyi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_buddys-first-day-home_5', 'bok_buddys-first-day-home', 5, 'pets-5', 'That night, Buddy curled up next to Dimas''s bed, feeling safe for the very first time.', 'Malam itu, Buddy meringkuk di samping tempat tidur Dimas, merasa aman untuk pertama kalinya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_buddys-first-day-home_6', 'bok_buddys-first-day-home', 6, 'pets-6', 'By morning, Buddy was already best friends with his whole new family.', 'Menjelang pagi, Buddy sudah menjadi sahabat bagi seluruh keluarga barunya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_buddys-first-day-home_1', 'bok_buddys-first-day-home', 1, 'How did Buddy feel when he first arrived?', 'Bagaimana perasaan Buddy saat pertama tiba?', '["Excited and loud","Small and nervous","Angry","Sleepy all day"]', '["Bersemangat dan berisik","Kecil dan gugup","Marah","Ngantuk seharian"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_buddys-first-day-home_2', 'bok_buddys-first-day-home', 2, 'Who welcomed Buddy?', 'Siapa yang menyambut Buddy?', '["A cat","A boy named Dimas","A stranger","Nobody"]', '["Kucing","Anak bernama Dimas","Orang asing","Tidak ada"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_buddys-first-day-home_3', 'bok_buddys-first-day-home', 3, 'Where did Buddy sleep that night?', 'Di mana Buddy tidur malam itu?', '["Outside","Next to Dimas''s bed","In the kitchen","In a basket outside"]', '["Di luar","Di samping tempat tidur Dimas","Di dapur","Dalam keranjang di luar"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_beep-and-the-broken-toy', 'beep-and-the-broken-toy', 'Beep and the Broken Toy', 'Beep dan Mainan yang Rusak', 'A helpful little robot learns that not everything broken needs fixing — sometimes it just needs care.', 'Seekor robot kecil yang suka menolong belajar bahwa tidak semua yang rusak perlu diperbaiki — kadang cukup dirawat.', 'cat_robots-tech', 'aut_david-lee', 'cosmic', '🤖', 4, 9, 0, 'published', 6, 2112, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_beep-and-the-broken-toy_1', 'bok_beep-and-the-broken-toy', 1, 'robots-1', 'Beep the robot loved fixing things. Squeaky doors, wobbly tables, anything at all.', 'Beep si robot suka memperbaiki barang. Pintu berdecit, meja goyang, apa saja.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_beep-and-the-broken-toy_2', 'bok_beep-and-the-broken-toy', 2, 'robots-2', 'One day, he found a little girl named Wina crying over her torn teddy bear, Coco.', 'Suatu hari, ia menemukan gadis kecil bernama Wina menangis karena boneka beruangnya, Coco, robek.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_beep-and-the-broken-toy_3', 'bok_beep-and-the-broken-toy', 3, 'robots-3', '"I can fix him with my tools!" Beep said, reaching for his glue and needle.', '"Aku bisa memperbaikinya dengan peralatanku!" kata Beep, mengambil lem dan jarumnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_beep-and-the-broken-toy_4', 'bok_beep-and-the-broken-toy', 4, 'robots-4', '"Wait," Wina said softly. "Coco doesn''t need to be perfect. He just needs a hug and some love."', '"Tunggu," kata Wina lembut. "Coco tidak perlu sempurna. Ia hanya butuh pelukan dan kasih sayang."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_beep-and-the-broken-toy_5', 'bok_beep-and-the-broken-toy', 5, 'robots-5', 'Beep paused his tools and thought about it. He gently helped Wina sew one small stitch instead.', 'Beep menghentikan peralatannya dan berpikir. Ia membantu Wina menjahit satu jahitan kecil saja.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_beep-and-the-broken-toy_6', 'bok_beep-and-the-broken-toy', 6, 'robots-6', 'Coco was still a little worn, but Wina hugged him tight and smiled. Beep learned love fixes more than tools.', 'Coco masih agak usang, tapi Wina memeluknya erat dan tersenyum. Beep belajar bahwa cinta memperbaiki lebih dari sekadar alat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_beep-and-the-broken-toy_1', 'bok_beep-and-the-broken-toy', 1, 'What did Beep love to do?', 'Apa yang disukai Beep?', '["Sleeping","Fixing things","Singing","Cooking"]', '["Tidur","Memperbaiki barang","Bernyanyi","Memasak"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_beep-and-the-broken-toy_2', 'bok_beep-and-the-broken-toy', 2, 'What was broken?', 'Apa yang rusak?', '["A chair","Wina''s teddy bear","A robot arm","A window"]', '["Kursi","Boneka beruang Wina","Lengan robot","Jendela"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_beep-and-the-broken-toy_3', 'bok_beep-and-the-broken-toy', 3, 'What did Wina say Coco really needed?', 'Apa yang menurut Wina benar-benar dibutuhkan Coco?', '["New stuffing","A hug and love","A new owner","To be thrown away"]', '["Isi baru","Pelukan dan kasih sayang","Pemilik baru","Dibuang"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-tree-everyone-forgot', 'the-tree-everyone-forgot', 'The Tree That Everyone Forgot', 'Pohon yang Terlupakan', 'Children rediscover an old forgotten tree in their neighborhood and learn to care for nature together.', 'Anak-anak menemukan kembali sebuah pohon tua yang terlupakan di lingkungan mereka dan belajar merawat alam bersama.', 'cat_nature-environment', 'aut_axto-creative-team', 'forest', '🌳', 4, 9, 0, 'published', 6, 3324, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tree-everyone-forgot_1', 'bok_the-tree-everyone-forgot', 1, 'nature-1', 'At the end of Melati Street stood an old tree, its leaves dusty and branches drooping.', 'Di ujung Jalan Melati berdiri sebuah pohon tua, daunnya berdebu dan rantingnya menunduk.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tree-everyone-forgot_2', 'bok_the-tree-everyone-forgot', 2, 'nature-2', 'Every day, children walked past it without even noticing it was there.', 'Setiap hari, anak-anak melewatinya tanpa menyadari keberadaannya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tree-everyone-forgot_3', 'bok_the-tree-everyone-forgot', 3, 'nature-3', 'One afternoon, little Arka stopped and looked up. "Why is this tree so sad?" he wondered.', 'Suatu sore, Arka kecil berhenti dan menengadah. "Kenapa pohon ini terlihat sedih?" pikirnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tree-everyone-forgot_4', 'bok_the-tree-everyone-forgot', 4, 'nature-4', 'He gathered his friends, and together they watered its roots and cleared the trash around it.', 'Ia mengumpulkan teman-temannya, dan bersama-sama mereka menyiram akarnya dan membersihkan sampah di sekitarnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tree-everyone-forgot_5', 'bok_the-tree-everyone-forgot', 5, 'nature-5', 'Week by week, the tree grew greener. Birds began building nests in its branches again.', 'Minggu demi minggu, pohon itu semakin hijau. Burung-burung mulai membuat sarang di rantingnya lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tree-everyone-forgot_6', 'bok_the-tree-everyone-forgot', 6, 'nature-6', 'Now the children call it "Our Tree," and every child on Melati Street helps take care of it.', 'Sekarang anak-anak menyebutnya "Pohon Kita," dan setiap anak di Jalan Melati ikut merawatnya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-tree-everyone-forgot_1', 'bok_the-tree-everyone-forgot', 1, 'What was wrong with the tree at first?', 'Apa yang salah dengan pohon itu di awal?', '["It was cut down","It looked dusty and drooping","It was on fire","It moved away"]', '["Ditebang","Terlihat berdebu dan lesu","Terbakar","Berpindah tempat"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-tree-everyone-forgot_2', 'bok_the-tree-everyone-forgot', 2, 'What did Arka and his friends do?', 'Apa yang dilakukan Arka dan teman-temannya?', '["Ignored it","Watered it and cleared trash","Cut it down","Painted it"]', '["Mengabaikannya","Menyiram dan membersihkan sampah","Menebangnya","Mengecatnya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-tree-everyone-forgot_3', 'bok_the-tree-everyone-forgot', 3, 'What happened after they cared for it?', 'Apa yang terjadi setelah mereka merawatnya?', '["It died anyway","It grew greener and birds returned","Nothing changed","It was cut down"]', '["Tetap mati","Semakin hijau dan burung kembali","Tidak ada yang berubah","Ditebang"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-rainbow-after-the-rain', 'the-rainbow-after-the-rain', 'The Rainbow After the Rain', 'Pelangi Setelah Hujan', 'A little boy learns why rainbows appear and discovers that even rainy days can lead to something beautiful.', 'Seorang anak laki-laki belajar kenapa pelangi muncul dan menemukan bahwa hari hujan pun bisa berujung indah.', 'cat_weather-seasons', 'aut_axto-creative-team', 'dusk', '🌦️', 2, 6, 0, 'published', 6, 2505, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-rainbow-after-the-rain_1', 'bok_the-rainbow-after-the-rain', 1, 'weather-1', 'Dark clouds rolled in, and rain began to fall. Bayu sighed, "No playing outside today."', 'Awan gelap datang, dan hujan mulai turun. Bayu menghela napas, "Tidak bisa main di luar hari ini."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-rainbow-after-the-rain_2', 'bok_the-rainbow-after-the-rain', 2, 'weather-2', 'His grandfather smiled. "Every rain has a surprise waiting at the end, if you''re patient."', 'Kakeknya tersenyum. "Setiap hujan menyimpan kejutan di akhir, kalau kamu sabar menunggu."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-rainbow-after-the-rain_3', 'bok_the-rainbow-after-the-rain', 3, 'weather-3', 'They watched from the window as the rain slowed down, drop by drop, until it finally stopped.', 'Mereka menonton dari jendela saat hujan melambat, tetes demi tetes, sampai akhirnya berhenti.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-rainbow-after-the-rain_4', 'bok_the-rainbow-after-the-rain', 4, 'weather-4', 'The sun peeked out from behind a cloud, and light passed through the tiny raindrops in the air.', 'Matahari mengintip dari balik awan, dan cahaya melewati tetesan air kecil di udara.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-rainbow-after-the-rain_5', 'bok_the-rainbow-after-the-rain', 5, 'weather-5', 'Suddenly, a rainbow stretched across the sky — red, orange, yellow, green, blue, and purple.', 'Tiba-tiba, sebuah pelangi terbentang di langit — merah, jingga, kuning, hijau, biru, dan ungu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-rainbow-after-the-rain_6', 'bok_the-rainbow-after-the-rain', 6, 'weather-6', '"The rain made room for the rainbow," Grandfather said. Bayu smiled, no longer sad about the rain.', '"Hujan memberi ruang untuk pelangi," kata Kakek. Bayu tersenyum, tak lagi sedih karena hujan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-rainbow-after-the-rain_1', 'bok_the-rainbow-after-the-rain', 1, 'What was Bayu sad about?', 'Apa yang membuat Bayu sedih?', '["He lost a toy","He couldn''t play outside because of rain","He was hungry","School was cancelled"]', '["Kehilangan mainan","Tidak bisa main di luar karena hujan","Lapar","Sekolah diliburkan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-rainbow-after-the-rain_2', 'bok_the-rainbow-after-the-rain', 2, 'What appeared after the rain?', 'Apa yang muncul setelah hujan?', '["Snow","A rainbow","A storm","Fog"]', '["Salju","Pelangi","Badai","Kabut"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-rainbow-after-the-rain_3', 'bok_the-rainbow-after-the-rain', 3, 'What lesson did Bayu learn?', 'Pelajaran apa yang dipetik Bayu?', '["Rain is always bad","Rain can lead to something beautiful","Rainbows are scary","Never go outside"]', '["Hujan selalu buruk","Hujan bisa berujung indah","Pelangi menakutkan","Jangan pernah keluar rumah"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_a-day-with-officer-dan', 'a-day-with-officer-dan', 'A Day With Officer Dan', 'Sehari Bersama Petugas Dan', 'A curious boy spends a day shadowing a police officer and learns how community helpers keep everyone safe.', 'Seorang anak yang penasaran menghabiskan sehari mengikuti seorang polisi dan belajar bagaimana profesi membantu menjaga keselamatan semua orang.', 'cat_community-helpers', 'aut_axto-creative-team', 'night', '👮', 3, 7, 0, 'published', 6, 4349, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-officer-dan_1', 'bok_a-day-with-officer-dan', 1, 'community-1', 'On School Career Day, Farrel got to spend the morning with Officer Dan, the friendliest police officer in town.', 'Di Hari Profesi Sekolah, Farrel menghabiskan pagi bersama Petugas Dan, polisi paling ramah di kota.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-officer-dan_2', 'bok_a-day-with-officer-dan', 2, 'community-2', 'First, they helped a group of children cross the busy street safely, holding up a bright stop sign.', 'Pertama, mereka membantu sekelompok anak menyeberang jalan ramai dengan aman, mengangkat rambu berhenti yang cerah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-officer-dan_3', 'bok_a-day-with-officer-dan', 3, 'community-3', 'Next, they helped an elderly man who couldn''t find his way home, guiding him gently back to his street.', 'Selanjutnya, mereka membantu seorang kakek yang tersesat, menuntunnya kembali ke jalannya dengan lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-officer-dan_4', 'bok_a-day-with-officer-dan', 4, 'community-4', '"Being a helper means noticing when someone needs you," Officer Dan explained with a warm smile.', '"Menjadi penolong berarti peka saat seseorang membutuhkanmu," jelas Petugas Dan dengan senyum hangat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-officer-dan_5', 'bok_a-day-with-officer-dan', 5, 'community-5', 'Farrel even got to wave to cars from a bicycle, helping keep the school zone safe at pickup time.', 'Farrel bahkan boleh melambai ke mobil dari sepeda, membantu menjaga keamanan zona sekolah saat jam jemput.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_a-day-with-officer-dan_6', 'bok_a-day-with-officer-dan', 6, 'community-6', 'That night, Farrel told his family, "I want to be a helper like Officer Dan when I grow up."', 'Malam itu, Farrel bercerita ke keluarganya, "Aku ingin jadi penolong seperti Petugas Dan kalau sudah besar."');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-day-with-officer-dan_1', 'bok_a-day-with-officer-dan', 1, 'Who did Farrel spend the day with?', 'Farrel menghabiskan hari bersama siapa?', '["A doctor","Officer Dan","A firefighter","A teacher"]', '["Dokter","Petugas Dan","Pemadam kebakaran","Guru"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-day-with-officer-dan_2', 'bok_a-day-with-officer-dan', 2, 'What did they help the elderly man with?', 'Apa yang mereka bantu untuk kakek itu?', '["Carrying groceries","Finding his way home","Fixing his bike","Crossing a river"]', '["Membawa belanjaan","Menemukan jalan pulang","Memperbaiki sepeda","Menyeberangi sungai"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_a-day-with-officer-dan_3', 'bok_a-day-with-officer-dan', 3, 'What did Farrel decide he wanted to be?', 'Farrel ingin menjadi apa?', '["A chef","A helper like Officer Dan","A pilot","A painter"]', '["Koki","Penolong seperti Petugas Dan","Pilot","Pelukis"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_team-sunflowers-big-game', 'team-sunflowers-big-game', 'Team Sunflower''s Big Game', 'Pertandingan Besar Tim Bunga Matahari', 'A young player learns that supporting your teammates matters more than winning.', 'Seorang pemain kecil belajar bahwa mendukung teman satu tim lebih penting daripada menang.', 'cat_sports', 'aut_axto-creative-team', 'meadow', '⚽', 5, 10, 0, 'published', 6, 5144, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_team-sunflowers-big-game_1', 'bok_team-sunflowers-big-game', 1, 'sports-1', 'Team Sunflower had practiced all season for the final match against Team Comet.', 'Tim Bunga Matahari sudah berlatih sepanjang musim untuk pertandingan final melawan Tim Komet.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_team-sunflowers-big-game_2', 'bok_team-sunflowers-big-game', 2, 'sports-2', 'Rayhan, the fastest runner on the team, was so nervous his hands were shaking before the whistle blew.', 'Rayhan, pelari tercepat di tim, sangat gugup hingga tangannya gemetar sebelum peluit ditiup.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_team-sunflowers-big-game_3', 'bok_team-sunflowers-big-game', 3, 'sports-3', 'In the second half, Rayhan missed an easy goal, and his shoulders slumped in disappointment.', 'Di babak kedua, Rayhan gagal mencetak gol yang mudah, dan bahunya turun kecewa.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_team-sunflowers-big-game_4', 'bok_team-sunflowers-big-game', 4, 'sports-4', 'His teammate Bimo ran over and patted his back. "We win and lose together. Keep playing!"', 'Rekan setimnya, Bimo, berlari dan menepuk punggungnya. "Kita menang dan kalah bersama. Ayo terus main!"');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_team-sunflowers-big-game_5', 'bok_team-sunflowers-big-game', 5, 'sports-5', 'Cheered on by his team, Rayhan ran faster than ever and passed the ball perfectly to score in the last minute.', 'Didukung timnya, Rayhan berlari lebih cepat dari sebelumnya dan mengoper bola dengan sempurna untuk mencetak gol di menit terakhir.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_team-sunflowers-big-game_6', 'bok_team-sunflowers-big-game', 6, 'sports-6', 'Team Sunflower won, but Rayhan said the best part was his team believing in him even after a mistake.', 'Tim Bunga Matahari menang, tapi bagi Rayhan yang terbaik adalah timnya tetap percaya padanya walau ia sempat gagal.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_team-sunflowers-big-game_1', 'bok_team-sunflowers-big-game', 1, 'What team did Rayhan play for?', 'Rayhan bermain untuk tim apa?', '["Team Comet","Team Sunflower","Team Star","Team Ocean"]', '["Tim Komet","Tim Bunga Matahari","Tim Bintang","Tim Laut"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_team-sunflowers-big-game_2', 'bok_team-sunflowers-big-game', 2, 'What happened when Rayhan missed a goal?', 'Apa yang terjadi saat Rayhan gagal mencetak gol?', '["His team got angry","His teammate encouraged him","He was sent home","The game stopped"]', '["Tim marah","Rekan setimnya menyemangatinya","Ia dipulangkan","Pertandingan berhenti"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_team-sunflowers-big-game_3', 'bok_team-sunflowers-big-game', 3, 'What did Rayhan say was the best part?', 'Apa menurut Rayhan bagian terbaiknya?', '["Winning the trophy","His team believing in him","Being the fastest","Getting a prize"]', '["Memenangkan trofi","Timnya tetap percaya padanya","Menjadi tercepat","Mendapat hadiah"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-song-that-made-the-village-dance', 'the-song-that-made-the-village-dance', 'The Song That Made the Village Dance', 'Lagu yang Membuat Desa Menari', 'A shy girl discovers her singing voice can bring an entire village together in joy.', 'Seorang gadis pemalu menemukan suara nyanyiannya bisa menyatukan seluruh desa dalam kebahagiaan.', 'cat_music-rhymes', 'aut_siti-aminah', 'candy', '🎵', 3, 7, 0, 'published', 6, 4196, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-song-that-made-the-village-dance_1', 'bok_the-song-that-made-the-village-dance', 1, 'music-1', 'Sari loved to hum little tunes, but she was too shy to sing in front of anyone.', 'Sari suka menggumamkan lagu-lagu kecil, tapi ia terlalu malu untuk bernyanyi di depan orang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-song-that-made-the-village-dance_2', 'bok_the-song-that-made-the-village-dance', 2, 'music-2', 'One evening, the village harvest festival felt quiet and a little sad — the usual singer was sick.', 'Suatu malam, festival panen desa terasa sepi dan sedikit sedih — penyanyi biasa sedang sakit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-song-that-made-the-village-dance_3', 'bok_the-song-that-made-the-village-dance', 3, 'music-3', 'Sari''s grandmother whispered, "Music is a gift you share, not something to hide."', 'Nenek Sari berbisik, "Musik adalah hadiah yang kau bagikan, bukan yang kau sembunyikan."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-song-that-made-the-village-dance_4', 'bok_the-song-that-made-the-village-dance', 4, 'music-4', 'With shaking knees, Sari stepped up and began to sing a gentle rhyme about the moon and rice fields.', 'Dengan lutut gemetar, Sari maju dan mulai menyanyikan pantun lembut tentang bulan dan sawah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-song-that-made-the-village-dance_5', 'bok_the-song-that-made-the-village-dance', 5, 'music-5', 'One by one, the villagers began clapping along, then swaying, then dancing under the stars.', 'Satu per satu, warga desa mulai bertepuk tangan, lalu bergoyang, lalu menari di bawah bintang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-song-that-made-the-village-dance_6', 'bok_the-song-that-made-the-village-dance', 6, 'music-6', 'From that night on, Sari sang at every festival, no longer afraid to share her gift.', 'Sejak malam itu, Sari bernyanyi di setiap festival, tak lagi takut membagikan hadiahnya.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-song-that-made-the-village-dance_1', 'bok_the-song-that-made-the-village-dance', 1, 'Why was the festival feeling sad?', 'Kenapa festival terasa sedih?', '["It was raining","The usual singer was sick","There was no food","It was cancelled"]', '["Sedang hujan","Penyanyi biasa sedang sakit","Tidak ada makanan","Dibatalkan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-song-that-made-the-village-dance_2', 'bok_the-song-that-made-the-village-dance', 2, 'What did Sari sing about?', 'Sari bernyanyi tentang apa?', '["Cars and roads","The moon and rice fields","Robots","The ocean"]', '["Mobil dan jalan","Bulan dan sawah","Robot","Laut"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-song-that-made-the-village-dance_3', 'bok_the-song-that-made-the-village-dance', 3, 'What did the villagers do while Sari sang?', 'Apa yang dilakukan warga desa saat Sari bernyanyi?', '["They left","They clapped and danced","They fell asleep","They argued"]', '["Pergi","Bertepuk tangan dan menari","Tertidur","Bertengkar"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_grandmas-lantern-festival', 'grandmas-lantern-festival', 'Grandma''s Lantern Festival', 'Festival Lampion Nenek', 'A boy learns the meaning behind his family''s lantern festival tradition and why celebrations bring people together.', 'Seorang anak belajar makna di balik tradisi festival lampion keluarganya dan kenapa perayaan menyatukan orang.', 'cat_holidays-culture', 'aut_siti-aminah', 'night', '🏮', 4, 8, 0, 'published', 6, 4747, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_grandmas-lantern-festival_1', 'bok_grandmas-lantern-festival', 1, 'holidays-1', 'Every year, Bram''s family made paper lanterns together for the village Lantern Festival.', 'Setiap tahun, keluarga Bram membuat lampion kertas bersama untuk Festival Lampion desa.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_grandmas-lantern-festival_2', 'bok_grandmas-lantern-festival', 2, 'holidays-2', '"Why do we do this every year, Grandma?" Bram asked, folding red paper carefully.', '"Kenapa kita melakukan ini setiap tahun, Nek?" tanya Bram, sambil melipat kertas merah hati-hati.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_grandmas-lantern-festival_3', 'bok_grandmas-lantern-festival', 3, 'holidays-3', '"The lanterns carry our wishes for the new year, and light guides family back home," Grandma explained.', '"Lampion membawa harapan kita untuk tahun baru, dan cahayanya menuntun keluarga kembali pulang," jelas Nenek.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_grandmas-lantern-festival_4', 'bok_grandmas-lantern-festival', 4, 'holidays-4', 'That evening, the whole village gathered, lighting their lanterns one by one until the sky glowed gold.', 'Malam itu, seluruh desa berkumpul, menyalakan lampion satu per satu hingga langit bersinar keemasan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_grandmas-lantern-festival_5', 'bok_grandmas-lantern-festival', 5, 'holidays-5', 'Bram wrote his wish on his lantern: "I wish everyone I love stays happy and healthy."', 'Bram menulis harapannya di lampionnya: "Aku berharap semua yang kucintai tetap bahagia dan sehat."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_grandmas-lantern-festival_6', 'bok_grandmas-lantern-festival', 6, 'holidays-6', 'Watching hundreds of lanterns float into the sky, Bram finally understood why the tradition mattered.', 'Melihat ratusan lampion melayang ke langit, Bram akhirnya paham kenapa tradisi ini begitu berarti.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_grandmas-lantern-festival_1', 'bok_grandmas-lantern-festival', 1, 'What did Bram''s family make together?', 'Apa yang dibuat keluarga Bram bersama?', '["Kites","Paper lanterns","Cookies","Masks"]', '["Layang-layang","Lampion kertas","Kue","Topeng"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_grandmas-lantern-festival_2', 'bok_grandmas-lantern-festival', 2, 'What do the lanterns carry, according to Grandma?', 'Menurut Nenek, apa yang dibawa lampion?', '["Food","Wishes for the new year","Money","Nothing special"]', '["Makanan","Harapan untuk tahun baru","Uang","Tidak ada yang khusus"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_grandmas-lantern-festival_3', 'bok_grandmas-lantern-festival', 3, 'What did Bram write on his lantern?', 'Apa yang ditulis Bram di lampionnya?', '["A joke","A wish for loved ones to be happy and healthy","His name only","A drawing"]', '["Lelucon","Harapan agar orang tercinta bahagia dan sehat","Namanya saja","Gambar"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_why-teeth-need-brushing', 'why-teeth-need-brushing', 'Why Teeth Need Brushing', 'Kenapa Gigi Perlu Disikat', 'A friendly visit to the dentist teaches a reluctant boy why brushing his teeth every day matters.', 'Kunjungan yang menyenangkan ke dokter gigi mengajarkan seorang anak yang malas kenapa menyikat gigi setiap hari itu penting.', 'cat_health-body', 'aut_axto-creative-team', 'ocean', '🦷', 3, 7, 0, 'published', 6, 1663, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_why-teeth-need-brushing_1', 'bok_why-teeth-need-brushing', 1, 'health-1', 'Ega never liked brushing his teeth. "It takes too long," he always complained.', 'Ega tidak pernah suka menyikat gigi. "Terlalu lama," ia selalu mengeluh.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_why-teeth-need-brushing_2', 'bok_why-teeth-need-brushing', 2, 'health-2', 'One day, his tooth started to hurt, so Mom took him to see Dr. Nisa, the dentist.', 'Suatu hari, giginya mulai sakit, jadi Ibu membawanya ke Dr. Nisa, dokter gigi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_why-teeth-need-brushing_3', 'bok_why-teeth-need-brushing', 3, 'health-3', 'Dr. Nisa showed him a picture: tiny sugar bugs love hiding in unbrushed teeth and cause holes.', 'Dr. Nisa menunjukkan gambar: kuman gula kecil suka bersembunyi di gigi yang tak disikat dan menyebabkan lubang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_why-teeth-need-brushing_4', 'bok_why-teeth-need-brushing', 4, 'health-4', '"Brushing twice a day chases the sugar bugs away before they can make a home in your teeth," she said.', '"Menyikat gigi dua kali sehari mengusir kuman gula sebelum mereka bisa tinggal di gigimu," katanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_why-teeth-need-brushing_5', 'bok_why-teeth-need-brushing', 5, 'health-5', 'Dr. Nisa gently fixed Ega''s tooth, and gave him a fun new toothbrush shaped like a dinosaur.', 'Dr. Nisa memperbaiki gigi Ega dengan lembut, dan memberinya sikat gigi baru berbentuk dinosaurus.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_why-teeth-need-brushing_6', 'bok_why-teeth-need-brushing', 6, 'health-6', 'Now Ega brushes every morning and night, proud that his teeth are strong and sugar-bug-free.', 'Sekarang Ega menyikat gigi setiap pagi dan malam, bangga giginya kuat dan bebas kuman gula.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_why-teeth-need-brushing_1', 'bok_why-teeth-need-brushing', 1, 'Why did Ega go to the dentist?', 'Kenapa Ega pergi ke dokter gigi?', '["For a checkup only","His tooth started to hurt","To get a toy","For fun"]', '["Cek rutin saja","Giginya mulai sakit","Untuk dapat mainan","Untuk senang-senang"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_why-teeth-need-brushing_2', 'bok_why-teeth-need-brushing', 2, 'What did Dr. Nisa say causes holes in teeth?', 'Menurut Dr. Nisa, apa yang menyebabkan lubang di gigi?', '["Cold water","Sugar bugs on unbrushed teeth","Sunlight","Too much sleep"]', '["Air dingin","Kuman gula di gigi tak disikat","Sinar matahari","Terlalu banyak tidur"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_why-teeth-need-brushing_3', 'bok_why-teeth-need-brushing', 3, 'How often should you brush your teeth?', 'Seberapa sering sebaiknya menyikat gigi?', '["Once a week","Twice a day","Only when it hurts","Never"]', '["Sekali seminggu","Dua kali sehari","Hanya saat sakit","Tidak pernah"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-magic-words', 'the-magic-words', 'The Magic Words: Please and Thank You', 'Kata Ajaib: Tolong dan Terima Kasih', 'A young rabbit discovers that two small words can turn a grumpy day into a wonderful one.', 'Seekor kelinci kecil menemukan bahwa dua kata sederhana bisa mengubah hari yang buruk menjadi menyenangkan.', 'cat_manners', 'aut_axto-creative-team', 'sunrise', '🙏', 2, 6, 0, 'published', 6, 2922, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-words_1', 'bok_the-magic-words', 1, 'manners-1', 'Kiki the rabbit wanted a carrot from the market stall. "Give me a carrot!" she demanded.', 'Kiki si kelinci ingin sebuah wortel dari kios pasar. "Kasih aku wortel!" katanya menuntut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-words_2', 'bok_the-magic-words', 2, 'manners-2', 'The shopkeeper, Mr. Beaver, looked a little sad and slowly turned away without a word.', 'Pemilik toko, Pak Berang-berang, terlihat sedikit sedih dan perlahan berbalik tanpa berkata apa-apa.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-words_3', 'bok_the-magic-words', 3, 'manners-3', 'Kiki''s mother whispered gently, "Try asking with the magic words, sweetheart."', 'Ibu Kiki berbisik lembut, "Coba minta dengan kata ajaib, Sayang."');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-words_4', 'bok_the-magic-words', 4, 'manners-4', '"Could I please have a carrot?" Kiki asked, softer this time. Mr. Beaver''s face lit up with a smile.', '"Bolehkah aku minta wortel, tolong?" tanya Kiki, kali ini lebih lembut. Wajah Pak Berang-berang langsung ceria.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-words_5', 'bok_the-magic-words', 5, 'manners-5', 'He handed her the biggest, crunchiest carrot in the stall. "Thank you so much!" Kiki said happily.', 'Ia memberikan wortel terbesar dan paling renyah di kiosnya. "Terima kasih banyak!" kata Kiki riang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-words_6', 'bok_the-magic-words', 6, 'manners-6', 'From that day, Kiki always remembered: please and thank you make everyone''s day a little brighter.', 'Sejak hari itu, Kiki selalu ingat: tolong dan terima kasih membuat hari semua orang sedikit lebih cerah.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-words_1', 'bok_the-magic-words', 1, 'How did Kiki first ask for a carrot?', 'Bagaimana Kiki pertama kali meminta wortel?', '["Politely","By demanding it rudely","By singing","By writing a note"]', '["Dengan sopan","Dengan menuntut kasar","Dengan bernyanyi","Dengan menulis catatan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-words_2', 'bok_the-magic-words', 2, 'What are the "magic words"?', 'Apa "kata ajaib" itu?', '["Hello and goodbye","Please and thank you","Yes and no","Sorry and okay"]', '["Halo dan sampai jumpa","Tolong dan terima kasih","Ya dan tidak","Maaf dan oke"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-words_3', 'bok_the-magic-words', 3, 'How did Mr. Beaver react to the magic words?', 'Bagaimana reaksi Pak Berang-berang mendengar kata ajaib?', '["He got angrier","He smiled and gave the best carrot","He ignored her","He closed his shop"]', '["Makin marah","Tersenyum dan memberi wortel terbaik","Mengabaikannya","Menutup tokonya"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-girl-who-planted-a-forest', 'the-girl-who-planted-a-forest', 'The Girl Who Planted a Forest', 'Gadis yang Menanam Hutan', 'Inspired by real young environmentalists around the world, this story follows a girl whose one small act of planting trees grows into a movement.', 'Terinspirasi dari anak-anak pencinta lingkungan di dunia nyata, kisah ini mengikuti seorang gadis yang aksi kecilnya menanam pohon tumbuh menjadi gerakan besar.', 'cat_true-stories', 'aut_axto-creative-team', 'forest', '🌟', 6, 11, 0, 'published', 6, 4783, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-girl-who-planted-a-forest_1', 'bok_the-girl-who-planted-a-forest', 1, 'true-1', 'When Maya was seven, she noticed the hill behind her school had no trees left — only dry, cracked earth.', 'Ketika Maya berusia tujuh tahun, ia menyadari bukit di belakang sekolahnya tak ada pohon lagi — hanya tanah kering yang retak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-girl-who-planted-a-forest_2', 'bok_the-girl-who-planted-a-forest', 2, 'true-2', 'Her teacher explained that without trees, the soil couldn''t hold rainwater, and animals had nowhere to live.', 'Gurunya menjelaskan bahwa tanpa pohon, tanah tak bisa menahan air hujan, dan hewan tak punya tempat tinggal.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-girl-who-planted-a-forest_3', 'bok_the-girl-who-planted-a-forest', 3, 'true-3', 'Maya decided to plant just one small seedling that weekend. It felt tiny compared to the whole bare hill.', 'Maya memutuskan menanam satu bibit kecil akhir pekan itu. Rasanya kecil sekali dibanding seluruh bukit gundul.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-girl-who-planted-a-forest_4', 'bok_the-girl-who-planted-a-forest', 4, 'true-4', 'She asked her friends to help the next weekend. Ten children came, then twenty, then the whole school.', 'Ia mengajak teman-temannya membantu akhir pekan berikutnya. Sepuluh anak datang, lalu dua puluh, lalu seluruh sekolah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-girl-who-planted-a-forest_5', 'bok_the-girl-who-planted-a-forest', 5, 'true-5', 'Within two years, hundreds of young trees covered the hill, and birds and butterflies began to return.', 'Dalam dua tahun, ratusan pohon muda menutupi bukit itu, dan burung serta kupu-kupu mulai kembali.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-girl-who-planted-a-forest_6', 'bok_the-girl-who-planted-a-forest', 6, 'true-6', 'Maya learned that one small act, shared with others, can grow into something as big as a forest.', 'Maya belajar bahwa satu tindakan kecil, jika dibagikan bersama orang lain, bisa tumbuh menjadi sebesar hutan.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-girl-who-planted-a-forest_1', 'bok_the-girl-who-planted-a-forest', 1, 'What did Maya notice about the hill?', 'Apa yang disadari Maya tentang bukit itu?', '["It had too many trees","It had no trees left","It was covered in flowers","It was underwater"]', '["Terlalu banyak pohon","Tidak ada pohon lagi","Penuh bunga","Terendam air"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-girl-who-planted-a-forest_2', 'bok_the-girl-who-planted-a-forest', 2, 'How did Maya''s small act grow?', 'Bagaimana tindakan kecil Maya berkembang?', '["It stayed just her alone","Friends and eventually the whole school joined","She gave up","Nobody noticed"]', '["Tetap sendirian","Teman-teman dan akhirnya seluruh sekolah ikut","Ia menyerah","Tidak ada yang peduli"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-girl-who-planted-a-forest_3', 'bok_the-girl-who-planted-a-forest', 3, 'What returned to the hill after the trees grew?', 'Apa yang kembali ke bukit setelah pohon tumbuh?', '["Cars","Birds and butterflies","Buildings","Nothing changed"]', '["Mobil","Burung dan kupu-kupu","Gedung","Tidak ada yang berubah"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-lion-and-the-mouse', 'the-lion-and-the-mouse', 'The Lion and the Mouse', 'Singa dan Tikus Kecil', 'A tiny mouse promises to help a mighty lion — and one day, against all odds, she keeps her word.', 'Seekor tikus kecil berjanji menolong singa yang perkasa — dan suatu hari, ia benar-benar menepatinya.', 'cat_moral-stories', 'aut_axto-creative-team', 'sunrise', '🦁', 3, 8, 0, 'published', 14, 862, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_1', 'bok_the-lion-and-the-mouse', 1, 'lion-mouse-1', 'Deep in the golden grasslands of Africa lived a great lion. He was the strongest animal for miles around, and when he roared, even the wind seemed to hold its breath.', 'Jauh di padang rumput keemasan Afrika, hiduplah seekor singa besar. Ia hewan terkuat sejauh mata memandang, dan ketika ia mengaum, angin pun seakan menahan napas.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_2', 'bok_the-lion-and-the-mouse', 2, 'lion-mouse-2', 'One warm afternoon, the lion lay sleeping under a shady acacia tree, his huge paws stretched out in the soft grass.', 'Suatu siang yang hangat, singa itu tertidur di bawah pohon akasia yang rindang, cakar besarnya terjulur di rerumputan lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_3', 'bok_the-lion-and-the-mouse', 3, 'lion-mouse-3', 'A little mouse, hurrying home with a seed for her supper, did not see the sleeping lion. She scampered right up his warm back — and woke him with a start!', 'Seekor tikus kecil yang tergesa pulang membawa biji untuk makan malamnya tak melihat singa yang tidur. Ia berlari tepat ke punggung hangat sang singa — dan membangunkannya!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_4', 'bok_the-lion-and-the-mouse', 4, 'lion-mouse-4', 'The lion''s giant paw came down and trapped her gently against the ground. ''How dare you wake me!'' he growled. The mouse trembled from her whiskers to her tail.', 'Cakar raksasa singa turun dan menahannya lembut ke tanah. ''Berani sekali kau membangunkanku!'' geramnya. Tikus itu gemetar dari kumis sampai ekornya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_5', 'bok_the-lion-and-the-mouse', 5, 'lion-mouse-5', '''Please, mighty lion, let me go,'' she squeaked. ''I am only small, and I meant no harm. If you set me free, perhaps one day I can help you.''', '''Tolong, singa yang perkasa, lepaskan aku,'' cicitnya. ''Aku hanya kecil dan tak bermaksud jahat. Jika kau membebaskanku, mungkin suatu hari aku bisa menolongmu.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_6', 'bok_the-lion-and-the-mouse', 6, 'lion-mouse-6', 'The lion laughed a great rumbling laugh. ''You? Help me? What a funny little thought!'' But he was in a kind mood, so he lifted his paw and let her go.', 'Singa itu tertawa menggelegar. ''Kau? Menolongku? Sungguh lucu!'' Namun hatinya sedang baik, maka ia mengangkat cakarnya dan melepaskan tikus itu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_7', 'bok_the-lion-and-the-mouse', 7, 'lion-mouse-7', '''Thank you, thank you!'' cried the mouse, and she darted away into the grass, her small heart pounding with relief.', '''Terima kasih, terima kasih!'' seru tikus itu, lalu melesat ke rerumputan, jantung kecilnya berdebar lega.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_8', 'bok_the-lion-and-the-mouse', 8, 'lion-mouse-8', 'Many days passed. Then one evening, hunters came to the grasslands. They spread a strong rope net between the trees, and the great lion walked straight into their trap.', 'Berhari-hari berlalu. Lalu suatu senja, pemburu datang ke padang. Mereka membentangkan jaring tali yang kuat di antara pohon, dan singa besar itu berjalan tepat ke perangkap.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_9', 'bok_the-lion-and-the-mouse', 9, 'lion-mouse-9', 'The more he struggled, the tighter the net held him. He roared and roared, but the ropes would not break. For the first time, the mighty lion felt truly helpless.', 'Semakin ia meronta, semakin erat jaring itu mengikatnya. Ia mengaum berkali-kali, tetapi tali itu tak putus. Untuk pertama kalinya, singa perkasa itu merasa benar-benar tak berdaya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_10', 'bok_the-lion-and-the-mouse', 10, 'lion-mouse-10', 'Far away, the little mouse heard the desperate roars. ''That is my friend the lion!'' she said, and she ran as fast as her tiny legs could carry her.', 'Jauh di sana, tikus kecil mendengar aumannya yang putus asa. ''Itu sahabatku, sang singa!'' katanya, lalu ia berlari secepat kaki kecilnya bisa membawanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_11', 'bok_the-lion-and-the-mouse', 11, 'lion-mouse-11', 'She reached the net and began to gnaw — nibble, nibble, nibble — with her sharp little teeth. One rope snapped. Then another. Then another.', 'Ia sampai di jaring dan mulai menggerogoti — kriuk, kriuk, kriuk — dengan gigi kecilnya yang tajam. Satu tali putus. Lalu satu lagi. Lalu satu lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_12', 'bok_the-lion-and-the-mouse', 12, 'lion-mouse-12', 'At last the net fell open, and the great lion stepped free. He looked down at the tiny mouse in wonder. ''You truly did help me,'' he said softly.', 'Akhirnya jaring itu terbuka, dan singa besar melangkah bebas. Ia menunduk memandang tikus mungil itu dengan takjub. ''Kau sungguh menolongku,'' katanya lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_13', 'bok_the-lion-and-the-mouse', 13, 'lion-mouse-13', 'From that day on, the lion and the mouse were the closest of friends. And the lion never again laughed at anyone for being small.', 'Sejak hari itu, singa dan tikus menjadi sahabat terdekat. Dan singa tak pernah lagi menertawakan siapa pun karena tubuhnya kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-lion-and-the-mouse_14', 'bok_the-lion-and-the-mouse', 14, 'lion-mouse-14', 'For kindness is never wasted, and even the smallest friend can do the greatest thing. The end.', 'Sebab kebaikan tak pernah sia-sia, dan sahabat sekecil apa pun bisa melakukan hal terbesar. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-lion-and-the-mouse_1', 'bok_the-lion-and-the-mouse', 1, 'Why did the lion let the mouse go?', 'Mengapa singa melepaskan tikus?', '["He was hungry","He was in a kind mood","The mouse ran away","He was afraid"]', '["Ia lapar","Hatinya sedang baik","Tikus melarikan diri","Ia takut"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-lion-and-the-mouse_2', 'bok_the-lion-and-the-mouse', 2, 'How did the mouse save the lion?', 'Bagaimana tikus menyelamatkan singa?', '["She roared loudly","She called the hunters","She gnawed through the net","She dug a hole"]', '["Ia mengaum keras","Ia memanggil pemburu","Ia menggerogoti jaring","Ia menggali lubang"]', 2, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-lion-and-the-mouse_3', 'bok_the-lion-and-the-mouse', 3, 'What is the lesson of the story?', 'Apa pelajaran dari cerita ini?', '["Big is always best","Kindness is never wasted","Never sleep outside","Run fast"]', '["Besar selalu terbaik","Kebaikan tak pernah sia-sia","Jangan tidur di luar","Berlari cepat"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_momotaro-the-peach-boy', 'momotaro-the-peach-boy', 'Momotaro, the Peach Boy', 'Momotaro, Anak dari Buah Persik', 'A brave boy born from a giant peach sets off with three animal friends to bring peace back to his island.', 'Anak pemberani yang lahir dari buah persik raksasa berpetualang bersama tiga sahabat hewan untuk membawa kedamaian kembali ke pulaunya.', 'cat_adventure', 'aut_axto-creative-team', 'sunrise', '🍑', 4, 9, 0, 'published', 15, 4965, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_1', 'bok_momotaro-the-peach-boy', 1, 'momo-1', 'Long ago in Japan, an old woodcutter and his wife lived at the edge of a quiet village. They were kind and gentle, but they had no children, and their little house often felt empty.', 'Dahulu kala di Jepang, seorang penebang kayu tua dan istrinya tinggal di tepi desa yang tenang. Mereka baik dan lembut, tetapi tak punya anak, dan rumah kecil mereka sering terasa sepi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_2', 'bok_momotaro-the-peach-boy', 2, 'momo-2', 'One morning, while the old woman washed clothes by the river, an enormous peach came bobbing down the water — the biggest peach she had ever seen.', 'Suatu pagi, ketika nenek mencuci pakaian di sungai, sebuah buah persik raksasa hanyut di air — persik terbesar yang pernah ia lihat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_3', 'bok_momotaro-the-peach-boy', 3, 'momo-3', 'She carried it home, and when the old man raised his knife to slice it, the peach split open by itself — and inside sat a healthy, laughing baby boy!', 'Ia membawanya pulang, dan ketika kakek mengangkat pisau untuk membelahnya, persik itu terbuka dengan sendirinya — dan di dalamnya duduk seorang bayi laki-laki yang sehat dan tertawa!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_4', 'bok_momotaro-the-peach-boy', 4, 'momo-4', '''A gift from heaven!'' they cried with joy. They named him Momotaro, which means Peach Boy, and raised him with all their love.', '''Anugerah dari langit!'' seru mereka penuh gembira. Mereka menamainya Momotaro, yang berarti Anak Persik, dan membesarkannya dengan segenap cinta.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_5', 'bok_momotaro-the-peach-boy', 5, 'momo-5', 'Momotaro grew strong and kind. But across the sea lay Ogre Island, where fierce ogres sailed out to trouble the villages and take what was not theirs.', 'Momotaro tumbuh kuat dan baik hati. Namun di seberang laut ada Pulau Raksasa, tempat para raksasa buas berlayar untuk mengganggu desa dan merampas yang bukan milik mereka.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_6', 'bok_momotaro-the-peach-boy', 6, 'momo-6', 'When he was old enough, Momotaro said, ''I will sail to Ogre Island and ask the ogres to stop, so our people can live in peace.'' His parents packed him millet dumplings for the journey.', 'Ketika cukup besar, Momotaro berkata, ''Aku akan berlayar ke Pulau Raksasa dan meminta mereka berhenti, agar rakyat kita hidup damai.'' Orang tuanya membekali kue millet untuk perjalanannya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_7', 'bok_momotaro-the-peach-boy', 7, 'momo-7', 'On the road he met a spotted dog. ''Where are you going, Momotaro?'' ''To Ogre Island, for peace.'' ''Give me a dumpling and I will come too!'' So they walked on together.', 'Di jalan ia bertemu anjing belang. ''Mau ke mana, Momotaro?'' ''Ke Pulau Raksasa, demi kedamaian.'' ''Beri aku sekue dan aku ikut!'' Maka mereka berjalan bersama.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_8', 'bok_momotaro-the-peach-boy', 8, 'momo-8', 'Next came a clever monkey, and then a bright-eyed pheasant. Each shared a dumpling, and each joined the quest. Now they were four brave friends.', 'Lalu datang seekor monyet cerdik, dan seekor burung pegar bermata cerah. Masing-masing berbagi kue, dan masing-masing ikut serta. Kini mereka berempat sahabat pemberani.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_9', 'bok_momotaro-the-peach-boy', 9, 'momo-9', 'They built a little boat and rowed across the wide blue sea. The pheasant flew ahead to scout, the monkey climbed the mast, and the dog watched the waves.', 'Mereka membuat perahu kecil dan mendayung menyeberangi laut biru yang luas. Pegar terbang memandu, monyet memanjat tiang, dan anjing mengawasi ombak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_10', 'bok_momotaro-the-peach-boy', 10, 'momo-10', 'At last they reached Ogre Island, ringed by tall black walls. The ogres laughed from their fortress. ''Go home, little boy!'' they shouted.', 'Akhirnya mereka sampai di Pulau Raksasa, dikelilingi tembok hitam yang tinggi. Para raksasa tertawa dari benteng mereka. ''Pulanglah, anak kecil!'' teriak mereka.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_11', 'bok_momotaro-the-peach-boy', 11, 'momo-11', 'But Momotaro and his friends worked as a team. The pheasant swooped and distracted the ogres, the monkey unlocked the gate, and the dog and Momotaro walked bravely inside.', 'Namun Momotaro dan sahabatnya bekerja sebagai satu tim. Pegar menukik mengalihkan perhatian raksasa, monyet membuka gerbang, dan anjing bersama Momotaro melangkah masuk dengan berani.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_12', 'bok_momotaro-the-peach-boy', 12, 'momo-12', 'The ogre king was surprised by their courage and teamwork. ''We surrender!'' he said. ''We are sorry for the trouble we caused.''', 'Raja raksasa terkejut oleh keberanian dan kerja sama mereka. ''Kami menyerah!'' katanya. ''Kami minta maaf atas kekacauan yang kami buat.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_13', 'bok_momotaro-the-peach-boy', 13, 'momo-13', 'Momotaro did not wish to be cruel. ''Return what you have taken, and promise to trouble the villages no more.'' The ogres agreed and gave back every stolen treasure.', 'Momotaro tak ingin kejam. ''Kembalikan yang kalian rampas, dan berjanjilah tak lagi mengganggu desa.'' Para raksasa setuju dan mengembalikan setiap harta yang mereka curi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_14', 'bok_momotaro-the-peach-boy', 14, 'momo-14', 'Momotaro and his three friends sailed home as heroes. The village celebrated, and the old couple hugged their brave Peach Boy with happy tears.', 'Momotaro dan tiga sahabatnya berlayar pulang sebagai pahlawan. Desa bersukacita, dan pasangan tua itu memeluk Anak Persik pemberani mereka dengan air mata bahagia.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_momotaro-the-peach-boy_15', 'bok_momotaro-the-peach-boy', 15, 'momo-15', 'And from that day, the island lived in peace — because Momotaro knew that courage and good friends can solve even the biggest troubles. The end.', 'Dan sejak hari itu, pulau itu hidup damai — sebab Momotaro tahu bahwa keberanian dan sahabat yang baik dapat mengatasi masalah terbesar sekalipun. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_momotaro-the-peach-boy_1', 'bok_momotaro-the-peach-boy', 1, 'Where was Momotaro found?', 'Di mana Momotaro ditemukan?', '["In a basket","Inside a giant peach","Under a tree","In a boat"]', '["Dalam keranjang","Di dalam persik raksasa","Di bawah pohon","Di perahu"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_momotaro-the-peach-boy_2', 'bok_momotaro-the-peach-boy', 2, 'Who joined Momotaro on his journey?', 'Siapa yang menemani Momotaro?', '["A dog, a monkey, and a pheasant","Three ogres","His teacher","No one"]', '["Anjing, monyet, dan pegar","Tiga raksasa","Gurunya","Tak seorang pun"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_momotaro-the-peach-boy_3', 'bok_momotaro-the-peach-boy', 3, 'How did they defeat the ogres?', 'Bagaimana mereka mengalahkan raksasa?', '["By fighting alone","With teamwork","By running away","With magic"]', '["Bertarung sendiri","Dengan kerja sama","Dengan melarikan diri","Dengan sihir"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_anansi-and-the-pot-of-wisdom', 'anansi-and-the-pot-of-wisdom', 'Anansi and the Pot of Wisdom', 'Anansi dan Periuk Kebijaksanaan', 'A clever spider tries to keep all the world''s wisdom for himself — and learns something wiser than he expected.', 'Laba-laba cerdik berusaha menyimpan semua kebijaksanaan dunia untuk dirinya sendiri — lalu belajar sesuatu yang lebih bijak dari dugaannya.', 'cat_moral-stories', 'aut_axto-creative-team', 'forest', '🕷️', 4, 9, 0, 'published', 12, 1571, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_1', 'bok_anansi-and-the-pot-of-wisdom', 1, 'anansi-1', 'In the warm forests of West Africa, there lived a clever spider named Anansi. He loved to know things — more than anyone else in the whole world.', 'Di hutan hangat Afrika Barat, hiduplah laba-laba cerdik bernama Anansi. Ia suka mengetahui banyak hal — lebih dari siapa pun di seluruh dunia.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_2', 'bok_anansi-and-the-pot-of-wisdom', 2, 'anansi-2', 'One day Anansi had an idea. ''If I gather ALL the wisdom in the world into one pot,'' he thought, ''then I will be the wisest of all, and everyone will need me.''', 'Suatu hari Anansi punya gagasan. ''Jika kukumpulkan SEMUA kebijaksanaan dunia ke dalam satu periuk,'' pikirnya, ''aku akan menjadi yang paling bijak, dan semua orang membutuhkanku.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_3', 'bok_anansi-and-the-pot-of-wisdom', 3, 'anansi-3', 'So he traveled far and wide, collecting wise sayings, clever ideas, and useful knowledge, and he poured every drop into a great clay pot.', 'Maka ia mengembara jauh, mengumpulkan kata-kata bijak, ide cerdas, dan pengetahuan berguna, lalu menuang setiap tetesnya ke dalam periuk tanah liat yang besar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_4', 'bok_anansi-and-the-pot-of-wisdom', 4, 'anansi-4', 'When the pot was full, Anansi wanted to hide it where no one could ever reach it. ''I will keep it at the very top of the tallest tree,'' he decided.', 'Ketika periuk itu penuh, Anansi ingin menyembunyikannya di tempat yang tak terjangkau siapa pun. ''Akan kusimpan di puncak pohon tertinggi,'' putusnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_5', 'bok_anansi-and-the-pot-of-wisdom', 5, 'anansi-5', 'He tied the heavy pot to the front of his belly and began to climb. But the pot kept bumping against the trunk and getting in his way.', 'Ia mengikat periuk berat itu di depan perutnya dan mulai memanjat. Namun periuk itu terus terbentur batang pohon dan menghalangi jalannya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_6', 'bok_anansi-and-the-pot-of-wisdom', 6, 'anansi-6', 'Again and again he slipped back down. The pot was simply too big and awkward to carry up the front of him. Anansi grew tired and cross.', 'Berulang kali ia melorot turun. Periuk itu terlalu besar dan menyusahkan untuk dibawa di depan tubuhnya. Anansi menjadi lelah dan kesal.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_7', 'bok_anansi-and-the-pot-of-wisdom', 7, 'anansi-7', 'Down below, his young son had been watching quietly. ''Father,'' he called up, ''wouldn''t it be easier to tie the pot on your BACK? Then you could climb freely.''', 'Di bawah, anaknya yang kecil memperhatikan dengan tenang. ''Ayah,'' serunya, ''bukankah lebih mudah mengikat periuk di PUNGGUNG? Agar Ayah bisa memanjat dengan leluasa.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_8', 'bok_anansi-and-the-pot-of-wisdom', 8, 'anansi-8', 'Anansi stopped. The idea was so simple — and so clever — and it had come from his little son, not from the great pot of wisdom at all.', 'Anansi terdiam. Gagasan itu begitu sederhana — dan begitu cerdas — dan datang dari anak kecilnya, bukan dari periuk kebijaksanaan yang besar itu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_9', 'bok_anansi-and-the-pot-of-wisdom', 9, 'anansi-9', '''I gathered all the wisdom in the world,'' Anansi said slowly, ''yet my own son knew something I did not. Wisdom cannot belong to just one person.''', '''Aku mengumpulkan semua kebijaksanaan dunia,'' kata Anansi perlahan, ''namun anakku sendiri tahu sesuatu yang tak kuketahui. Kebijaksanaan tak bisa menjadi milik satu orang saja.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_10', 'bok_anansi-and-the-pot-of-wisdom', 10, 'anansi-10', 'In that moment Anansi understood. He lifted the pot high and let it tip. The wisdom spilled out and scattered on the wind, drifting to every corner of the earth.', 'Saat itu Anansi mengerti. Ia mengangkat periuk itu tinggi-tinggi dan menumpahkannya. Kebijaksanaan tumpah dan berhamburan tertiup angin, melayang ke setiap sudut bumi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_11', 'bok_anansi-and-the-pot-of-wisdom', 11, 'anansi-11', 'That is why, to this day, a little bit of wisdom can be found in everyone — in the old and the young, the big and the small.', 'Itulah sebabnya, hingga kini, sedikit kebijaksanaan bisa ditemukan pada setiap orang — pada yang tua dan yang muda, yang besar dan yang kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_anansi-and-the-pot-of-wisdom_12', 'bok_anansi-and-the-pot-of-wisdom', 12, 'anansi-12', 'And Anansi learned the wisest lesson of all: that we grow wiser not by keeping knowledge to ourselves, but by sharing it. The end.', 'Dan Anansi belajar pelajaran paling bijak: bahwa kita menjadi lebih bijak bukan dengan menyimpan pengetahuan sendiri, melainkan dengan membagikannya. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_anansi-and-the-pot-of-wisdom_1', 'bok_anansi-and-the-pot-of-wisdom', 1, 'What did Anansi try to collect?', 'Apa yang Anansi coba kumpulkan?', '["Gold coins","All the wisdom in the world","Ripe fruit","Spider webs"]', '["Koin emas","Semua kebijaksanaan dunia","Buah matang","Jaring laba-laba"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_anansi-and-the-pot-of-wisdom_2', 'bok_anansi-and-the-pot-of-wisdom', 2, 'Who gave Anansi the clever idea?', 'Siapa yang memberi Anansi ide cerdas?', '["A wise king","His young son","A bird","No one"]', '["Raja bijak","Anaknya yang kecil","Seekor burung","Tak seorang pun"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_anansi-and-the-pot-of-wisdom_3', 'bok_anansi-and-the-pot-of-wisdom', 3, 'What did Anansi learn?', 'Apa yang Anansi pelajari?', '["To keep everything","That wisdom grows by sharing","To climb faster","To stay quiet"]', '["Menyimpan segalanya","Kebijaksanaan tumbuh dengan berbagi","Memanjat lebih cepat","Diam saja"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-fisherman-and-the-golden-fish', 'the-fisherman-and-the-golden-fish', 'The Fisherman and the Golden Fish', 'Nelayan dan Ikan Emas', 'A kind old fisherman frees a magical fish — but when wishes grow greedy, he learns what truly matters.', 'Nelayan tua yang baik hati membebaskan ikan ajaib — namun ketika permintaan berubah tamak, ia belajar apa yang sungguh berharga.', 'cat_moral-stories', 'aut_axto-creative-team', 'ocean', '🐟', 4, 9, 0, 'published', 14, 623, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_1', 'bok_the-fisherman-and-the-golden-fish', 1, 'gfish-1', 'By the shore of a wide grey sea lived a poor old fisherman and his wife, in a tiny hut with a leaky roof and one old fishing net.', 'Di tepi laut kelabu yang luas, tinggallah nelayan tua yang miskin dan istrinya, di gubuk kecil beratap bocor dengan satu jala tua.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_2', 'bok_the-fisherman-and-the-golden-fish', 2, 'gfish-2', 'One morning the fisherman cast his net and pulled up something that shimmered like sunlight — a beautiful golden fish.', 'Suatu pagi nelayan menebar jala dan menarik sesuatu yang berkilau seperti cahaya matahari — seekor ikan emas yang indah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_3', 'bok_the-fisherman-and-the-golden-fish', 3, 'gfish-3', 'To his amazement, the fish spoke. ''Kind fisherman, please let me go, and I will grant you a wish in return.''', 'Betapa terkejutnya ia, ikan itu berbicara. ''Nelayan yang baik, tolong lepaskan aku, dan aku akan mengabulkan satu permintaanmu.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_4', 'bok_the-fisherman-and-the-golden-fish', 4, 'gfish-4', 'The fisherman had a gentle heart. ''You need no reward, little fish. Go home to your family.'' And he slipped the golden fish back into the waves.', 'Nelayan itu berhati lembut. ''Kau tak perlu memberi imbalan, ikan kecil. Pulanglah ke keluargamu.'' Dan ia melepas ikan emas itu kembali ke ombak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_5', 'bok_the-fisherman-and-the-golden-fish', 5, 'gfish-5', 'When he told his wife, she frowned. ''You foolish man! Go back and ask for a fine new loaf of bread — ours is stale.''', 'Ketika ia bercerita pada istrinya, sang istri mengernyit. ''Suami bodoh! Kembalilah dan minta sepotong roti baru yang enak — roti kita sudah basi.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_6', 'bok_the-fisherman-and-the-golden-fish', 6, 'gfish-6', 'The fisherman called the fish, and at once fresh warm bread appeared on their table. But the next day, his wife wanted more.', 'Nelayan memanggil ikan itu, dan seketika roti hangat yang segar muncul di meja mereka. Namun keesokan harinya, istrinya ingin lebih.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_7', 'bok_the-fisherman-and-the-golden-fish', 7, 'gfish-7', '''Ask for a new house!'' she said. So he did, and their leaky hut became a snug cottage with a solid roof and a warm fire.', '''Minta rumah baru!'' katanya. Maka ia melakukannya, dan gubuk bocor mereka menjadi pondok nyaman beratap kokoh dengan perapian yang hangat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_8', 'bok_the-fisherman-and-the-golden-fish', 8, 'gfish-8', 'But a cottage was not enough. ''Now ask for a grand mansion, with servants and gardens!'' Again the fish granted it. Yet still she was not happy.', 'Namun pondok itu tak cukup. ''Sekarang minta rumah megah, dengan pelayan dan taman!'' Lagi-lagi ikan itu mengabulkannya. Namun sang istri tetap tak bahagia.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_9', 'bok_the-fisherman-and-the-golden-fish', 9, 'gfish-9', '''I do not want to be rich,'' she declared. ''I want to be Queen of all the land!'' The fisherman''s heart sank, but he went to the shore once more.', '''Aku tak mau hanya kaya,'' katanya. ''Aku ingin menjadi Ratu seluruh negeri!'' Hati nelayan itu tenggelam, tetapi ia pergi ke pantai sekali lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_10', 'bok_the-fisherman-and-the-golden-fish', 10, 'gfish-10', 'The sea had turned dark and stormy. The golden fish rose from the churning waves. ''What does she wish for now?'' it asked quietly.', 'Laut menjadi gelap dan bergolak. Ikan emas muncul dari ombak yang bergemuruh. ''Apa lagi yang ia inginkan sekarang?'' tanyanya perlahan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_11', 'bok_the-fisherman-and-the-golden-fish', 11, 'gfish-11', '''She wishes to be Queen,'' the fisherman whispered, ashamed. The fish looked at him with sad, wise eyes, then vanished beneath the water without a word.', '''Ia ingin menjadi Ratu,'' bisik nelayan itu dengan malu. Ikan itu menatapnya dengan mata sedih nan bijak, lalu lenyap di bawah air tanpa sepatah kata.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_12', 'bok_the-fisherman-and-the-golden-fish', 12, 'gfish-12', 'When the fisherman walked home, the mansion was gone. The gardens were gone. There stood only their tiny old hut, with its leaky roof, just as before.', 'Ketika nelayan pulang, rumah megah itu lenyap. Tamannya lenyap. Yang tersisa hanya gubuk tua kecil mereka, dengan atap bocornya, persis seperti dulu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_13', 'bok_the-fisherman-and-the-golden-fish', 13, 'gfish-13', 'His wife sat quietly by the door. For the first time in a long while, she looked at all they still had — each other, a roof, and the wide kind sea.', 'Istrinya duduk diam di dekat pintu. Untuk pertama kalinya sejak lama, ia memandang semua yang masih mereka miliki — satu sama lain, sebuah atap, dan laut yang luas dan ramah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-fisherman-and-the-golden-fish_14', 'bok_the-fisherman-and-the-golden-fish', 14, 'gfish-14', '''I am sorry,'' she said softly. ''I forgot to be thankful.'' And from that day they lived simply and gratefully, and were happier than any king or queen. The end.', '''Maafkan aku,'' katanya lirih. ''Aku lupa bersyukur.'' Dan sejak hari itu mereka hidup sederhana dan penuh syukur, lebih bahagia dari raja atau ratu mana pun. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-fisherman-and-the-golden-fish_1', 'bok_the-fisherman-and-the-golden-fish', 1, 'Why did the fisherman first let the fish go?', 'Mengapa nelayan mula-mula melepas ikan itu?', '["He wasn''t hungry","He had a kind heart","The fish was too small","He was afraid"]', '["Ia tak lapar","Ia berhati baik","Ikannya terlalu kecil","Ia takut"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-fisherman-and-the-golden-fish_2', 'bok_the-fisherman-and-the-golden-fish', 2, 'What happened when the wife grew greedy?', 'Apa yang terjadi saat istrinya menjadi tamak?', '["She became Queen","Everything vanished","The fish gave more","Nothing changed"]', '["Ia jadi Ratu","Semuanya lenyap","Ikan memberi lebih","Tak ada yang berubah"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-fisherman-and-the-golden-fish_3', 'bok_the-fisherman-and-the-golden-fish', 3, 'What did the wife finally learn?', 'Apa yang akhirnya dipelajari istrinya?', '["To wish for more","To be thankful","To catch fish","To build houses"]', '["Meminta lebih banyak","Bersyukur","Menangkap ikan","Membangun rumah"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-magic-paintbrush', 'the-magic-paintbrush', 'The Magic Paintbrush', 'Kuas Ajaib', 'A poor but generous boy is given a paintbrush that brings drawings to life — and uses its magic to help everyone but the greedy.', 'Anak miskin yang murah hati diberi kuas yang menghidupkan gambar — dan memakai keajaibannya untuk menolong semua orang, kecuali yang tamak.', 'cat_fairy-tales', 'aut_axto-creative-team', 'sunrise', '🖌️', 4, 9, 0, 'published', 13, 3348, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_1', 'bok_the-magic-paintbrush', 1, 'brush-1', 'In a village in old China lived a poor boy named Ma Liang. He had no paints and no brush, but more than anything in the world, he longed to draw.', 'Di sebuah desa di Tiongkok kuno, tinggallah anak miskin bernama Ma Liang. Ia tak punya cat maupun kuas, tetapi lebih dari apa pun di dunia, ia ingin menggambar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_2', 'bok_the-magic-paintbrush', 2, 'brush-2', 'He practiced with a twig in the sand and a wet finger on stone. Every bird, every fish, every leaf he drew looked almost ready to move.', 'Ia berlatih dengan ranting di pasir dan jari basah di atas batu. Setiap burung, ikan, dan daun yang ia gambar tampak nyaris bergerak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_3', 'bok_the-magic-paintbrush', 3, 'brush-3', 'One night an old man with a kind, glowing face appeared in his dream. ''You have a good and generous heart, Ma Liang. Here is a gift.''', 'Suatu malam, seorang kakek berwajah ramah dan bercahaya muncul dalam mimpinya. ''Hatimu baik dan murah hati, Ma Liang. Ini sebuah hadiah.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_4', 'bok_the-magic-paintbrush', 4, 'brush-4', 'When Ma Liang woke, a beautiful paintbrush lay in his hand. He dipped it and painted a crane — and the crane flapped its wings and flew off the paper into the sky!', 'Ketika Ma Liang bangun, sebuah kuas indah ada di tangannya. Ia mencelupkannya dan melukis burung bangau — dan bangau itu mengepakkan sayap dan terbang dari kertas ke langit!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_5', 'bok_the-magic-paintbrush', 5, 'brush-5', 'It was a magic paintbrush: whatever he painted came to life. But Ma Liang remembered his empty stomach and his poor neighbours.', 'Itu kuas ajaib: apa pun yang ia lukis menjadi hidup. Namun Ma Liang teringat perutnya yang lapar dan tetangganya yang miskin.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_6', 'bok_the-magic-paintbrush', 6, 'brush-6', 'He did not paint gold for himself. Instead he painted a plough for the farmer, a bucket for the water-carrier, and a warm blanket for a shivering old woman.', 'Ia tak melukis emas untuk dirinya. Ia justru melukis bajak untuk petani, ember untuk pembawa air, dan selimut hangat untuk nenek yang kedinginan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_7', 'bok_the-magic-paintbrush', 7, 'brush-7', 'Soon the whole village had what it needed, and everyone loved the kind boy with the magic brush.', 'Tak lama, seluruh desa memiliki apa yang mereka butuhkan, dan semua orang menyayangi anak baik dengan kuas ajaib itu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_8', 'bok_the-magic-paintbrush', 8, 'brush-8', 'But news of the brush reached a greedy rich lord. He sent his guards to seize Ma Liang and lock him in a cold stone room. ''Paint me a mountain of gold!'' he demanded.', 'Namun kabar tentang kuas itu sampai ke telinga tuan tanah yang tamak. Ia mengirim pengawal menangkap Ma Liang dan menguncinya di ruang batu yang dingin. ''Lukiskan aku gunung emas!'' perintahnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_9', 'bok_the-magic-paintbrush', 9, 'brush-9', 'Ma Liang thought carefully. He agreed — but he was clever. First he painted a wide blue sea. ''Where is my gold?'' snapped the lord.', 'Ma Liang berpikir hati-hati. Ia setuju — tetapi ia cerdik. Pertama ia melukis laut biru yang luas. ''Mana emasku?'' bentak sang tuan tanah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_10', 'bok_the-magic-paintbrush', 10, 'brush-10', '''The gold is on an island across the water,'' said Ma Liang, and he painted a fine ship. The greedy lord and his guards jumped aboard at once.', '''Emasnya ada di pulau seberang,'' kata Ma Liang, lalu ia melukis kapal yang bagus. Tuan tanah tamak dan pengawalnya langsung melompat naik.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_11', 'bok_the-magic-paintbrush', 11, 'brush-11', '''Faster! Faster!'' cried the lord. So Ma Liang painted a strong wind. He painted it stronger, and stronger — until the waves rose and carried the ship far, far over the horizon.', '''Lebih cepat! Lebih cepat!'' teriak sang tuan tanah. Maka Ma Liang melukis angin kencang. Ia melukisnya makin kencang, makin kencang — hingga ombak meninggi dan membawa kapal itu jauh, jauh melewati cakrawala.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_12', 'bok_the-magic-paintbrush', 12, 'brush-12', 'The greedy lord was never seen troubling the village again. Ma Liang returned home free, and to the people who were kind and worked hard.', 'Tuan tanah tamak itu tak pernah lagi terlihat mengganggu desa. Ma Liang pulang dengan bebas, kembali kepada orang-orang yang baik dan pekerja keras.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-magic-paintbrush_13', 'bok_the-magic-paintbrush', 13, 'brush-13', 'For the rest of his days, Ma Liang used his magic brush only to help those in need — for he knew that a gift is truest when it is shared. The end.', 'Sepanjang sisa hidupnya, Ma Liang memakai kuas ajaibnya hanya untuk menolong yang membutuhkan — sebab ia tahu bahwa sebuah anugerah paling berarti ketika dibagikan. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-paintbrush_1', 'bok_the-magic-paintbrush', 1, 'What did the magic paintbrush do?', 'Apa yang dilakukan kuas ajaib itu?', '["Made things invisible","Brought drawings to life","Turned things to gold","Told stories"]', '["Membuat benda tak terlihat","Menghidupkan gambar","Mengubah benda jadi emas","Bercerita"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-paintbrush_2', 'bok_the-magic-paintbrush', 2, 'What did Ma Liang paint for the village?', 'Apa yang Ma Liang lukis untuk desa?', '["Gold for himself","Tools and blankets to help others","A castle","Nothing"]', '["Emas untuk dirinya","Alat dan selimut untuk menolong","Sebuah istana","Tidak ada"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-magic-paintbrush_3', 'bok_the-magic-paintbrush', 3, 'How did Ma Liang outwit the greedy lord?', 'Bagaimana Ma Liang mengecoh tuan tanah tamak?', '["He gave him gold","He painted a storm at sea","He ran away","He apologised"]', '["Memberinya emas","Melukis badai di laut","Melarikan diri","Meminta maaf"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_stone-soup', 'stone-soup', 'Stone Soup', 'Sup Batu', 'Three tired travellers arrive at a village with nothing but a stone — and teach everyone the magic of sharing.', 'Tiga pengembara lelah tiba di desa hanya dengan sebuah batu — dan mengajarkan semua orang keajaiban berbagi.', 'cat_friendship', 'aut_axto-creative-team', 'forest', '🍲', 3, 8, 0, 'published', 12, 1881, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_1', 'bok_stone-soup', 1, 'soup-1', 'Three tired travellers walked a long dusty road until they reached a small village at dusk. They were hungry, and they had no food at all.', 'Tiga pengembara yang lelah menyusuri jalan berdebu yang panjang hingga tiba di desa kecil saat senja. Mereka lapar, dan sama sekali tak punya makanan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_2', 'bok_stone-soup', 2, 'soup-2', 'They knocked on doors, but times were hard. ''We have nothing to spare,'' said each villager, and quietly closed the door.', 'Mereka mengetuk pintu-pintu, tetapi masa itu sulit. ''Kami tak punya lebih,'' kata setiap warga, lalu menutup pintu perlahan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_3', 'bok_stone-soup', 3, 'soup-3', 'The travellers were not angry. Instead, they smiled. ''Then we shall make Stone Soup, and share it with the whole village!''', 'Para pengembara tidak marah. Mereka justru tersenyum. ''Kalau begitu kami akan membuat Sup Batu, dan membaginya dengan seluruh desa!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_4', 'bok_stone-soup', 4, 'soup-4', 'In the village square they lit a fire, set a big black pot of water to boil, and gently placed one smooth grey stone inside.', 'Di alun-alun desa mereka menyalakan api, menjerang periuk hitam besar berisi air, dan meletakkan sebuah batu kelabu yang halus ke dalamnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_5', 'bok_stone-soup', 5, 'soup-5', 'Curious villagers gathered round. ''Stone soup?'' ''Oh yes,'' said a traveller, stirring. ''It is delicious — though a pinch of salt would make it even better.''', 'Warga yang penasaran berkumpul. ''Sup batu?'' ''Oh ya,'' kata seorang pengembara sambil mengaduk. ''Rasanya lezat — meski sejumput garam akan membuatnya lebih enak lagi.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_6', 'bok_stone-soup', 6, 'soup-6', '''I have salt!'' said a woman, and hurried to fetch some. Soon a man said, ''I have a few carrots in my cellar,'' and in they went.', '''Aku punya garam!'' kata seorang perempuan, lalu bergegas mengambilnya. Tak lama seorang lelaki berkata, ''Aku punya beberapa wortel di gudang,'' dan wortel pun dimasukkan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_7', 'bok_stone-soup', 7, 'soup-7', '''Onions would help,'' said a traveller kindly. ''I have onions!'' called a boy. Then came potatoes, then barley, then a handful of fresh green herbs.', '''Bawang akan menambah rasa,'' kata pengembara dengan ramah. ''Aku punya bawang!'' seru seorang anak. Lalu datang kentang, jelai, dan segenggam rempah hijau segar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_8', 'bok_stone-soup', 8, 'soup-8', 'One by one, each villager brought a little of what they had — a cabbage, some beans, a bit of milk — and stirred it into the bubbling pot.', 'Satu per satu, tiap warga membawa sedikit yang mereka punya — sebutir kubis, sedikit kacang, seteguk susu — dan mengaduknya ke dalam periuk yang mendidih.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_9', 'bok_stone-soup', 9, 'soup-9', 'The smell that rose from the pot was wonderful. Something that had begun with a single stone was becoming a feast for everyone.', 'Aroma yang naik dari periuk itu sungguh menggoda. Sesuatu yang bermula dari sebutir batu kini menjadi jamuan untuk semua orang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_10', 'bok_stone-soup', 10, 'soup-10', 'When the soup was ready, the whole village sat together in the square, sharing bowls, bread, and laughter under the first stars.', 'Ketika sup matang, seluruh desa duduk bersama di alun-alun, berbagi mangkuk, roti, dan tawa di bawah bintang-bintang pertama.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_11', 'bok_stone-soup', 11, 'soup-11', '''What magic stone makes such a soup?'' the villagers asked. The travellers smiled. ''The stone is just a stone. The magic was you — sharing what you had.''', '''Batu ajaib apa yang membuat sup seperti ini?'' tanya warga. Para pengembara tersenyum. ''Batu itu hanyalah batu. Keajaibannya adalah kalian — berbagi apa yang kalian punya.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_stone-soup_12', 'bok_stone-soup', 12, 'soup-12', 'The next morning the travellers walked on, leaving behind a village that had learned the sweetest recipe of all: that a little from everyone becomes plenty for all. The end.', 'Keesokan paginya para pengembara melanjutkan perjalanan, meninggalkan desa yang telah belajar resep termanis: bahwa sedikit dari setiap orang menjadi berlimpah untuk semua. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_stone-soup_1', 'bok_stone-soup', 1, 'What did the travellers put in the pot first?', 'Apa yang pertama dimasukkan pengembara ke periuk?', '["A carrot","A stone","An onion","Salt"]', '["Wortel","Sebuah batu","Bawang","Garam"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_stone-soup_2', 'bok_stone-soup', 2, 'How did the soup become a feast?', 'Bagaimana sup itu menjadi jamuan besar?', '["By magic","Everyone shared a little food","The stone grew","They bought it"]', '["Dengan sihir","Semua berbagi sedikit makanan","Batunya membesar","Mereka membelinya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_stone-soup_3', 'bok_stone-soup', 3, 'What was the real ''magic''?', 'Apa ''keajaiban'' yang sebenarnya?', '["The stone","Sharing together","The big pot","The fire"]', '["Batunya","Berbagi bersama","Periuk besar","Apinya"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-clever-rabbit-and-the-lion', 'the-clever-rabbit-and-the-lion', 'The Clever Rabbit and the Lion', 'Kelinci Cerdik dan Singa', 'From the ancient Panchatantra of India: a small rabbit uses a big idea to save the whole forest from a greedy lion.', 'Dari Panchatantra kuno India: kelinci kecil memakai ide besar untuk menyelamatkan seluruh hutan dari singa yang serakah.', 'cat_moral-stories', 'aut_axto-creative-team', 'meadow', '🐇', 4, 9, 0, 'published', 14, 1431, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_1', 'bok_the-clever-rabbit-and-the-lion', 1, 'rabbit-lion-1', 'Long ago, in a deep green forest in India, there lived a lion who was never, ever satisfied. Every day he hunted more than he could eat, and the animals of the forest lived in fear.', 'Dahulu kala, di hutan hijau nan lebat di India, hiduplah seekor singa yang tak pernah puas. Setiap hari ia berburu lebih dari yang bisa ia makan, dan hewan-hewan hutan hidup dalam ketakutan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_2', 'bok_the-clever-rabbit-and-the-lion', 2, 'rabbit-lion-2', 'At last the animals gathered under the great banyan tree. ''If this goes on,'' said the old elephant, ''soon there will be no one left in the forest at all.''', 'Akhirnya hewan-hewan berkumpul di bawah pohon beringin besar. ''Kalau begini terus,'' kata gajah tua, ''sebentar lagi tak akan ada yang tersisa di hutan ini.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_3', 'bok_the-clever-rabbit-and-the-lion', 3, 'rabbit-lion-3', 'So they made a brave bargain with the lion: every day, one animal would come to him by lot, and in return he would leave all the others in peace. The lion licked his lips and agreed.', 'Maka mereka membuat kesepakatan berani dengan singa: setiap hari, satu hewan akan datang kepadanya berdasarkan undian, dan sebagai gantinya ia membiarkan yang lain hidup tenang. Singa menjilat bibirnya dan setuju.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_4', 'bok_the-clever-rabbit-and-the-lion', 4, 'rabbit-lion-4', 'One morning, the lot fell to a small grey rabbit. The other animals hung their heads. ''Poor little one,'' they whispered. But the rabbit''s bright eyes were already thinking.', 'Suatu pagi, undian jatuh pada seekor kelinci kecil abu-abu. Hewan-hewan lain menunduk sedih. ''Kasihan si kecil,'' bisik mereka. Namun mata cerah kelinci itu sudah mulai berpikir.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_5', 'bok_the-clever-rabbit-and-the-lion', 5, 'rabbit-lion-5', 'The rabbit did not hurry. He hopped slowly through the forest, stopped to nibble sweet grass, and arrived at the lion''s den when the sun was already high and hot.', 'Kelinci itu tidak terburu-buru. Ia melompat pelan menembus hutan, berhenti mengunyah rumput manis, dan tiba di sarang singa saat matahari sudah tinggi dan panas.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_6', 'bok_the-clever-rabbit-and-the-lion', 6, 'rabbit-lion-6', 'The lion was pacing and roaring with hunger. ''You are LATE, and you are SMALL!'' he thundered. ''Is this how the forest keeps its promise?''', 'Singa mondar-mandir dan mengaum kelaparan. ''Kau TERLAMBAT, dan kau KECIL!'' geramnya. ''Beginikah cara hutan menepati janjinya?''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_7', 'bok_the-clever-rabbit-and-the-lion', 7, 'rabbit-lion-7', 'The rabbit bowed very low. ''Forgive me, Your Majesty. Five rabbits were sent to you this morning — but on the way, another lion leapt out and ate the other four!''', 'Kelinci membungkuk dalam-dalam. ''Ampuni hamba, Baginda. Lima kelinci dikirim untukmu pagi ini — tetapi di tengah jalan, singa lain melompat keluar dan memakan empat lainnya!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_8', 'bok_the-clever-rabbit-and-the-lion', 8, 'rabbit-lion-8', '''ANOTHER lion? In MY forest?'' The lion''s mane bristled like a storm cloud. ''Where is this thief? Take me to him at once!''', '''Singa LAIN? Di hutan-KU?'' Surai singa berdiri bagai awan badai. ''Di mana pencuri itu? Antarkan aku kepadanya sekarang juga!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_9', 'bok_the-clever-rabbit-and-the-lion', 9, 'rabbit-lion-9', 'The clever rabbit led him down a winding path to an old stone well, deep and still and full of clear water. ''He lives down there, Your Majesty,'' whispered the rabbit.', 'Kelinci cerdik menuntunnya melewati jalan berliku menuju sumur batu tua, dalam, tenang, dan penuh air jernih. ''Ia tinggal di bawah sana, Baginda,'' bisik kelinci.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_10', 'bok_the-clever-rabbit-and-the-lion', 10, 'rabbit-lion-10', 'The lion looked over the edge — and there, in the water, glared a mighty lion with a great dark mane, staring straight back at him!', 'Singa menjenguk ke tepi sumur — dan di sana, di dalam air, seekor singa perkasa bersurai gelap menatapnya tajam!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_11', 'bok_the-clever-rabbit-and-the-lion', 11, 'rabbit-lion-11', '''THIEF!'' roared the lion, and the well roared back. That was too much. He leapt at his rival with all his strength — and splashed into the deep, deep water.', '''PENCURI!'' aum sang singa, dan sumur itu mengaum balik. Itu keterlaluan baginya. Ia melompat menerkam lawannya sekuat tenaga — dan tercebur ke air yang dalam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_12', 'bok_the-clever-rabbit-and-the-lion', 12, 'rabbit-lion-12', 'The lion splashed and spluttered and finally dragged himself out, soaked and shivering and very much smaller-feeling. Without a word, he slunk away from the forest and never returned.', 'Singa itu megap-megap dan akhirnya merangkak keluar, basah kuyup, menggigil, dan merasa jauh lebih kecil. Tanpa sepatah kata pun, ia pergi meninggalkan hutan dan tak pernah kembali.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_13', 'bok_the-clever-rabbit-and-the-lion', 13, 'rabbit-lion-13', 'The animals danced under the banyan tree and lifted the little rabbit onto the elephant''s back. ''The smallest of us saved us all!'' they cheered.', 'Hewan-hewan menari di bawah pohon beringin dan mengangkat kelinci kecil ke punggung gajah. ''Yang terkecil di antara kita menyelamatkan kita semua!'' sorak mereka.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-clever-rabbit-and-the-lion_14', 'bok_the-clever-rabbit-and-the-lion', 14, 'rabbit-lion-14', 'For strength wins many fights, says the old Panchatantra — but wisdom wins the ones that matter. The end.', 'Sebab kekuatan memenangkan banyak pertarungan, kata Panchatantra tua — tetapi kecerdikan memenangkan pertarungan yang paling penting. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-clever-rabbit-and-the-lion_1', 'bok_the-clever-rabbit-and-the-lion', 1, 'Why were the forest animals afraid?', 'Mengapa hewan-hewan hutan ketakutan?', '["A storm was coming","The lion hunted too much","The well was empty","The elephant was angry"]', '["Badai akan datang","Singa berburu terlalu banyak","Sumur kering","Gajah sedang marah"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-clever-rabbit-and-the-lion_2', 'bok_the-clever-rabbit-and-the-lion', 2, 'What did the rabbit show the lion in the well?', 'Apa yang ditunjukkan kelinci kepada singa di sumur?', '["A fish","A treasure","His own reflection","Another rabbit"]', '["Seekor ikan","Harta karun","Bayangannya sendiri","Kelinci lain"]', 2, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-clever-rabbit-and-the-lion_3', 'bok_the-clever-rabbit-and-the-lion', 3, 'What does the story teach?', 'Apa pesan cerita ini?', '["Bigger is stronger","Wisdom can beat strength","Never be late","Lions are bad"]', '["Besar berarti kuat","Kecerdikan bisa mengalahkan kekuatan","Jangan pernah terlambat","Singa itu jahat"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_timun-mas-and-the-giant', 'timun-mas-and-the-giant', 'Timun Mas and the Giant', 'Timun Mas dan Raksasa', 'A beloved Indonesian legend: a girl born from a golden cucumber outruns a giant with four small magical gifts and her own great courage.', 'Legenda Indonesia yang dicintai: gadis yang lahir dari timun emas mengalahkan raksasa dengan empat bingkisan ajaib dan keberaniannya sendiri.', 'cat_adventure', 'aut_axto-creative-team', 'meadow', '🥒', 4, 10, 0, 'published', 14, 542, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_1', 'bok_timun-mas-and-the-giant', 1, 'timun-1', 'On the green slopes of a Javanese mountain lived a widow named Mbok Srini, who wished for a child more than for anything under the sky.', 'Di lereng hijau sebuah gunung di Jawa, hiduplah seorang janda bernama Mbok Srini, yang menginginkan seorang anak melebihi apa pun di kolong langit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_2', 'bok_timun-mas-and-the-giant', 2, 'timun-2', 'One night a giant came striding over the hills, tall as a coconut tree, with a laugh like falling rocks. ''Plant this seed, little woman,'' he rumbled, ''and you shall have your child. But when she turns seventeen, she is MINE.''', 'Suatu malam, seorang raksasa datang melangkahi bukit-bukit, tinggi bagai pohon kelapa, dengan tawa seperti batu runtuh. ''Tanamlah biji ini, wahai ibu,'' gemuruhnya, ''dan kau akan mendapat anak. Tapi saat ia berusia tujuh belas tahun, ia MILIKKU.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_3', 'bok_timun-mas-and-the-giant', 3, 'timun-3', 'Frightened but longing, Mbok Srini planted the seed. It grew into a vine, and on the vine swelled one enormous golden cucumber that glowed like the morning sun.', 'Takut namun penuh harap, Mbok Srini menanam biji itu. Tumbuhlah sulur menjalar, dan pada sulur itu membesar sebuah timun emas raksasa yang berkilau bagai matahari pagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_4', 'bok_timun-mas-and-the-giant', 4, 'timun-4', 'When she split it open, inside lay a baby girl with cheeks like rose petals. Mbok Srini named her Timun Mas — Golden Cucumber — and loved her more each day.', 'Ketika dibelahnya, di dalamnya terbaring bayi perempuan berpipi bagai kelopak mawar. Mbok Srini menamainya Timun Mas — Timun Emas — dan menyayanginya lebih setiap hari.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_5', 'bok_timun-mas-and-the-giant', 5, 'timun-5', 'The years flew like birds. Timun Mas grew clever and kind and quick as a mountain stream. But the night before her seventeenth birthday, the ground began to shake.', 'Tahun-tahun berlalu bagai burung terbang. Timun Mas tumbuh cerdas, baik hati, dan gesit bagai aliran sungai gunung. Namun malam sebelum ulang tahunnya yang ketujuh belas, tanah mulai berguncang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_6', 'bok_timun-mas-and-the-giant', 6, 'timun-6', '''Run, my child!'' cried Mbok Srini, pressing a small cloth bundle into her hands. ''A wise hermit gave me these four gifts long ago. Use them when all seems lost!''', '''Larilah, anakku!'' seru Mbok Srini sambil menyelipkan buntelan kain kecil ke tangannya. ''Seorang pertapa bijak memberiku empat bingkisan ini dulu. Gunakan saat semua terasa hilang!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_7', 'bok_timun-mas-and-the-giant', 7, 'timun-7', 'Timun Mas ran through the moonlit forest, and the giant''s footsteps boomed behind her like thunder. Closer... closer... She opened the bundle and threw the first gift: a handful of cucumber seeds.', 'Timun Mas berlari menembus hutan bermandi cahaya bulan, dan langkah raksasa menggelegar di belakangnya bagai guntur. Makin dekat... makin dekat... Ia membuka buntelan dan melempar bingkisan pertama: segenggam biji timun.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_8', 'bok_timun-mas-and-the-giant', 8, 'timun-8', 'Instantly a tangle of vines burst from the earth, thick with heavy golden cucumbers. The greedy giant stopped to gobble them up — and Timun Mas flew ahead.', 'Seketika sulur-sulur menyembur dari tanah, lebat dengan timun emas yang berat. Raksasa yang rakus berhenti untuk melahapnya — dan Timun Mas melesat jauh ke depan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_9', 'bok_timun-mas-and-the-giant', 9, 'timun-9', 'But soon the thunder-steps returned. She threw the second gift: needles. They sprang up into a forest of bamboo, sharp as spears. The giant crashed through, roaring, scratched from head to toe.', 'Namun tak lama, langkah guntur itu kembali. Ia melempar bingkisan kedua: jarum-jarum. Semuanya menjelma hutan bambu runcing bagai tombak. Raksasa menerobos sambil mengaum, tergores dari kepala sampai kaki.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_10', 'bok_timun-mas-and-the-giant', 10, 'timun-10', 'The third gift was a handful of salt. It became a wide rolling sea! The giant waded in, gasping and swallowing waves, but still he came on.', 'Bingkisan ketiga adalah segenggam garam. Garam itu menjelma lautan luas bergelombang! Raksasa menyeberang, megap-megap menelan ombak, tapi ia terus mengejar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_11', 'bok_timun-mas-and-the-giant', 11, 'timun-11', 'At last, with trembling fingers, Timun Mas threw the final gift: a paste of hot shrimp sauce. Where it landed, the earth bubbled into a lake of boiling mud, and the giant sank down, down, down — and was gone.', 'Akhirnya, dengan jari gemetar, Timun Mas melempar bingkisan terakhir: terasi. Di tempat jatuhnya, bumi menggelegak menjadi danau lumpur mendidih, dan raksasa itu tenggelam, tenggelam, tenggelam — lalu lenyap.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_12', 'bok_timun-mas-and-the-giant', 12, 'timun-12', 'The forest fell silent. The moon came out from behind the clouds. Timun Mas walked home on shaking legs, and her mother ran to meet her with tears of joy.', 'Hutan menjadi sunyi. Bulan muncul dari balik awan. Timun Mas berjalan pulang dengan kaki gemetar, dan ibunya berlari menyambut dengan air mata bahagia.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_13', 'bok_timun-mas-and-the-giant', 13, 'timun-13', 'From that day, mother and daughter lived in peace on their green mountainside, and no giant ever troubled the valley again.', 'Sejak hari itu, ibu dan anak hidup damai di lereng gunung yang hijau, dan tak ada raksasa yang mengganggu lembah itu lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_timun-mas-and-the-giant_14', 'bok_timun-mas-and-the-giant', 14, 'timun-14', 'For courage is not being unafraid, says the old tale — it is running on even when your legs tremble, and using every gift you are given. The end.', 'Sebab keberanian bukan berarti tak takut, kata dongeng lama — melainkan terus berlari meski kakimu gemetar, dan menggunakan setiap bekal yang kau miliki. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_timun-mas-and-the-giant_1', 'bok_timun-mas-and-the-giant', 1, 'Where was baby Timun Mas found?', 'Di mana bayi Timun Mas ditemukan?', '["In a basket","Inside a golden cucumber","Under a tree","By the river"]', '["Di dalam keranjang","Di dalam timun emas","Di bawah pohon","Di tepi sungai"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_timun-mas-and-the-giant_2', 'bok_timun-mas-and-the-giant', 2, 'Which gift finally stopped the giant?', 'Bingkisan mana yang akhirnya menghentikan raksasa?', '["Cucumber seeds","Needles","Salt","Shrimp paste"]', '["Biji timun","Jarum","Garam","Terasi"]', 3, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_timun-mas-and-the-giant_3', 'bok_timun-mas-and-the-giant', 3, 'What does the story say courage is?', 'Menurut cerita, apa itu keberanian?', '["Never feeling afraid","Running on even when afraid","Being the biggest","Hiding well"]', '["Tak pernah takut","Terus berlari meski takut","Menjadi yang terbesar","Pandai bersembunyi"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-ugly-duckling', 'the-ugly-duckling', 'The Ugly Duckling', 'Itik Buruk Rupa', 'Hans Christian Andersen''s gentle classic: a little bird who never fit in discovers, after a long hard year, exactly who he was born to be.', 'Klasik lembut Hans Christian Andersen: seekor anak unggas yang tak pernah diterima akhirnya menemukan, setelah setahun yang berat, siapa dirinya sebenarnya.', 'cat_emotions', 'aut_axto-creative-team', 'sky', '🦢', 3, 8, 0, 'published', 14, 1009, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_1', 'bok_the-ugly-duckling', 1, 'duckling-1', 'By a quiet pond on a summer farm, a mother duck sat on her nest, waiting. One by one the eggs cracked open — peep! peep! — until only the biggest egg was left.', 'Di tepi kolam yang tenang di sebuah ladang musim panas, induk bebek duduk mengerami telurnya, menunggu. Satu per satu telur menetas — piyik! piyik! — hingga tersisa telur yang paling besar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_2', 'bok_the-ugly-duckling', 2, 'duckling-2', 'At last it split, and out tumbled a chick — big, grey, and clumsy. ''Well,'' said the mother duck, ''you don''t look like the others. But you are mine, and I love you.''', 'Akhirnya telur itu terbelah, dan keluarlah seekor anak unggas — besar, abu-abu, dan canggung. ''Hmm,'' kata induk bebek, ''kau tak mirip yang lain. Tapi kau anakku, dan aku menyayangimu.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_3', 'bok_the-ugly-duckling', 3, 'duckling-3', 'But the farmyard was not kind. The hens pecked him, the turkey puffed at him, and even his brothers and sisters quacked, ''Go away, ugly duckling!''', 'Namun penghuni ladang tidaklah ramah. Ayam-ayam mematuknya, kalkun menggembungkan bulunya, bahkan saudara-saudaranya berkwek, ''Pergilah, itik buruk rupa!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_4', 'bok_the-ugly-duckling', 4, 'duckling-4', 'One grey evening, his heart heavier than his little wings, the duckling slipped under the fence and wandered away alone.', 'Suatu senja kelabu, dengan hati yang lebih berat daripada sayap kecilnya, itik itu menyelinap di bawah pagar dan mengembara sendirian.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_5', 'bok_the-ugly-duckling', 5, 'duckling-5', 'Autumn came with cold rain. The duckling hid among the reeds of a marsh, where wild ducks laughed at his strange looks but let him stay.', 'Musim gugur datang membawa hujan dingin. Itik itu bersembunyi di antara gelagah rawa, tempat bebek-bebek liar menertawakan rupanya yang aneh namun membiarkannya tinggal.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_6', 'bok_the-ugly-duckling', 6, 'duckling-6', 'One evening a flock of great white birds flew overhead, their long necks stretched toward the south, their wings singing in the wind. The duckling did not know their name — but his heart ached to follow them.', 'Suatu senja, sekawanan burung putih besar terbang di atasnya, leher panjang mereka terjulur ke selatan, sayap mereka berdesir di angin. Itik itu tak tahu nama mereka — namun hatinya nyeri ingin ikut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_7', 'bok_the-ugly-duckling', 7, 'duckling-7', 'Winter was long and bitter. The duckling nearly froze in the pond ice, and a kind farmer carried him home — but he knocked over the milk pail in fright, and had to flee again.', 'Musim dingin panjang dan menggigit. Itik itu nyaris membeku di es kolam, dan seorang petani baik hati membawanya pulang — namun karena ketakutan ia menumpahkan ember susu, dan harus lari lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_8', 'bok_the-ugly-duckling', 8, 'duckling-8', 'Somehow, through frost and hunger and loneliness, the little bird survived until the willows turned green and the air smelled of spring.', 'Entah bagaimana, melewati embun beku, lapar, dan sepi, unggas kecil itu bertahan hingga pohon willow menghijau dan udara berbau musim semi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_9', 'bok_the-ugly-duckling', 9, 'duckling-9', 'He spread his wings — and they were strong now, wide and white, and they carried him high over the gardens to a shining lake where three great white birds glided like ships.', 'Ia mengembangkan sayapnya — kini kuat, lebar, dan putih, membawanya tinggi melintasi taman menuju danau berkilau tempat tiga burung putih besar meluncur bagai kapal.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_10', 'bok_the-ugly-duckling', 10, 'duckling-10', '''They will chase me away, like everyone else,'' he thought sadly. ''But better to be chased by such beautiful birds than pecked by hens.'' And he flew down to meet them.', '''Mereka pasti akan mengusirku, seperti yang lain,'' pikirnya sedih. ''Tapi lebih baik diusir burung-burung seindah itu daripada dipatuki ayam.'' Lalu ia turun menghampiri mereka.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_11', 'bok_the-ugly-duckling', 11, 'duckling-11', 'He bowed his head, waiting for the pecks — and saw, in the still water, his own reflection: not a clumsy grey duckling at all, but a swan, white as snow, graceful as morning.', 'Ia menundukkan kepala, siap dipatuk — dan melihat, di air yang tenang, bayangannya sendiri: sama sekali bukan itik abu-abu yang canggung, melainkan seekor angsa, putih bagai salju, anggun bagai pagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_12', 'bok_the-ugly-duckling', 12, 'duckling-12', 'The great swans swam around him and stroked him with their beaks. Children on the shore clapped and cried, ''The new one is the most beautiful of all!''', 'Angsa-angsa besar berenang mengelilinginya dan membelainya dengan paruh mereka. Anak-anak di tepi danau bertepuk tangan dan berseru, ''Yang baru itu paling indah dari semuanya!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_13', 'bok_the-ugly-duckling', 13, 'duckling-13', 'And the young swan felt shy and hid his head under his wing — for a heart that has known sorrow is never proud. He was happy, deeply happy, but not proud.', 'Angsa muda itu tersipu dan menyembunyikan kepala di bawah sayapnya — sebab hati yang pernah mengenal duka tak pernah menjadi sombong. Ia bahagia, sungguh bahagia, tapi tidak sombong.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-ugly-duckling_14', 'bok_the-ugly-duckling', 14, 'duckling-14', 'It does not matter, said Andersen, if you are born in a duckyard — so long as you are hatched from a swan''s egg. You are becoming who you truly are. The end.', 'Tak masalah, kata Andersen, jika kau lahir di kandang bebek — selama kau menetas dari telur angsa. Kau sedang tumbuh menjadi dirimu yang sebenarnya. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-ugly-duckling_1', 'bok_the-ugly-duckling', 1, 'Why did the duckling leave the farmyard?', 'Mengapa itik itu meninggalkan ladang?', '["He wanted adventure","Everyone was unkind to him","He was hungry","The pond froze"]', '["Ia ingin bertualang","Semua bersikap tak baik padanya","Ia lapar","Kolam membeku"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-ugly-duckling_2', 'bok_the-ugly-duckling', 2, 'What did he see in the water in spring?', 'Apa yang dilihatnya di air saat musim semi?', '["A fish","A boat","His reflection — a swan","Another duckling"]', '["Seekor ikan","Sebuah perahu","Bayangannya — seekor angsa","Itik lain"]', 2, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-ugly-duckling_3', 'bok_the-ugly-duckling', 3, 'How did the swan behave when praised?', 'Bagaimana sikap angsa saat dipuji?', '["Proud and loud","Happy but humble","Angry","He flew away"]', '["Sombong dan berisik","Bahagia tapi rendah hati","Marah","Ia terbang pergi"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-bremen-town-musicians', 'the-bremen-town-musicians', 'The Bremen Town Musicians', 'Para Pemusik Kota Bremen', 'The Brothers Grimm classic: four old animals nobody wanted team up, scare off a band of robbers, and find a home — together.', 'Klasik Grimm bersaudara: empat hewan tua yang tak diinginkan bersatu, mengusir kawanan perampok, dan menemukan rumah — bersama-sama.', 'cat_friendship', 'aut_axto-creative-team', 'sunset', '🎺', 4, 9, 0, 'published', 14, 3687, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_1', 'bok_the-bremen-town-musicians', 1, 'bremen-1', 'There was once a donkey who had carried sacks to the mill for many long years. When he grew too old to work, his master decided to send him away — so the donkey set off down the road to Bremen. ''I shall be a town musician,'' he said.', 'Alkisah seekor keledai telah bertahun-tahun memikul karung ke penggilingan. Ketika ia terlalu tua untuk bekerja, tuannya hendak membuangnya — maka keledai itu berangkat menyusuri jalan ke Bremen. ''Aku akan menjadi pemusik kota,'' katanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_2', 'bok_the-bremen-town-musicians', 2, 'bremen-2', 'On the road he found an old hunting dog lying in the grass, panting sadly. ''I am too slow to hunt now, and my master has no use for me.'' ''Come to Bremen!'' said the donkey. ''You shall play the drum.''', 'Di jalan ia menemukan seekor anjing pemburu tua terbaring di rumput, terengah sedih. ''Aku terlalu lambat untuk berburu sekarang, dan tuanku tak membutuhkanku lagi.'' ''Ikutlah ke Bremen!'' kata keledai. ''Kau akan menabuh genderang.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_3', 'bok_the-bremen-town-musicians', 3, 'bremen-3', 'Soon they met a cat sitting by the road with a face like three days of rain. ''I am old, my teeth are dull, and I would rather sit by the stove than chase mice — so no one wants me.'' ''Join us! You shall sing soprano.''', 'Tak lama mereka bertemu seekor kucing duduk di tepi jalan dengan wajah bagai hujan tiga hari. ''Aku tua, gigiku tumpul, dan aku lebih suka duduk dekat tungku daripada mengejar tikus — jadi tak ada yang menginginkanku.'' ''Bergabunglah! Kau akan menyanyi sopran.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_4', 'bok_the-bremen-town-musicians', 4, 'bremen-4', 'At a farmyard gate, a rooster was crowing with all his might. ''Guests are coming on Sunday,'' he wailed, ''and the cook means to put me in the soup! I crow while I still can.'' ''Come with us to Bremen — anything is better than the soup!''', 'Di gerbang sebuah ladang, seekor ayam jantan berkokok sekuat tenaga. ''Tamu akan datang hari Minggu,'' ratapnya, ''dan juru masak hendak memasukkanku ke dalam sup! Aku berkokok selagi bisa.'' ''Ikutlah kami ke Bremen — apa pun lebih baik daripada sup!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_5', 'bok_the-bremen-town-musicians', 5, 'bremen-5', 'Night fell before they reached the city, and deep in the forest they saw a light. Through the window of a little house they spied a table heaped with food and drink — and around it, a band of robbers counting stolen gold.', 'Malam tiba sebelum mereka sampai di kota, dan jauh di dalam hutan mereka melihat cahaya. Lewat jendela sebuah rumah kecil mereka mengintip meja penuh makanan dan minuman — dan di sekelilingnya, kawanan perampok tengah menghitung emas curian.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_6', 'bok_the-bremen-town-musicians', 6, 'bremen-6', 'The four friends put their heads together and made a plan. The donkey stood at the window, the dog climbed on his back, the cat on the dog, and the rooster perched on top of them all.', 'Keempat sahabat itu berunding dan menyusun rencana. Keledai berdiri di dekat jendela, anjing naik ke punggungnya, kucing naik ke atas anjing, dan ayam jantan bertengger paling atas.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_7', 'bok_the-bremen-town-musicians', 7, 'bremen-7', 'Then, at a signal, they made their music all at once: the donkey brayed, the dog barked, the cat yowled, and the rooster crowed — and they crashed through the window in a shower of glass!', 'Lalu, pada satu aba-aba, mereka bermusik serentak: keledai meringkik, anjing menggonggong, kucing mengeong keras, dan ayam berkokok — dan mereka menerjang jendela hingga kaca berhamburan!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_8', 'bok_the-bremen-town-musicians', 8, 'bremen-8', 'The robbers leapt up in terror. ''A ghost! A monster! A judge with a sword!'' they cried, falling over each other as they fled into the dark forest.', 'Para perampok melompat ketakutan. ''Hantu! Monster! Hakim bersama pedang!'' teriak mereka, jatuh bertumpukan sambil lari ke hutan gelap.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_9', 'bok_the-bremen-town-musicians', 9, 'bremen-9', 'The four musicians sat down at the table and ate as if they had been hungry for a month — which, in truth, they had. Then each found a sleeping place to his liking, and the lights went out.', 'Keempat pemusik duduk di meja dan makan seolah sudah lapar sebulan — dan memang begitulah adanya. Lalu masing-masing mencari tempat tidur kesukaannya, dan lampu pun padam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_10', 'bok_the-bremen-town-musicians', 10, 'bremen-10', 'At midnight, the bravest robber crept back to the dark house. In the kitchen, the cat''s eyes glowed — he took them for burning coals, and reached out to light a match.', 'Tengah malam, perampok yang paling berani menyelinap kembali ke rumah gelap itu. Di dapur, mata kucing berpendar — dikiranya bara api, dan ia mengulurkan tangan hendak menyalakan korek.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_11', 'bok_the-bremen-town-musicians', 11, 'bremen-11', 'The cat flew at his face, spitting and scratching. He stumbled to the door — the dog bit his leg. He staggered through the yard — the donkey kicked him high over the fence. And from the roof the rooster screamed, ''Cock-a-doodle-doo!''', 'Kucing menerkam wajahnya, mendesis dan mencakar. Ia terhuyung ke pintu — anjing menggigit kakinya. Ia sempoyongan melewati halaman — keledai menendangnya tinggi melewati pagar. Dan dari atap ayam jantan berteriak, ''Kukuruyuk!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_12', 'bok_the-bremen-town-musicians', 12, 'bremen-12', '''A witch scratched me, a man stabbed my leg, a monster beat me with a club,'' the robber gasped to his friends, ''and on the roof a judge shouted: Bring the rogue to me!'' The robbers never went near the house again.', '''Penyihir mencakarku, seorang pria menusuk kakiku, monster memukulku dengan pentungan,'' perampok itu tersengal pada kawan-kawannya, ''dan di atap seorang hakim berteriak: Bawa penjahat itu padaku!'' Para perampok tak pernah berani mendekati rumah itu lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_13', 'bok_the-bremen-town-musicians', 13, 'bremen-13', 'As for the four musicians, they liked their little house in the forest so well that they never went to Bremen at all. They had found something better than a stage: a home, and each other.', 'Adapun keempat pemusik, mereka begitu betah di rumah kecil di hutan itu hingga tak pernah pergi ke Bremen sama sekali. Mereka menemukan sesuatu yang lebih baik daripada panggung: sebuah rumah, dan satu sama lain.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-bremen-town-musicians_14', 'bok_the-bremen-town-musicians', 14, 'bremen-14', 'For no one is ever too old to start again, say the Brothers Grimm — and friends who sing together are never homeless. The end.', 'Sebab tak ada yang terlalu tua untuk memulai lagi, kata Grimm bersaudara — dan sahabat yang bernyanyi bersama tak akan pernah kehilangan rumah. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-bremen-town-musicians_1', 'bok_the-bremen-town-musicians', 1, 'Why did the animals leave their homes?', 'Mengapa hewan-hewan itu meninggalkan rumah mereka?', '["They were bored","Their owners no longer wanted them","They loved music","They were lost"]', '["Mereka bosan","Pemiliknya tak menginginkan mereka lagi","Mereka cinta musik","Mereka tersesat"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-bremen-town-musicians_2', 'bok_the-bremen-town-musicians', 2, 'How did they scare the robbers the first time?', 'Bagaimana mereka mengusir perampok pertama kali?', '["They called the police","They made loud music together and crashed in","They threw stones","They lit a fire"]', '["Memanggil polisi","Bermusik keras bersama dan menerjang masuk","Melempar batu","Menyalakan api"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-bremen-town-musicians_3', 'bok_the-bremen-town-musicians', 3, 'What did the four friends find in the end?', 'Apa yang akhirnya ditemukan keempat sahabat?', '["Gold","A stage in Bremen","A home together","A new master"]', '["Emas","Panggung di Bremen","Rumah bersama","Tuan baru"]', 2, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-tortoise-and-the-hare', 'the-tortoise-and-the-hare', 'The Tortoise and the Hare', 'Kura-kura dan Kelinci', 'The fastest runner in the meadow laughs at the slowest — until race day teaches everyone what steady really means.', 'Pelari tercepat di padang menertawakan yang paling lambat — sampai hari perlombaan mengajarkan arti kata ''tekun'' pada semua.', 'cat_moral-stories', 'aut_axto-creative-team', 'meadow', '🐢', 3, 8, 0, 'published', 12, 1806, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_1', 'bok_the-tortoise-and-the-hare', 1, 'tortoise-hare-1', 'In a wide green meadow lived a hare who could run like the wind. He knew it, too, and told everyone about it every single day.', 'Di padang hijau yang luas hiduplah seekor kelinci yang bisa berlari secepat angin. Ia tahu itu, dan menceritakannya kepada semua hewan setiap hari.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_2', 'bok_the-tortoise-and-the-hare', 2, 'tortoise-hare-2', '''I am the fastest animal in the whole meadow!'' he boasted. ''Nobody could ever beat me. Especially not... a tortoise!'' And he laughed and laughed.', '''Akulah hewan tercepat di seluruh padang!'' sombongnya. ''Tak ada yang bisa mengalahkanku. Apalagi... seekor kura-kura!'' Lalu ia tertawa terbahak-bahak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_3', 'bok_the-tortoise-and-the-hare', 3, 'tortoise-hare-3', 'The old tortoise looked up slowly. ''Then let us race, friend hare,'' she said in her calm, quiet voice. ''To the big oak tree on the hill.''', 'Kura-kura tua itu mengangkat kepalanya pelan-pelan. ''Kalau begitu, ayo kita berlomba, sahabat kelinci,'' katanya dengan suara tenang. ''Sampai pohon ek besar di atas bukit.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_4', 'bok_the-tortoise-and-the-hare', 4, 'tortoise-hare-4', 'All the animals gathered to watch. The fox raised his paw. ''Ready... steady... GO!'' The hare shot away like an arrow. The tortoise took one small step.', 'Semua hewan berkumpul untuk menonton. Rubah mengangkat cakarnya. ''Bersedia... siap... MULAI!'' Kelinci melesat bagai anak panah. Kura-kura melangkah satu langkah kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_5', 'bok_the-tortoise-and-the-hare', 5, 'tortoise-hare-5', 'In no time at all, the hare was so far ahead he could not even see the tortoise behind him. ''This is too easy,'' he yawned. ''I have time for a little nap.''', 'Dalam sekejap, kelinci sudah jauh sekali di depan sampai kura-kura tak terlihat lagi. ''Ini terlalu mudah,'' ia menguap. ''Aku masih sempat tidur sebentar.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_6', 'bok_the-tortoise-and-the-hare', 6, 'tortoise-hare-6', 'He curled up under a shady bush, and the warm afternoon sun soon rocked him into a deep, deep sleep.', 'Ia meringkuk di bawah semak yang teduh, dan matahari sore yang hangat segera membuainya ke dalam tidur yang sangat lelap.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_7', 'bok_the-tortoise-and-the-hare', 7, 'tortoise-hare-7', 'Meanwhile, the tortoise kept walking. Step... step... step. She did not stop to rest. She did not stop to chat. She just kept going, slow and steady.', 'Sementara itu, kura-kura terus berjalan. Langkah... langkah... langkah. Ia tak berhenti untuk beristirahat. Ia tak berhenti untuk mengobrol. Ia terus maju, pelan tapi pasti.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_8', 'bok_the-tortoise-and-the-hare', 8, 'tortoise-hare-8', 'She passed the sleeping hare very quietly. Her little legs were tired, but she whispered to herself: ''One more step. And one more. And one more.''', 'Ia melewati kelinci yang tertidur dengan sangat pelan. Kaki kecilnya lelah, tetapi ia berbisik pada dirinya: ''Satu langkah lagi. Satu lagi. Satu lagi.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_9', 'bok_the-tortoise-and-the-hare', 9, 'tortoise-hare-9', 'When the hare finally woke, the sun was already low. He stretched, laughed — and then he saw it: far up the hill, the tortoise was almost at the oak tree!', 'Ketika kelinci akhirnya terbangun, matahari sudah rendah. Ia menggeliat, tertawa — lalu ia melihatnya: jauh di atas bukit, kura-kura hampir sampai di pohon ek!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_10', 'bok_the-tortoise-and-the-hare', 10, 'tortoise-hare-10', 'The hare ran faster than he had ever run in his life. His ears flew back, his paws barely touched the ground — but it was too late.', 'Kelinci berlari lebih cepat daripada yang pernah ia lakukan seumur hidupnya. Telinganya melambai ke belakang, kakinya nyaris tak menyentuh tanah — tapi semuanya terlambat.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_11', 'bok_the-tortoise-and-the-hare', 11, 'tortoise-hare-11', 'The tortoise touched the great oak tree, and the whole meadow cheered. ''Slow and steady wins the race!'' cried the fox.', 'Kura-kura menyentuh pohon ek besar itu, dan seluruh padang bersorak. ''Pelan tapi pasti memenangkan lomba!'' seru rubah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-tortoise-and-the-hare_12', 'bok_the-tortoise-and-the-hare', 12, 'tortoise-hare-12', 'The hare hung his head — then he did something brave: he walked up and shook the tortoise''s hand. ''You taught me a big lesson today, little friend.'' And from that day, he never boasted again. The end.', 'Kelinci menundukkan kepala — lalu ia melakukan sesuatu yang berani: ia menghampiri dan menjabat tangan kura-kura. ''Kau mengajariku pelajaran besar hari ini, sahabat kecil.'' Dan sejak hari itu, ia tak pernah menyombong lagi. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-tortoise-and-the-hare_1', 'bok_the-tortoise-and-the-hare', 1, 'Why did the hare lose the race?', 'Mengapa kelinci kalah dalam perlombaan?', '["He hurt his leg","He stopped to sleep","He got lost"]', '["Kakinya terluka","Ia berhenti untuk tidur","Ia tersesat"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-tortoise-and-the-hare_2', 'bok_the-tortoise-and-the-hare', 2, 'What did the tortoise keep doing all through the race?', 'Apa yang terus dilakukan kura-kura sepanjang lomba?', '["Resting under bushes","Walking without stopping","Asking for help"]', '["Beristirahat di bawah semak","Berjalan tanpa berhenti","Meminta bantuan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-tortoise-and-the-hare_3', 'bok_the-tortoise-and-the-hare', 3, 'What lesson did the hare learn?', 'Pelajaran apa yang didapat kelinci?', '["Never race again","Boasting is fun","Do not mock others; steady effort wins"]', '["Jangan pernah berlomba lagi","Menyombong itu menyenangkan","Jangan meremehkan orang lain; ketekunan yang menang"]', 2, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-honest-woodcutter', 'the-honest-woodcutter', 'The Honest Woodcutter and the Golden Axe', 'Penebang Kayu yang Jujur dan Kapak Emas', 'A poor woodcutter drops his only axe into the deep river — and a shining spirit rises with a test that will change his life.', 'Seorang penebang kayu miskin menjatuhkan satu-satunya kapaknya ke sungai yang dalam — dan seorang peri sungai muncul membawa ujian yang mengubah hidupnya.', 'cat_manners', 'aut_axto-creative-team', 'forest', '🪓', 4, 9, 0, 'published', 13, 1137, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_1', 'bok_the-honest-woodcutter', 1, 'woodcutter-1', 'Long ago, beside a deep green river, lived a poor woodcutter. Every morning he walked into the forest with his old iron axe — the only precious thing he owned.', 'Dahulu kala, di tepi sungai hijau yang dalam, hiduplah seorang penebang kayu miskin. Setiap pagi ia masuk hutan membawa kapak besinya yang tua — satu-satunya benda berharga miliknya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_2', 'bok_the-honest-woodcutter', 2, 'woodcutter-2', 'One day, as he chopped a tree that leaned over the water, his hands slipped. The axe flew from his fingers — splash! — and sank into the deepest part of the river.', 'Suatu hari, saat menebang pohon yang condong ke air, tangannya terpeleset. Kapak itu terlempar dari genggamannya — byur! — dan tenggelam ke bagian sungai yang paling dalam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_3', 'bok_the-honest-woodcutter', 3, 'woodcutter-3', 'The woodcutter sat on the bank and covered his face. ''Without my axe I cannot work. Without work I cannot eat. What will become of me?''', 'Penebang kayu itu duduk di tepi sungai dan menutupi wajahnya. ''Tanpa kapak aku tak bisa bekerja. Tanpa bekerja aku tak bisa makan. Bagaimana nasibku nanti?''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_4', 'bok_the-honest-woodcutter', 4, 'woodcutter-4', 'Suddenly the water began to glow. Out of the river rose a gentle spirit with eyes like moonlight. ''Why do you weep, woodcutter?'' she asked.', 'Tiba-tiba air sungai mulai bercahaya. Dari dalam sungai muncul peri lembut bermata seperti cahaya bulan. ''Mengapa engkau menangis, penebang kayu?'' tanyanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_5', 'bok_the-honest-woodcutter', 5, 'woodcutter-5', '''I have lost my axe in the river,'' he said. The spirit smiled, dived down, and rose again holding an axe of pure shining gold. ''Is this yours?''', '''Kapakku jatuh ke sungai,'' katanya. Peri itu tersenyum, menyelam, lalu muncul kembali membawa kapak dari emas murni yang berkilauan. ''Inikah milikmu?''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_6', 'bok_the-honest-woodcutter', 6, 'woodcutter-6', 'The woodcutter''s eyes grew wide — gold! Enough to buy food for years. But he shook his head. ''No, kind spirit. That is not my axe.''', 'Mata penebang kayu terbelalak — emas! Cukup untuk membeli makanan bertahun-tahun. Tapi ia menggeleng. ''Bukan, peri yang baik. Itu bukan kapakku.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_7', 'bok_the-honest-woodcutter', 7, 'woodcutter-7', 'The spirit dived again and rose with an axe of bright silver. ''Then surely this one is yours?'' Again the woodcutter shook his head. ''No. Mine was only old iron.''', 'Peri itu menyelam lagi dan muncul membawa kapak perak yang berkilap. ''Kalau begitu, pasti yang ini milikmu?'' Penebang kayu kembali menggeleng. ''Bukan. Kapakku hanya besi tua.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_8', 'bok_the-honest-woodcutter', 8, 'woodcutter-8', 'A third time the spirit dived, and this time she held up the old iron axe with its worn wooden handle. ''That one is mine!'' cried the woodcutter joyfully.', 'Untuk ketiga kalinya peri itu menyelam, dan kali ini ia mengangkat kapak besi tua dengan gagang kayu yang usang. ''Yang itu milikku!'' seru penebang kayu gembira.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_9', 'bok_the-honest-woodcutter', 9, 'woodcutter-9', 'The spirit''s smile shone brighter than the gold. ''You spoke the truth, though you are poor and gold was in your reach. Honesty like yours deserves a reward.''', 'Senyum peri itu bersinar lebih terang daripada emas. ''Engkau berkata jujur, padahal engkau miskin dan emas ada di depan mata. Kejujuran seperti ini pantas mendapat hadiah.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_10', 'bok_the-honest-woodcutter', 10, 'woodcutter-10', '''Take all three axes — the iron, the silver, and the gold. Let them remind you that a true heart is the greatest treasure of all.'' And the river fell quiet again.', '''Ambillah ketiga kapak ini — besi, perak, dan emas. Biarlah semuanya mengingatkanmu bahwa hati yang jujur adalah harta yang paling besar.'' Lalu sungai itu tenang kembali.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_11', 'bok_the-honest-woodcutter', 11, 'woodcutter-11', 'A greedy neighbour heard the story and threw his own axe into the river on purpose. When the spirit offered him the golden axe, he shouted, ''Yes! That one is mine!''', 'Seorang tetangga yang serakah mendengar kisah itu dan sengaja melempar kapaknya ke sungai. Ketika peri menawarkan kapak emas, ia berteriak, ''Ya! Itu milikku!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_12', 'bok_the-honest-woodcutter', 12, 'woodcutter-12', 'The spirit looked at him sadly — and sank beneath the water, taking the golden axe, the silver axe, and even his own iron axe with her. He went home with nothing at all.', 'Peri itu memandangnya dengan sedih — lalu tenggelam ke dalam air, membawa kapak emas, kapak perak, bahkan kapak besinya sendiri. Ia pulang tanpa membawa apa-apa.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-honest-woodcutter_13', 'bok_the-honest-woodcutter', 13, 'woodcutter-13', 'But the honest woodcutter lived well and happily, and whenever anyone asked about his three axes, he would say: ''The gold is pretty — but the truth bought it.'' The end.', 'Namun penebang kayu yang jujur hidup senang dan berkecukupan, dan bila ada yang bertanya tentang ketiga kapaknya, ia menjawab: ''Emas memang indah — tapi kejujuranlah yang membelinya.'' Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-honest-woodcutter_1', 'bok_the-honest-woodcutter', 1, 'What did the woodcutter say when shown the golden axe?', 'Apa kata penebang kayu saat ditunjukkan kapak emas?', '["''That is mine!''","''That is not my axe.''","''Keep it for yourself.''"]', '["''Itu milikku!''","''Itu bukan kapakku.''","''Simpan saja untukmu.''"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-honest-woodcutter_2', 'bok_the-honest-woodcutter', 2, 'Why did the spirit give him all three axes?', 'Mengapa peri memberinya ketiga kapak itu?', '["Because he cried loudly","Because he was honest","Because he asked politely"]', '["Karena ia menangis keras","Karena ia jujur","Karena ia meminta dengan sopan"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-honest-woodcutter_3', 'bok_the-honest-woodcutter', 3, 'What happened to the greedy neighbour?', 'Apa yang terjadi pada tetangga yang serakah?', '["He got the golden axe","He lost even his own axe","He became the spirit''s friend"]', '["Ia mendapat kapak emas","Ia kehilangan kapaknya sendiri","Ia menjadi sahabat peri"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_sang-kancil-and-the-crocodiles', 'sang-kancil-and-the-crocodiles', 'Sang Kancil and the Crocodiles', 'Sang Kancil dan Buaya-buaya', 'A tiny mouse-deer must cross a river full of hungry crocodiles — armed with nothing but a very big idea.', 'Kancil kecil harus menyeberangi sungai yang penuh buaya lapar — hanya berbekal satu ide yang sangat besar.', 'cat_world-cultures', 'aut_siti-aminah', 'ocean', '🐊', 3, 8, 0, 'published', 12, 3579, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_1', 'bok_sang-kancil-and-the-crocodiles', 1, 'kancil-1', 'In the warm forests of the Nusantara lived Sang Kancil, the mouse-deer — the smallest of the big animals and the cleverest of the small ones.', 'Di hutan Nusantara yang hangat hiduplah Sang Kancil — yang paling kecil di antara hewan besar, dan yang paling cerdik di antara hewan kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_2', 'bok_sang-kancil-and-the-crocodiles', 2, 'kancil-2', 'One morning, Kancil saw the ripest, sweetest rambutan trees he had ever seen — on the other side of the wide brown river.', 'Suatu pagi, Kancil melihat pohon rambutan paling ranum dan manis yang pernah ia lihat — di seberang sungai cokelat yang lebar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_3', 'bok_sang-kancil-and-the-crocodiles', 3, 'kancil-3', 'But the river was full of crocodiles. Big ones, long ones, hungry ones. Their yellow eyes watched Kancil from the water like floating lanterns.', 'Tapi sungai itu penuh buaya. Yang besar, yang panjang, yang lapar. Mata kuning mereka mengawasi Kancil dari dalam air seperti lentera terapung.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_4', 'bok_sang-kancil-and-the-crocodiles', 4, 'kancil-4', 'Kancil thought and thought. Then he smiled his small clever smile, stood tall on a rock, and called out: ''Crocodiles! Wonderful news! The King has sent me to count you all for a great feast!''', 'Kancil berpikir dan berpikir. Lalu ia tersenyum kecil penuh akal, berdiri di atas batu, dan berseru: ''Buaya-buaya! Kabar gembira! Raja mengutusku menghitung kalian semua untuk pesta besar!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_5', 'bok_sang-kancil-and-the-crocodiles', 5, 'kancil-5', '''A feast?'' the biggest crocodile rumbled, lifting his huge head. ''With food for all of us?'' — ''Mountains of it!'' said Kancil. ''But only crocodiles who are counted may come!''', '''Pesta?'' gumam buaya terbesar sambil mengangkat kepala raksasanya. ''Dengan makanan untuk kami semua?'' — ''Bergunung-gunung!'' kata Kancil. ''Tapi hanya buaya yang terhitung yang boleh datang!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_6', 'bok_sang-kancil-and-the-crocodiles', 6, 'kancil-6', '''Then count us! Count us!'' the crocodiles cried. ''Very well,'' said Kancil. ''Line up from this bank to the far bank — straight and still, nose to tail, so I miss nobody!''', '''Kalau begitu hitunglah kami! Hitung kami!'' seru para buaya. ''Baiklah,'' kata Kancil. ''Berbarislah dari tepi sini sampai tepi seberang — lurus dan diam, dari hidung ke ekor, supaya tak ada yang terlewat!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_7', 'bok_sang-kancil-and-the-crocodiles', 7, 'kancil-7', 'The crocodiles hurried into a line across the river, floating side by side like a bridge of bumpy green logs.', 'Buaya-buaya bergegas berbaris melintasi sungai, mengapung berdampingan seperti jembatan dari batang kayu hijau yang berbonggol-bonggol.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_8', 'bok_sang-kancil-and-the-crocodiles', 8, 'kancil-8', '''One!'' said Kancil, hopping onto the first crocodile''s back. ''Two!'' — hop. ''Three!'' — hop. He counted his way lightly across the whole river.', '''Satu!'' kata Kancil sambil melompat ke punggung buaya pertama. ''Dua!'' — lompat. ''Tiga!'' — lompat. Ia menghitung sambil melompat ringan menyeberangi seluruh sungai.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_9', 'bok_sang-kancil-and-the-crocodiles', 9, 'kancil-9', '''...and TWELVE!'' he cried, landing safely on the far bank, right beneath the rambutan trees. The crocodiles waited eagerly. ''And now? When is the feast?''', '''...dan DUA BELAS!'' serunya sambil mendarat selamat di tepi seberang, tepat di bawah pohon rambutan. Para buaya menunggu tak sabar. ''Lalu? Kapan pestanya?''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_10', 'bok_sang-kancil-and-the-crocodiles', 10, 'kancil-10', 'Kancil picked a sweet rambutan and grinned. ''Thank you for the bridge, friends! The only feast today is mine!'' And he skipped away into the trees.', 'Kancil memetik rambutan manis dan menyeringai. ''Terima kasih atas jembatannya, kawan-kawan! Satu-satunya pesta hari ini adalah pestaku!'' Lalu ia melompat riang ke balik pepohonan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_11', 'bok_sang-kancil-and-the-crocodiles', 11, 'kancil-11', 'The crocodiles snapped and splashed and grumbled all afternoon. But secretly, even the biggest one had to admit: ''That little Kancil... has a very big brain.''', 'Para buaya menggertak, mencipratkan air, dan menggerutu sepanjang sore. Tapi diam-diam, buaya terbesar pun harus mengakui: ''Kancil kecil itu... otaknya besar sekali.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_sang-kancil-and-the-crocodiles_12', 'bok_sang-kancil-and-the-crocodiles', 12, 'kancil-12', 'And that is why, to this day, parents in the Nusantara tell their children: when the problem is bigger than you are, think bigger than the problem. The end.', 'Dan itulah sebabnya, sampai hari ini, orang tua di Nusantara berpesan kepada anak-anaknya: bila masalah lebih besar daripada dirimu, berpikirlah lebih besar daripada masalahmu. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_sang-kancil-and-the-crocodiles_1', 'bok_sang-kancil-and-the-crocodiles', 1, 'Why did Kancil need to cross the river?', 'Mengapa Kancil perlu menyeberangi sungai?', '["To visit the King","To reach the sweet rambutan trees","To swim with the crocodiles"]', '["Untuk menemui Raja","Untuk mencapai pohon rambutan yang manis","Untuk berenang dengan buaya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_sang-kancil-and-the-crocodiles_2', 'bok_sang-kancil-and-the-crocodiles', 2, 'How did Kancil get the crocodiles to make a bridge?', 'Bagaimana Kancil membuat buaya-buaya menjadi jembatan?', '["He said the King wanted to count them for a feast","He paid them with fruit","He asked politely"]', '["Ia berkata Raja ingin menghitung mereka untuk pesta","Ia membayar mereka dengan buah","Ia meminta dengan sopan"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_sang-kancil-and-the-crocodiles_3', 'bok_sang-kancil-and-the-crocodiles', 3, 'What is the lesson of the story?', 'Apa pelajaran dari cerita ini?', '["Crocodiles are kind","Being big always wins","A clever mind can solve a big problem"]', '["Buaya itu baik hati","Yang besar selalu menang","Akal yang cerdik bisa memecahkan masalah besar"]', 2, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-crow-and-the-pitcher', 'the-crow-and-the-pitcher', 'The Crow and the Pitcher', 'Gagak dan Kendi Air', 'A thirsty crow finds water she cannot reach — and shows that patience plus a good idea can move the impossible.', 'Seekor gagak yang kehausan menemukan air yang tak terjangkau — dan membuktikan bahwa kesabaran dan ide cerdas bisa mengalahkan yang mustahil.', 'cat_science', 'aut_axto-creative-team', 'dusk', '🐦‍⬛', 3, 7, 0, 'published', 12, 5181, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_1', 'bok_the-crow-and-the-pitcher', 1, 'crow-pitcher-1', 'It had not rained for many, many days. The streams were dry, the puddles were gone, and a tired crow flew across the hot fields looking for one thing only: water.', 'Hujan tak turun berhari-hari lamanya. Sungai kecil mengering, genangan lenyap, dan seekor gagak yang lelah terbang melintasi ladang panas mencari satu hal saja: air.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_2', 'bok_the-crow-and-the-pitcher', 2, 'crow-pitcher-2', 'Her throat burned and her wings felt heavy. ''Water,'' she croaked. ''Just a little water...''', 'Tenggorokannya terasa terbakar dan sayapnya berat. ''Air,'' seraknya. ''Sedikit saja air...''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_3', 'bok_the-crow-and-the-pitcher', 3, 'crow-pitcher-3', 'Then, near an old farmhouse, she saw it: a tall clay pitcher! She peered inside — and yes! At the very bottom gleamed a little pool of cool, clear water.', 'Lalu, di dekat rumah tani tua, ia melihatnya: sebuah kendi tanah liat yang tinggi! Ia mengintip ke dalam — dan ya! Di dasar kendi berkilau sedikit air yang sejuk dan jernih.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_4', 'bok_the-crow-and-the-pitcher', 4, 'crow-pitcher-4', 'She pushed her beak into the pitcher. Too short! The water lay far below, and the pitcher''s neck was narrow and deep.', 'Ia memasukkan paruhnya ke dalam kendi. Terlalu pendek! Air itu jauh di bawah, dan leher kendi sempit lagi dalam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_5', 'bok_the-crow-and-the-pitcher', 5, 'crow-pitcher-5', 'She pushed the pitcher with her wings — it was too heavy to tip. She flapped and pecked and pushed again. Nothing. The water only trembled, far out of reach.', 'Ia mendorong kendi dengan sayapnya — terlalu berat untuk dimiringkan. Ia mengepak, mematuk, dan mendorong lagi. Sia-sia. Air itu hanya bergetar, jauh dari jangkauan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_6', 'bok_the-crow-and-the-pitcher', 6, 'crow-pitcher-6', 'Many birds would have flown away. But this crow sat down, tilted her shiny black head, and looked at the problem the way clever birds do.', 'Burung lain mungkin sudah terbang pergi. Tapi gagak ini duduk, memiringkan kepala hitamnya yang berkilau, dan menatap masalah itu seperti burung-burung cerdik biasanya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_7', 'bok_the-crow-and-the-pitcher', 7, 'crow-pitcher-7', 'Beside the pitcher lay a scattering of small pebbles. The crow looked at the pebbles. She looked at the water. And her bright eyes sparkled with an idea.', 'Di samping kendi berserakan kerikil-kerikil kecil. Gagak menatap kerikil. Ia menatap air. Dan matanya yang cerah berbinar oleh sebuah ide.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_8', 'bok_the-crow-and-the-pitcher', 8, 'crow-pitcher-8', 'She picked up a pebble and dropped it into the pitcher. Plop! The water rose — just a tiny, tiny bit.', 'Ia mengambil sebutir kerikil dan menjatuhkannya ke dalam kendi. Plung! Air naik — sedikit, sedikit sekali.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_9', 'bok_the-crow-and-the-pitcher', 9, 'crow-pitcher-9', 'Another pebble. Plop! And another. Plop! Pebble after pebble, the busy crow worked in the hot sun, and pebble after pebble, the water crept higher.', 'Kerikil lagi. Plung! Lagi. Plung! Kerikil demi kerikil, gagak yang rajin itu bekerja di bawah matahari panas, dan kerikil demi kerikil, air merayap semakin tinggi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_10', 'bok_the-crow-and-the-pitcher', 10, 'crow-pitcher-10', 'At last — plop! — the water rose right up to the pitcher''s neck. The crow dipped her beak and drank the sweetest, coolest drink of her whole life.', 'Akhirnya — plung! — air naik sampai ke leher kendi. Gagak mencelupkan paruhnya dan meneguk minuman termanis dan tersejuk sepanjang hidupnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_11', 'bok_the-crow-and-the-pitcher', 11, 'crow-pitcher-11', '''Little by little does the trick,'' she said happily, ruffling her feathers. And she flew off into the evening, strong and quick again.', '''Sedikit demi sedikit, akhirnya berhasil,'' katanya senang sambil mengibaskan bulunya. Lalu ia terbang ke senja, kembali kuat dan gesit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-crow-and-the-pitcher_12', 'bok_the-crow-and-the-pitcher', 12, 'crow-pitcher-12', 'So when a problem looks too big, remember the crow: do not give up — think, start small, and keep going. Drop by drop, the water rises. The end.', 'Maka bila sebuah masalah tampak terlalu besar, ingatlah sang gagak: jangan menyerah — berpikirlah, mulailah dari yang kecil, dan teruslah berusaha. Setetes demi setetes, air akan naik. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-crow-and-the-pitcher_1', 'bok_the-crow-and-the-pitcher', 1, 'Why couldn''t the crow drink at first?', 'Mengapa gagak tak bisa langsung minum?', '["The water was too deep inside the pitcher","The water was dirty","The pitcher was empty"]', '["Airnya terlalu dalam di dasar kendi","Airnya kotor","Kendinya kosong"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-crow-and-the-pitcher_2', 'bok_the-crow-and-the-pitcher', 2, 'What did the crow drop into the pitcher?', 'Apa yang dijatuhkan gagak ke dalam kendi?', '["Leaves","Pebbles","Seeds"]', '["Daun","Kerikil","Biji-bijian"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-crow-and-the-pitcher_3', 'bok_the-crow-and-the-pitcher', 3, 'What made the water rise?', 'Apa yang membuat air naik?', '["Magic","Each pebble taking up space","The hot sun"]', '["Sihir","Setiap kerikil memenuhi ruang di dalam air","Matahari yang panas"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-elves-and-the-shoemaker', 'the-elves-and-the-shoemaker', 'The Elves and the Shoemaker', 'Peri Kecil dan Tukang Sepatu', 'A kind old shoemaker is down to his last piece of leather — until tiny midnight helpers change everything, and kindness is repaid with kindness.', 'Tukang sepatu tua yang baik hati hanya punya selembar kulit terakhir — sampai para penolong mungil tengah malam mengubah segalanya, dan kebaikan dibalas kebaikan.', 'cat_fairy-tales', 'aut_axto-creative-team', 'night', '👞', 4, 9, 0, 'published', 13, 1811, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_1', 'bok_the-elves-and-the-shoemaker', 1, 'elves-shoemaker-1', 'There was once a shoemaker who was honest and kind, but times were hard, and one evening he found he had leather left for only one last pair of shoes.', 'Dahulu ada seorang tukang sepatu yang jujur dan baik hati, tetapi zaman sedang sulit, dan suatu malam ia sadar kulitnya hanya cukup untuk satu pasang sepatu terakhir.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_2', 'bok_the-elves-and-the-shoemaker', 2, 'elves-shoemaker-2', 'He cut the leather carefully, laid the pieces on his workbench, and sighed. ''I will sew them in the morning.'' Then he blew out the candle and went to bed.', 'Ia memotong kulit itu dengan hati-hati, menata potongannya di meja kerja, lalu menghela napas. ''Besok pagi akan kujahit.'' Kemudian ia meniup lilin dan pergi tidur.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_3', 'bok_the-elves-and-the-shoemaker', 3, 'elves-shoemaker-3', 'But in the morning — what a wonder! On the bench stood a finished pair of shoes, so beautifully stitched that every seam was perfect. ''Who could have done this?''', 'Namun pagi harinya — sungguh ajaib! Di atas meja sudah berdiri sepasang sepatu jadi, dijahit begitu indah hingga setiap jahitannya sempurna. ''Siapa gerangan yang mengerjakan ini?''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_4', 'bok_the-elves-and-the-shoemaker', 4, 'elves-shoemaker-4', 'A rich traveller bought the shoes at once, and paid so well that the shoemaker could buy leather for two pairs. That night, he cut the pieces and left them out again.', 'Seorang pelancong kaya langsung membeli sepatu itu, dan membayar sangat mahal hingga tukang sepatu bisa membeli kulit untuk dua pasang. Malam itu ia memotong kulitnya dan menaruhnya lagi di meja.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_5', 'bok_the-elves-and-the-shoemaker', 5, 'elves-shoemaker-5', 'In the morning, two perfect pairs! And so it went on, night after night: whatever he cut in the evening was finished by dawn, finer than any shoes in the town.', 'Paginya, dua pasang sepatu sempurna! Begitu seterusnya, malam demi malam: apa pun yang ia potong di senja hari selesai saat fajar, lebih bagus daripada sepatu mana pun di kota.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_6', 'bok_the-elves-and-the-shoemaker', 6, 'elves-shoemaker-6', 'The little shop grew busy and warm again. But the shoemaker and his wife could not stop wondering. ''Tonight,'' said his wife, ''let us hide behind the curtain and watch.''', 'Toko kecil itu kembali ramai dan hangat. Tapi tukang sepatu dan istrinya tak bisa berhenti bertanya-tanya. ''Malam ini,'' kata istrinya, ''mari kita sembunyi di balik tirai dan mengintip.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_7', 'bok_the-elves-and-the-shoemaker', 7, 'elves-shoemaker-7', 'At midnight, the window creaked open — and in slipped two tiny elves, no taller than teacups. Their little clothes were nothing but rags, but their hands flew like hummingbirds.', 'Tepat tengah malam, jendela berderit terbuka — dan masuklah dua peri mungil, tak lebih tinggi dari cangkir teh. Pakaian kecil mereka hanya kain compang-camping, tetapi tangan mereka bekerja secepat kolibri.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_8', 'bok_the-elves-and-the-shoemaker', 8, 'elves-shoemaker-8', 'Snip, stitch, tap-tap-tap! In moments the shoes stood finished, gleaming in the moonlight. Then the little elves bowed to each other and slipped away into the night.', 'Gunting, jahit, tok-tok-tok! Dalam sekejap sepatu-sepatu itu selesai, berkilau dalam cahaya bulan. Lalu kedua peri kecil saling membungkuk dan menghilang ke dalam malam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_9', 'bok_the-elves-and-the-shoemaker', 9, 'elves-shoemaker-9', '''They work so hard for us,'' whispered the shoemaker''s wife, ''and their clothes are so thin and torn. Winter is coming. Let us make a gift for them!''', '''Mereka bekerja begitu keras untuk kita,'' bisik istri tukang sepatu, ''padahal baju mereka tipis dan robek. Musim dingin akan tiba. Mari kita buatkan hadiah untuk mereka!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_10', 'bok_the-elves-and-the-shoemaker', 10, 'elves-shoemaker-10', 'So they sewed two tiny shirts, two tiny coats, two tiny caps — and the shoemaker made the smallest, softest pair of boots his hands had ever made.', 'Maka mereka menjahit dua kemeja mungil, dua mantel mungil, dua topi mungil — dan tukang sepatu membuat sepasang sepatu bot terkecil dan terlembut yang pernah dibuat tangannya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_11', 'bok_the-elves-and-the-shoemaker', 11, 'elves-shoemaker-11', 'That night they laid the little clothes on the bench instead of leather. When the elves arrived, they clapped their tiny hands with joy, dressed at once, and danced around the workbench!', 'Malam itu mereka menaruh pakaian mungil di meja, bukan kulit sepatu. Ketika para peri datang, mereka bertepuk tangan gembira, langsung berpakaian, dan menari-nari mengelilingi meja kerja!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_12', 'bok_the-elves-and-the-shoemaker', 12, 'elves-shoemaker-12', '''Now we are dressed so fine and neat — no more cobbling, dancing feet!'' they sang, and out of the window they twirled, never to be seen again.', '''Kini kami berpakaian rapi dan indah — tak lagi menjahit, kaki kami menari!'' nyanyi mereka, lalu berputar keluar jendela, dan tak pernah terlihat lagi.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-elves-and-the-shoemaker_13', 'bok_the-elves-and-the-shoemaker', 13, 'elves-shoemaker-13', 'But good luck never left that little shop. For kindness given in secret has a way of staying in the walls — and in every pair of shoes the old man made, people said they could feel it. The end.', 'Namun keberuntungan tak pernah meninggalkan toko kecil itu. Sebab kebaikan yang diberikan diam-diam selalu tinggal di dinding rumah — dan pada setiap pasang sepatu buatan pak tua itu, kata orang, kebaikan itu terasa. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-elves-and-the-shoemaker_1', 'bok_the-elves-and-the-shoemaker', 1, 'Who finished the shoes at night?', 'Siapa yang menyelesaikan sepatu di malam hari?', '["The shoemaker''s wife","Two tiny elves","The rich traveller"]', '["Istri tukang sepatu","Dua peri mungil","Pelancong kaya"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-elves-and-the-shoemaker_2', 'bok_the-elves-and-the-shoemaker', 2, 'What gift did the shoemaker and his wife make?', 'Hadiah apa yang dibuat tukang sepatu dan istrinya?', '["Tiny clothes and boots","A little house","Golden coins"]', '["Pakaian dan sepatu bot mungil","Rumah kecil","Koin emas"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-elves-and-the-shoemaker_3', 'bok_the-elves-and-the-shoemaker', 3, 'Why did they give the elves a gift?', 'Mengapa mereka memberi hadiah kepada para peri?', '["To make them work harder","To thank them for their secret kindness","To make them leave"]', '["Agar mereka bekerja lebih keras","Untuk berterima kasih atas kebaikan diam-diam mereka","Agar mereka pergi"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-town-mouse-and-the-country-mouse', 'the-town-mouse-and-the-country-mouse', 'The Town Mouse and the Country Mouse', 'Tikus Kota dan Tikus Desa', 'Two cousin mice visit each other''s worlds — fine food in the noisy town, simple food in the peaceful field — and discover what ''home'' really tastes like.', 'Dua tikus bersaudara saling mengunjungi dunia masing-masing — makanan mewah di kota yang bising, makanan sederhana di ladang yang damai — dan menemukan rasa ''rumah'' yang sesungguhnya.', 'cat_family', 'aut_axto-creative-team', 'candy', '🐭', 3, 8, 0, 'published', 12, 5197, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_1', 'bok_the-town-mouse-and-the-country-mouse', 1, 'town-country-1', 'Once there were two cousin mice. One lived in the quiet countryside, in a snug burrow under a hazel hedge. The other lived in the big, busy town, inside the wall of a grand house.', 'Dahulu ada dua tikus bersaudara sepupu. Yang satu tinggal di desa yang tenang, dalam liang hangat di bawah pagar tanaman. Yang lain tinggal di kota besar yang sibuk, di balik dinding sebuah rumah megah.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_2', 'bok_the-town-mouse-and-the-country-mouse', 2, 'town-country-2', 'One autumn day, the town mouse came to visit. The country mouse proudly served the best he had: barley grains, hazelnuts, and a little piece of cheese rind.', 'Suatu hari di musim gugur, tikus kota datang berkunjung. Tikus desa dengan bangga menghidangkan yang terbaik miliknya: butir jelai, kacang hazel, dan sepotong kecil kulit keju.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_3', 'bok_the-town-mouse-and-the-country-mouse', 3, 'town-country-3', 'The town mouse nibbled politely, then wrinkled his nose. ''Dear cousin, how do you bear such plain food and such a quiet life? Come with me to town — I shall show you how to truly live!''', 'Tikus kota mengunyah dengan sopan, lalu mengernyitkan hidungnya. ''Saudaraku, bagaimana kau tahan dengan makanan sederhana dan hidup sesunyi ini? Ikutlah ke kota — akan kutunjukkan cara hidup yang sesungguhnya!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_4', 'bok_the-town-mouse-and-the-country-mouse', 4, 'town-country-4', 'So off they went. The town glittered with a thousand lights. In the grand house, the dining table was still covered from a feast: cakes, cheeses, figs, and honey!', 'Maka berangkatlah mereka. Kota berkilauan dengan seribu lampu. Di rumah megah itu, meja makan masih penuh sisa pesta: kue, keju, buah ara, dan madu!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_5', 'bok_the-town-mouse-and-the-country-mouse', 5, 'town-country-5', '''Help yourself, cousin!'' said the town mouse grandly. The country mouse had never tasted anything so delicious in all his life. ''Why, this is wonderful!'' he squeaked.', '''Silakan makan sepuasnya, saudaraku!'' kata tikus kota dengan megah. Tikus desa belum pernah mencicipi makanan selezat itu seumur hidupnya. ''Wah, ini luar biasa!'' cicitnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_6', 'bok_the-town-mouse-and-the-country-mouse', 6, 'town-country-6', 'But just as he bit into a fig — BANG! — the door flew open. Servants marched in with heavy boots, and the two mice dashed behind the curtain, hearts drumming.', 'Namun tepat saat ia menggigit buah ara — BRAK! — pintu terbuka lebar. Para pelayan masuk dengan sepatu bot berat, dan kedua tikus melesat ke balik tirai, jantung berdebar kencang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_7', 'bok_the-town-mouse-and-the-country-mouse', 7, 'town-country-7', 'When all was quiet, they crept out again. But hardly had they reached the cheese — ''MEOW!'' A huge cat leapt onto the table, eyes blazing like green fire!', 'Setelah semuanya sunyi, mereka merayap keluar lagi. Namun belum sampai ke keju — ''MEONG!'' Seekor kucing besar melompat ke atas meja, matanya menyala seperti api hijau!');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_8', 'bok_the-town-mouse-and-the-country-mouse', 8, 'town-country-8', 'The mice tumbled into a crack in the wall just in time. The country mouse pressed his paws to his chest. ''Cousin... is it like this every day?'' — ''Oh, one gets used to it,'' said the town mouse airily.', 'Kedua tikus terguling masuk celah dinding tepat pada waktunya. Tikus desa mendekap dadanya. ''Saudaraku... apakah setiap hari seperti ini?'' — ''Ah, lama-lama juga terbiasa,'' jawab tikus kota enteng.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_9', 'bok_the-town-mouse-and-the-country-mouse', 9, 'town-country-9', 'That night, the country mouse lay awake listening to carriages rattle and doors slam. He thought of his hedge, where the loudest sound was the owl saying goodnight.', 'Malam itu, tikus desa terjaga mendengarkan kereta kuda berderak dan pintu-pintu dibanting. Ia teringat pagar tanamannya, tempat suara paling nyaring hanyalah burung hantu yang mengucap selamat malam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_10', 'bok_the-town-mouse-and-the-country-mouse', 10, 'town-country-10', 'In the morning he hugged his cousin. ''Thank you for the feast, truly. But I would rather eat barley in peace than honey in fear. My little hedge is calling me home.''', 'Paginya ia memeluk sepupunya. ''Sungguh terima kasih atas pestanya. Tapi aku lebih suka makan jelai dalam damai daripada madu dalam ketakutan. Pagar kecilku memanggilku pulang.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_11', 'bok_the-town-mouse-and-the-country-mouse', 11, 'town-country-11', 'Back under the hazel hedge, he cooked his plain barley supper and ate it slowly, listening to the wind in the leaves. It tasted, he thought, exactly like happiness.', 'Kembali di bawah pagar tanamannya, ia memasak jelai sederhana untuk makan malam dan menyantapnya pelan-pelan sambil mendengarkan angin di dedaunan. Rasanya, pikirnya, persis seperti kebahagiaan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-town-mouse-and-the-country-mouse_12', 'bok_the-town-mouse-and-the-country-mouse', 12, 'town-country-12', 'For a simple life in peace can be sweeter than a rich life in fear — and the best home is the one where your heart can rest. The end.', 'Sebab hidup sederhana yang damai bisa lebih manis daripada hidup mewah yang penuh ketakutan — dan rumah terbaik adalah tempat hatimu bisa beristirahat. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-town-mouse-and-the-country-mouse_1', 'bok_the-town-mouse-and-the-country-mouse', 1, 'What food did the country mouse serve?', 'Makanan apa yang dihidangkan tikus desa?', '["Cakes and honey","Barley, hazelnuts and cheese rind","Figs and cream"]', '["Kue dan madu","Jelai, kacang hazel, dan kulit keju","Buah ara dan krim"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-town-mouse-and-the-country-mouse_2', 'bok_the-town-mouse-and-the-country-mouse', 2, 'What dangers did the mice meet in town?', 'Bahaya apa yang mereka temui di kota?', '["Rain and thunder","Servants and a huge cat","A hungry owl"]', '["Hujan dan petir","Para pelayan dan kucing besar","Burung hantu lapar"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-town-mouse-and-the-country-mouse_3', 'bok_the-town-mouse-and-the-country-mouse', 3, 'What did the country mouse decide in the end?', 'Apa keputusan tikus desa pada akhirnya?', '["To stay in town forever","That peace at home is sweeter than riches in fear","To become a town mouse"]', '["Tinggal di kota selamanya","Damai di rumah lebih manis daripada kemewahan dalam ketakutan","Menjadi tikus kota"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-little-red-hen', 'the-little-red-hen', 'The Little Red Hen', 'Ayam Merah Kecil', 'Who will help plant the wheat? Not I, said the cat, the dog and the duck — a warm farm tale about work, sharing, and second chances.', 'Siapa mau membantu menanam gandum? Tidak aku, kata kucing, anjing, dan bebek — dongeng peternakan yang hangat tentang kerja, berbagi, dan kesempatan kedua.', 'cat_farm', 'aut_axto-creative-team', 'sunrise', '🐔', 3, 7, 0, 'published', 12, 2681, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_1', 'bok_the-little-red-hen', 1, 'red-hen-1', 'On a cosy little farm lived a little red hen with her fluffy yellow chicks — and three lazy friends: a sleepy cat, a dozy dog, and a daydreaming duck.', 'Di sebuah peternakan kecil yang nyaman hiduplah ayam merah kecil bersama anak-anaknya yang kuning berbulu halus — dan tiga sahabat pemalas: kucing yang mengantuk, anjing yang lesu, dan bebek yang suka melamun.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_2', 'bok_the-little-red-hen', 2, 'red-hen-2', 'One bright morning, the little red hen found some golden grains of wheat on the path. ''Who will help me plant this wheat?'' she called.', 'Suatu pagi yang cerah, ayam merah kecil menemukan butir-butir gandum keemasan di jalan setapak. ''Siapa mau membantuku menanam gandum ini?'' serunya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_3', 'bok_the-little-red-hen', 3, 'red-hen-3', '''Not I,'' yawned the cat from the windowsill. ''Not I,'' mumbled the dog from his shady spot. ''Not I,'' quacked the duck, watching the clouds.', '''Tidak aku,'' kucing menguap dari jendela. ''Tidak aku,'' gumam anjing dari tempat teduhnya. ''Tidak aku,'' kwek bebek sambil menatap awan.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_4', 'bok_the-little-red-hen', 4, 'red-hen-4', '''Then I shall plant it myself,'' said the little red hen. And she did — scratching the soil, tucking in each grain, and patting the earth gently on top.', '''Kalau begitu akan kutanam sendiri,'' kata ayam merah kecil. Dan ia melakukannya — mengais tanah, membenamkan setiap butir, dan menepuk-nepuk tanah dengan lembut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_5', 'bok_the-little-red-hen', 5, 'red-hen-5', 'All summer she watered and weeded. ''Who will help me care for the wheat?'' — ''Not I.'' ''Not I.'' ''Not I.'' So she cared for it herself, day after day.', 'Sepanjang musim ia menyiram dan mencabuti rumput liar. ''Siapa mau membantuku merawat gandum?'' — ''Tidak aku.'' ''Tidak aku.'' ''Tidak aku.'' Maka ia merawatnya sendiri, hari demi hari.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_6', 'bok_the-little-red-hen', 6, 'red-hen-6', 'The wheat grew tall and golden as the sun. ''Who will help me cut the wheat?'' asked the hen. ''Not I,'' said the cat, the dog and the duck together.', 'Gandum tumbuh tinggi dan keemasan seperti matahari. ''Siapa mau membantuku memanen gandum?'' tanya si ayam. ''Tidak aku,'' jawab kucing, anjing, dan bebek serempak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_7', 'bok_the-little-red-hen', 7, 'red-hen-7', '''Then I shall cut it myself.'' Swish, swish! She cut and bundled every stalk, and carried it to the mill to be ground into soft white flour.', '''Kalau begitu akan kupanen sendiri.'' Kres, kres! Ia memotong dan mengikat setiap batang, lalu membawanya ke penggilingan untuk dijadikan tepung putih yang halus.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_8', 'bok_the-little-red-hen', 8, 'red-hen-8', '''Who will help me bake the bread?'' she asked at last. ''Not I... not I... not I,'' came the three lazy voices. ''Then I shall bake it myself,'' said the little red hen.', '''Siapa mau membantuku memanggang roti?'' tanyanya akhirnya. ''Tidak aku... tidak aku... tidak aku,'' sahut tiga suara pemalas itu. ''Kalau begitu akan kupanggang sendiri,'' kata ayam merah kecil.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_9', 'bok_the-little-red-hen', 9, 'red-hen-9', 'Soon a smell so warm and wonderful floated across the farm that the cat, the dog and the duck all came running. ''We will help you EAT the bread!'' they cried.', 'Tak lama kemudian, aroma yang begitu hangat dan lezat tercium ke seluruh peternakan, sampai kucing, anjing, dan bebek berlari datang. ''Kami mau membantu MAKAN rotinya!'' seru mereka.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_10', 'bok_the-little-red-hen', 10, 'red-hen-10', 'The little red hen looked at them kindly but firmly. ''You did not plant, you did not water, you did not cut, you did not bake. My chicks and I, who did the work, will eat this loaf.''', 'Ayam merah kecil memandang mereka dengan lembut tapi tegas. ''Kalian tidak menanam, tidak menyiram, tidak memanen, tidak memanggang. Aku dan anak-anakku, yang mengerjakan semuanya, yang akan memakan roti ini.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_11', 'bok_the-little-red-hen', 11, 'red-hen-11', 'The three friends hung their heads, for they knew she was right. ''We are sorry, little red hen,'' said the dog quietly. ''Next time, we will help from the very first day.''', 'Ketiga sahabat itu menunduk malu, karena mereka tahu ayam merah benar. ''Maafkan kami, ayam merah kecil,'' kata anjing pelan. ''Lain kali, kami akan membantu sejak hari pertama.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-little-red-hen_12', 'bok_the-little-red-hen', 12, 'red-hen-12', 'And they kept their word! When spring came, four friends planted the wheat together — and when the next loaf came out of the oven, the whole farm shared it, warm slice by warm slice. The end.', 'Dan mereka menepati janji! Saat musim semi tiba, empat sahabat menanam gandum bersama — dan ketika roti berikutnya keluar dari panggangan, seisi peternakan menikmatinya bersama, sepotong demi sepotong yang hangat. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-little-red-hen_1', 'bok_the-little-red-hen', 1, 'What did the friends say when the hen asked for help?', 'Apa jawaban para sahabat saat si ayam minta tolong?', '["''Yes, of course!''","''Not I.''","''Maybe tomorrow.''"]', '["''Ya, tentu!''","''Tidak aku.''","''Mungkin besok.''"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-little-red-hen_2', 'bok_the-little-red-hen', 2, 'Why didn''t the hen share the first loaf?', 'Mengapa ayam tidak membagi roti pertamanya?', '["She was unkind","The friends had refused to do any of the work","The bread was too small"]', '["Ia jahat","Para sahabat menolak ikut bekerja","Rotinya terlalu kecil"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-little-red-hen_3', 'bok_the-little-red-hen', 3, 'What happened in spring?', 'Apa yang terjadi saat musim semi?', '["The friends helped from the first day and all shared the bread","The hen moved away","The wheat did not grow"]', '["Para sahabat membantu sejak hari pertama dan semua berbagi roti","Si ayam pindah","Gandumnya tidak tumbuh"]', 0, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-boy-who-cried-wolf', 'the-boy-who-cried-wolf', 'The Boy Who Cried Wolf', 'Anak Gembala yang Berteriak Serigala', 'A bored shepherd boy plays a trick on his village — twice. But when a real wolf comes, he learns what a lie costs.', 'Seorang anak gembala yang bosan mengerjai desanya — dua kali. Namun saat serigala sungguhan datang, ia belajar mahalnya harga sebuah kebohongan.', 'cat_moral-stories', 'aut_axto-creative-team', 'dusk', '🐺', 4, 9, 0, 'published', 12, 2074, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_1', 'bok_the-boy-who-cried-wolf', 1, 'cried-wolf-1', 'On a green hill above a little village, a shepherd boy watched the sheep every day. The sun was warm, the bells went ting-ting, and the days were very, very long.', 'Di bukit hijau di atas sebuah desa kecil, seorang anak gembala menjaga domba setiap hari. Matahari hangat, lonceng domba berdenting-denting, dan hari terasa sangat, sangat panjang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_2', 'bok_the-boy-who-cried-wolf', 2, 'cried-wolf-2', 'One afternoon, the boy grew so bored that a naughty idea popped into his head. He stood up, cupped his hands, and shouted down to the village: ''WOLF! WOLF! A wolf is after the sheep!''', 'Suatu sore, anak itu begitu bosan sampai sebuah ide nakal muncul di kepalanya. Ia berdiri, menangkupkan tangan, dan berteriak ke arah desa: ''SERIGALA! SERIGALA! Ada serigala mengejar domba!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_3', 'bok_the-boy-who-cried-wolf', 3, 'cried-wolf-3', 'The villagers dropped everything. The baker left his oven, the farmer left his plough, and up the hill they ran with sticks and shouts — as fast as their legs could carry them.', 'Warga desa meninggalkan semuanya. Tukang roti meninggalkan panggangannya, petani meninggalkan bajaknya, dan mereka berlari mendaki bukit membawa tongkat sambil berteriak — secepat kaki mereka bisa berlari.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_4', 'bok_the-boy-who-cried-wolf', 4, 'cried-wolf-4', 'But at the top they found no wolf at all — only the boy, rolling in the grass with laughter. ''You should see your faces!'' he giggled. The villagers walked home, shaking their heads.', 'Namun di puncak bukit tak ada serigala sama sekali — hanya si anak, berguling-guling di rumput sambil tertawa. ''Coba lihat wajah kalian!'' kikiknya. Warga desa pulang sambil menggeleng-geleng.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_5', 'bok_the-boy-who-cried-wolf', 5, 'cried-wolf-5', 'A few days later, the boy did it again. ''WOLF! WOLF!'' And again the villagers came running — and again there was no wolf, only laughter rolling down the hill.', 'Beberapa hari kemudian, anak itu melakukannya lagi. ''SERIGALA! SERIGALA!'' Dan lagi-lagi warga berlari datang — dan lagi-lagi tak ada serigala, hanya tawa yang bergema menuruni bukit.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_6', 'bok_the-boy-who-cried-wolf', 6, 'cried-wolf-6', 'This time nobody smiled. ''Lies are not jokes, boy,'' said the old baker quietly. ''A liar is not believed — even when he tells the truth.'' But the boy only shrugged.', 'Kali ini tak ada yang tersenyum. ''Bohong itu bukan lelucon, nak,'' kata tukang roti tua pelan. ''Pembohong takkan dipercaya — bahkan saat ia berkata benar.'' Tapi anak itu hanya mengangkat bahu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_7', 'bok_the-boy-who-cried-wolf', 7, 'cried-wolf-7', 'Then, one grey evening, the grass rustled — and out of the shadows stepped a real wolf, with hungry yellow eyes fixed on the flock.', 'Lalu, pada suatu senja kelabu, rerumputan bergemerisik — dan dari balik bayangan muncullah serigala sungguhan, dengan mata kuning lapar menatap kawanan domba.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_8', 'bok_the-boy-who-cried-wolf', 8, 'cried-wolf-8', '''WOLF!'' screamed the boy, and this time his voice shook with real fear. ''WOLF! PLEASE! HELP! A REAL WOLF!''', '''SERIGALA!'' jerit anak itu, dan kali ini suaranya gemetar oleh ketakutan yang sungguhan. ''SERIGALA! TOLONG! SERIGALA BETULAN!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_9', 'bok_the-boy-who-cried-wolf', 9, 'cried-wolf-9', 'Down in the village, the baker heard him and sighed. ''That boy again.'' The farmer heard him and kept ploughing. ''He will not fool us a third time.'' Nobody came.', 'Di bawah, di desa, tukang roti mendengarnya dan menghela napas. ''Anak itu lagi.'' Petani mendengarnya dan terus membajak. ''Ia takkan menipu kami untuk ketiga kalinya.'' Tak seorang pun datang.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_10', 'bok_the-boy-who-cried-wolf', 10, 'cried-wolf-10', 'The boy could only wave his stick and shout as the wolf scattered the flock and drove off the fattest sheep into the dark woods.', 'Anak itu hanya bisa mengayunkan tongkat dan berteriak saat serigala mencerai-beraikan kawanan dan menggiring domba paling gemuk ke dalam hutan yang gelap.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_11', 'bok_the-boy-who-cried-wolf', 11, 'cried-wolf-11', 'When the villagers finally came at nightfall and heard what had happened, the boy hung his head and wept. ''You warned me,'' he whispered to the baker. ''Nobody believes a liar — even when he tells the truth.''', 'Ketika warga akhirnya datang saat malam tiba dan mendengar kejadiannya, anak itu menunduk dan menangis. ''Kalian sudah memperingatkanku,'' bisiknya pada tukang roti. ''Tak ada yang percaya pembohong — bahkan saat ia berkata benar.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-boy-who-cried-wolf_12', 'bok_the-boy-who-cried-wolf', 12, 'cried-wolf-12', 'From that day on, the boy guarded both his sheep and his words. And when he grew up, they say, he became the most trusted man in the village — because he had learned young how precious the truth is. The end.', 'Sejak hari itu, si anak menjaga dombanya dan juga kata-katanya. Dan ketika ia dewasa, konon ia menjadi orang paling dipercaya di desa — karena ia belajar sejak kecil betapa berharganya kejujuran. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-boy-who-cried-wolf_1', 'bok_the-boy-who-cried-wolf', 1, 'Why did the boy first shout ''Wolf!''?', 'Mengapa anak itu pertama kali berteriak ''Serigala!''?', '["He saw a real wolf","He was bored and wanted to trick the villagers","He was practising singing"]', '["Ia melihat serigala sungguhan","Ia bosan dan ingin mengerjai warga","Ia sedang latihan bernyanyi"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-boy-who-cried-wolf_2', 'bok_the-boy-who-cried-wolf', 2, 'Why did nobody come when the real wolf appeared?', 'Mengapa tak ada yang datang saat serigala sungguhan muncul?', '["They were asleep","They no longer believed him after his lies","They were afraid of wolves"]', '["Mereka sedang tidur","Mereka tak lagi percaya setelah kebohongannya","Mereka takut serigala"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-boy-who-cried-wolf_3', 'bok_the-boy-who-cried-wolf', 3, 'What is the lesson of this story?', 'Apa pelajaran dari cerita ini?', '["Wolves are dangerous","Shouting is rude","If you lie, people stop believing you — even when you tell the truth"]', '["Serigala itu berbahaya","Berteriak itu tidak sopan","Jika kau berbohong, orang berhenti mempercayaimu — bahkan saat kau jujur"]', 2, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-monkey-and-the-crocodile', 'the-monkey-and-the-crocodile', 'The Monkey and the Crocodile', 'Kera dan Buaya', 'A monkey and a crocodile become unlikely river friends — until a dangerous secret tests how quickly a clever heart can think.', 'Seekor kera dan buaya menjadi sahabat sungai yang tak terduga — sampai sebuah rahasia berbahaya menguji secepat apa akal yang cerdik bisa berpikir.', 'cat_jungle-safari', 'aut_axto-creative-team', 'forest', '🐒', 4, 9, 0, 'published', 12, 1099, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_1', 'bok_the-monkey-and-the-crocodile', 1, 'monkey-croc-1', 'Long ago, in a jamun tree that leaned over a great river, lived a cheerful monkey. The tree''s purple fruit was the sweetest for miles, and the monkey ate it from morning till night.', 'Dahulu kala, di pohon jamblang yang condong ke sungai besar, hiduplah seekor kera yang riang. Buah ungu pohon itu paling manis sejauh mata memandang, dan si kera memakannya dari pagi sampai malam.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_2', 'bok_the-monkey-and-the-crocodile', 2, 'monkey-croc-2', 'One day a crocodile swam up and rested under the tree. ''You look tired, friend,'' said the monkey, and he threw down a pawful of sweet jamun. The crocodile had never tasted anything so fine.', 'Suatu hari seekor buaya berenang mendekat dan beristirahat di bawah pohon. ''Kau tampak lelah, kawan,'' kata kera, lalu ia menjatuhkan segenggam jamblang manis. Buaya itu belum pernah mencicipi buah selezat itu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_3', 'bok_the-monkey-and-the-crocodile', 3, 'monkey-croc-3', 'From then on, the crocodile came every day, and the two became true friends — the monkey dropping fruit, the crocodile telling stories of the deep river and the far bank.', 'Sejak itu, buaya datang setiap hari, dan keduanya menjadi sahabat sejati — kera menjatuhkan buah, buaya bercerita tentang sungai yang dalam dan tepian yang jauh.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_4', 'bok_the-monkey-and-the-crocodile', 4, 'monkey-croc-4', 'The crocodile carried some jamun home to his wife. She ate them and her eyes narrowed greedily. ''If the fruit is this sweet,'' she said, ''how sweet must be the heart of the monkey who eats them every day! Bring me his heart.''', 'Buaya membawa beberapa jamblang pulang untuk istrinya. Istrinya memakannya dan matanya menyipit serakah. ''Kalau buahnya semanis ini,'' katanya, ''betapa manisnya hati kera yang memakannya setiap hari! Bawakan aku hati kera itu.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_5', 'bok_the-monkey-and-the-crocodile', 5, 'monkey-croc-5', 'The crocodile was horrified. ''He is my friend!'' But his wife pretended to be terribly ill. ''Only a monkey''s heart can cure me,'' she moaned. And the weak-willed crocodile finally agreed.', 'Buaya terkejut dan sedih. ''Ia sahabatku!'' Tapi istrinya berpura-pura sakit parah. ''Hanya hati kera yang bisa menyembuhkanku,'' rintihnya. Dan buaya yang lemah hati itu akhirnya menurut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_6', 'bok_the-monkey-and-the-crocodile', 6, 'monkey-croc-6', '''Friend monkey!'' he called the next morning. ''My wife has cooked a feast to thank you for the fruit. Climb on my back, and I shall carry you across to our home!''', '''Sahabatku kera!'' panggilnya keesokan pagi. ''Istriku memasak jamuan untuk berterima kasih atas buah-buahmu. Naiklah ke punggungku, akan kubawa kau ke rumah kami di seberang!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_7', 'bok_the-monkey-and-the-crocodile', 7, 'monkey-croc-7', 'The monkey, delighted, hopped onto the crocodile''s back. But in the middle of the river, where the water ran deepest, the crocodile began to sink — and told the truth.', 'Kera dengan senang hati melompat ke punggung buaya. Namun di tengah sungai, di bagian air yang paling dalam, buaya mulai menenggelamkan diri — dan mengakui yang sebenarnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_8', 'bok_the-monkey-and-the-crocodile', 8, 'monkey-croc-8', '''Forgive me, friend. My wife is ill, and she says only your heart can cure her.'' The monkey''s blood ran cold — but his clever mind stayed warm, and it worked faster than fear.', '''Maafkan aku, kawan. Istriku sakit, dan katanya hanya hatimu yang bisa menyembuhkannya.'' Darah kera serasa membeku — tapi akal cerdiknya tetap hangat, dan bekerja lebih cepat daripada rasa takut.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_9', 'bok_the-monkey-and-the-crocodile', 9, 'monkey-croc-9', '''My heart? Oh, dear friend, why didn''t you say so at the tree!'' cried the monkey. ''We monkeys never carry our hearts around — they are far too precious! Mine is hanging safely in the jamun tree!''', '''Hatiku? Aduh, sahabatku, mengapa tak bilang dari tadi di pohon!'' seru kera. ''Kami para kera tak pernah membawa-bawa hati — terlalu berharga! Hatiku kugantung aman di pohon jamblang!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_10', 'bok_the-monkey-and-the-crocodile', 10, 'monkey-croc-10', '''Then we must go back for it at once!'' said the crocodile, and he turned around and swam swiftly back to the tree.', '''Kalau begitu kita harus kembali mengambilnya sekarang juga!'' kata buaya, lalu ia berbalik dan berenang cepat kembali ke pohon.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_11', 'bok_the-monkey-and-the-crocodile', 11, 'monkey-croc-11', 'The moment they touched the bank, the monkey leapt high into his tree and looked down. ''Foolish friend! Who ever heard of a heart hanging in a tree? A friend who plots against a friend loses the fruit AND the friendship!''', 'Begitu menyentuh tepian, kera melompat tinggi ke pohonnya dan menoleh ke bawah. ''Sahabat yang bodoh! Mana ada hati digantung di pohon? Sahabat yang berkhianat kehilangan buahnya DAN persahabatannya!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-monkey-and-the-crocodile_12', 'bok_the-monkey-and-the-crocodile', 12, 'monkey-croc-12', 'The crocodile swam home ashamed, with no heart, no fruit and no friend. And children by that river still learn the double lesson: keep your wits when danger speaks sweetly — and never trade a true friend for anything. The end.', 'Buaya berenang pulang dengan malu, tanpa hati, tanpa buah, dan tanpa sahabat. Dan anak-anak di tepi sungai itu masih mempelajari pelajaran gandanya: jaga akalmu saat bahaya berbicara manis — dan jangan pernah menukar sahabat sejati dengan apa pun. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-monkey-and-the-crocodile_1', 'bok_the-monkey-and-the-crocodile', 1, 'How did the monkey and crocodile become friends?', 'Bagaimana kera dan buaya bersahabat?', '["The monkey shared his sweet jamun fruit","They raced across the river","The crocodile saved the monkey"]', '["Kera berbagi buah jamblang manisnya","Mereka berlomba menyeberangi sungai","Buaya menyelamatkan kera"]', 0, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-monkey-and-the-crocodile_2', 'bok_the-monkey-and-the-crocodile', 2, 'What did the monkey say to save himself?', 'Apa kata kera untuk menyelamatkan diri?', '["That he could not swim","That his heart was hanging in the jamun tree","That he was not sweet"]', '["Bahwa ia tak bisa berenang","Bahwa hatinya tergantung di pohon jamblang","Bahwa ia tidak manis"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-monkey-and-the-crocodile_3', 'bok_the-monkey-and-the-crocodile', 3, 'What did the crocodile lose in the end?', 'Apa yang hilang dari buaya pada akhirnya?', '["His tail","The fruit and the friendship","His house"]', '["Ekornya","Buah dan persahabatannya","Rumahnya"]', 1, 10);

INSERT OR IGNORE INTO books (id, slug, title_en, title_id, description_en, description_id, category_id, author_id, cover_palette, cover_emoji, age_min, age_max, is_premium, status, page_count, read_count, created_at, updated_at) VALUES ('bok_the-empty-pot', 'the-empty-pot', 'The Empty Pot', 'Pot yang Kosong', 'The Emperor will choose his heir with a single flower seed. A whole kingdom grows glorious blooms — except one boy, whose pot stays empty.', 'Kaisar akan memilih penerusnya dengan sebutir benih bunga. Seluruh negeri menumbuhkan bunga-bunga indah — kecuali satu anak, yang potnya tetap kosong.', 'cat_world-cultures', 'aut_david-lee', 'meadow', '🌱', 4, 10, 0, 'published', 12, 1178, 1784684005536, 1784684005536);
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_1', 'bok_the-empty-pot', 1, 'empty-pot-1', 'Long ago in China there lived an old Emperor who loved flowers more than gold. He had no child of his own, and the time had come to choose who would rule after him.', 'Dahulu kala di Tiongkok hiduplah seorang Kaisar tua yang mencintai bunga melebihi emas. Ia tak punya anak, dan tibalah waktunya memilih siapa yang akan memerintah setelahnya.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_2', 'bok_the-empty-pot', 2, 'empty-pot-2', 'So the Emperor made a proclamation: ''Every child in the kingdom shall receive one seed from my own hand. Whoever grows the finest flower in one year shall be my heir.''', 'Maka Kaisar mengeluarkan pengumuman: ''Setiap anak di negeri ini akan menerima sebutir benih dari tanganku sendiri. Siapa yang menumbuhkan bunga terindah dalam satu tahun akan menjadi penerusku.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_3', 'bok_the-empty-pot', 3, 'empty-pot-3', 'A boy named Ping was among the thousands who came. Ping loved gardening with his whole heart — everything he planted seemed to wake up and dance. He carried his seed home like a treasure.', 'Seorang anak bernama Ping ada di antara ribuan anak yang datang. Ping mencintai berkebun dengan segenap hatinya — apa pun yang ia tanam seakan bangun dan menari. Ia membawa pulang benihnya bagai harta karun.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_4', 'bok_the-empty-pot', 4, 'empty-pot-4', 'He chose his best pot, his richest soil, and planted the seed with the gentlest fingers in the kingdom. He watered it every morning. And he waited.', 'Ia memilih pot terbaiknya, tanah tersuburnya, dan menanam benih itu dengan jari-jari terlembut di seluruh negeri. Ia menyiraminya setiap pagi. Lalu ia menunggu.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_5', 'bok_the-empty-pot', 5, 'empty-pot-5', 'Nothing grew. Ping moved the pot into the sun. Nothing. He changed the soil, he sang to it, he checked it by moonlight. Still nothing — not even the smallest green tip.', 'Tak ada yang tumbuh. Ping memindahkan pot ke bawah matahari. Nihil. Ia mengganti tanah, bernyanyi untuknya, memeriksanya di bawah cahaya bulan. Tetap nihil — bahkan pucuk hijau terkecil pun tidak.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_6', 'bok_the-empty-pot', 6, 'empty-pot-6', 'Meanwhile, all over the kingdom, the other children whispered of their wonderful flowers. ''Mine is red as fire!'' ''Mine is taller than my father!'' Ping''s heart sank lower every day.', 'Sementara itu, di seluruh negeri, anak-anak lain berbisik tentang bunga mereka yang menakjubkan. ''Punyaku merah seperti api!'' ''Punyaku lebih tinggi dari ayahku!'' Hati Ping tenggelam semakin dalam setiap hari.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_7', 'bok_the-empty-pot', 7, 'empty-pot-7', 'The year ended. The children marched to the palace carrying pots bursting with magnificent blooms — crimson, gold, purple, white. And Ping walked among them carrying... an empty pot.', 'Tahun pun berakhir. Anak-anak berbaris ke istana membawa pot yang penuh bunga-bunga megah — merah tua, emas, ungu, putih. Dan Ping berjalan di antara mereka membawa... pot yang kosong.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_8', 'bok_the-empty-pot', 8, 'empty-pot-8', '''Why do you bring an empty pot?'' the other children laughed. Ping''s cheeks burned, but he answered quietly: ''I did everything I could. This is the truth of what grew.''', '''Mengapa kau membawa pot kosong?'' anak-anak lain tertawa. Pipi Ping memerah, tapi ia menjawab pelan: ''Aku sudah berusaha sebisaku. Inilah yang sebenarnya tumbuh.''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_9', 'bok_the-empty-pot', 9, 'empty-pot-9', 'The Emperor walked slowly down the long line of glorious flowers, his face growing stranger and sadder at every step. Then he stopped — in front of the empty pot.', 'Kaisar berjalan pelan menyusuri barisan panjang bunga-bunga indah itu, wajahnya semakin aneh dan sedih di setiap langkah. Lalu ia berhenti — di depan pot yang kosong.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_10', 'bok_the-empty-pot', 10, 'empty-pot-10', '''What is your name, child?'' — ''Ping, Your Majesty. I am sorry. I tried my very best, but your seed would not grow.'' The Emperor''s eyes began to shine.', '''Siapa namamu, nak?'' — ''Ping, Yang Mulia. Maafkan saya. Saya sudah berusaha sebaik mungkin, tapi benih Paduka tidak mau tumbuh.'' Mata Kaisar mulai berbinar.');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_11', 'bok_the-empty-pot', 11, 'empty-pot-11', 'The Emperor turned to the crowd and raised his voice: ''Hear me! The seeds I gave were all COOKED. Not one of them could ever grow. Yet only one child has brought me the truth!''', 'Kaisar berbalik ke arah kerumunan dan mengangkat suaranya: ''Dengarlah! Semua benih yang kubagikan sudah DIREBUS. Tak satu pun bisa tumbuh. Namun hanya satu anak yang membawakan kepadaku kejujuran!''');
INSERT OR IGNORE INTO book_pages (id, book_id, page_number, illustration_seed, text_en, text_id) VALUES ('pag_the-empty-pot_12', 'bok_the-empty-pot', 12, 'empty-pot-12', '''Courage to tell the truth when it is hard — that is the flower I was looking for.'' And so Ping, the boy with the empty pot, became the Emperor''s heir — and years later, the kingdom''s most honest and beloved ruler. The end.', '''Keberanian berkata jujur saat itu sulit — itulah bunga yang kucari.'' Maka Ping, anak dengan pot kosong itu, menjadi penerus Kaisar — dan bertahun-tahun kemudian, menjadi pemimpin paling jujur dan paling dicintai di negeri itu. Tamat.');
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-empty-pot_1', 'bok_the-empty-pot', 1, 'Why did nothing grow from Ping''s seed?', 'Mengapa benih Ping tidak tumbuh?', '["He forgot to water it","All the seeds had been cooked","He used bad soil"]', '["Ia lupa menyiramnya","Semua benih sudah direbus","Tanahnya jelek"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-empty-pot_2', 'bok_the-empty-pot', 2, 'Where did the other children''s flowers come from?', 'Dari mana bunga anak-anak lain berasal?', '["From the Emperor''s seeds","Not from the Emperor''s seeds — they were not honest","From a magic garden"]', '["Dari benih Kaisar","Bukan dari benih Kaisar — mereka tidak jujur","Dari kebun ajaib"]', 1, 10);
INSERT OR IGNORE INTO quiz_questions (id, book_id, sort_order, question_en, question_id, options_en_json, options_id_json, correct_index, xp_reward) VALUES ('qz_the-empty-pot_3', 'bok_the-empty-pot', 3, 'What ''flower'' was the Emperor really looking for?', '''Bunga'' apa yang sebenarnya dicari Kaisar?', '["The tallest bloom","The rarest color","The courage to tell the truth"]', '["Bunga tertinggi","Warna terlangka","Keberanian untuk berkata jujur"]', 2, 10);

